        private void frmMain_Load(object sender, EventArgs e)
        {
#if RPI
            //String Message;
            String build_date_temp;
            int Start, End;
#endif
            byte[] buf = new byte[2];
            Size pic_size = new Size(0, 0);
            bool Subsystem_start = false;
            bool status = false;
            Point my_location = new Point(2053, 279);

            MonitorTextBoxText(" " + Master_Controls.proc_name + " STARTING");
            picSpectrum.Visible = true;
            picSpectrum.BringToFront();
            picSpectrum.Enabled = true;
            picSpectrum.Show();

            this.FormClosing += new FormClosingEventHandler(this.Form1_Closing);
            IQ_Controls.IQ_Default_Location = IQ_groupBox3.Location;
            //Window_controls.Docking_Controls.Previous_Main_location = this.Location;
            
            //Application.UseWaitCursor = true;
            //Cursor.Hide();
            //Smeter_controls.Power_Meter_Max_Level = Forward_Meter.LevelMax;
            Master_Controls.isLoading = true;         // keep control events from sending messages to DLL, or worse starting a feedback loop.
            Thread.Sleep(3000);
            if (frmGui_called)
            {
                MonitorTextBoxText(" frmGUI Called");
            }
            MonitorTextBoxText(" frmMain_Load Called");
            build_date_temp = Properties.Resources.build_date;
            End = build_date_temp.Length - 1;
            Start = 4;
            Master_Controls.build_date = build_date_temp.Substring(Start, End - Start);
            MonitorTextBoxText(" MSCC Version: " + Master_Controls.build_date);
            Transceiver_Model_Settings.Fortis_Devices = Transceiver_Model_Settings.FORTIS_GEMINUS;
            Subsystem_start = oCode.Start_subsystem(1);
            if (!Subsystem_start)
            {
                MessageBox.Show("Subsystem Startup FAILED. MSCC is terminating",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
                Application.Exit();
            }
            else
            {
                status = Init_Spectrum_values();
                if (!status)
                {
                    MessageBox.Show("Init_Spectrum_values FAILED. MSCC is terminating",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    Application.Exit();
                }
                Initialize_Spectrum();
                status = Init_Waterfall_values();
                if (!status)
                {
                    MessageBox.Show("Init_Waterfall_values FAILED. MSCC is terminating",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    Application.Exit();
                }
                Initialize_Waterfall();
                Configure_Geminus();
                timer3.Enabled = true;
            }
            //this.Location = my_location;
            this.Location = Settings.Default.Main_Window_Location;
        }

