        #region Log Management
        private void Manage_Log_File()
        {
            String Message;
            if (File.Exists(Log_file))
            {
                try
                {
                    File.Delete(Log_file);
                    Master_Controls.line_count = 0;
                }
                catch (Exception error)
                {
                    Message = "Log FILE Delete FAILED" + Convert.ToString(error);
                    MessageBox.Show(Message, "MSCC-MKII", MessageBoxButtons.OK, MessageBoxIcon.Error);
                    Application.Exit();
                }
            }
        }
