        public void Display_Error_Message(String msg, bool stop)
        {
            Error_Message_label.BringToFront();
            Error_Message_label.Visible = true;
            if (stop)
            {
                Error_Message_label.Text = "ERROR\r\n" + msg;
                Thread.Sleep(3000);
                //if (Master_Controls.Initialize_network_status == true)
                //{
                //    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_STOP, Transceiver_Model_Settings.Stop_States.STOP_NORMAL);
                //}
                Application.Exit();
            }
            else
            {
                Error_Message_label.Text = "WARNING\r\n" + msg;
                Thread.Sleep(3000);
                Error_Message_label.Visible = false;
                Error_Message_label.SendToBack();
            }
        }
        public void LogWrite(string logMessage)
        {
            try
            {
                using (StreamWriter w = File.AppendText(Log_file))
                {
                    Log(logMessage, w);
                }
            }
            catch
            {
                Display_Error_Message("LOG FILE WRITE FAILED MSCC WILL NOW STOP", true);
            }
        }
        public void Log(string logMessage, TextWriter txtWriter)
        {
            try
            {
                txtWriter.WriteLine("{0} {1}", DateTime.Now.ToLongTimeString(),
                    DateTime.Now.ToLongDateString());
                txtWriter.WriteLine("  :{0}", logMessage);
                txtWriter.WriteLine("-------------------------------");
            }
            catch
            {
                Display_Error_Message("LOG FILE WRITE FAILED MSCC WILL NOW STOP", true);
            }
        }
        public void MonitorTextBoxText(string text)
        {
            String Message_text;

            // InvokeRequired required compares the thread ID of the
            // calling thread to the thread ID of the creating thread.
            // If these threads are different, it returns true.
            if (!Master_Controls.MonitorText_Busy)
            {
                Master_Controls.MonitorText_Busy = true;
                try
                {
                    if (this.Monitor_window.Monitortxt.InvokeRequired)
                    {
                        MonitorTextCallback d = new MonitorTextCallback(MonitorTextBoxText);
                        this.Invoke(d, new object[] { text });
                    }
                    else
                    {
                        Message_text = Convert.ToString(Master_Controls.line_count++) + text;
                        if (Master_Controls.monitor_suspend == false) Monitor_window.Monitortxt.AppendText(Message_text + "\r\n");
                        LogWrite(Message_text);
                    }
                }
                catch
                {
                    Display_Error_Message("LOG FILE WRITE FAILED MSCC WILL NOW STOP", true);
                }
                Master_Controls.MonitorText_Busy = false;
            }
            else
            {
                Master_Controls.MonitorText_Busy_count++;
            }
        }
        public void Write_Message(String Message)
        {
            try
            {
                MonitorTextBoxText(Message);
            }
            catch
            {
                Display_Error_Message("LOG FILE WRITE FAILED MSCC WILL NOW STOP", true);
            }
        }
        public void Write_Debug_Message(String Message)
        {
            var thisForm2 = Application.OpenForms.OfType<Main_form>().Single();
            thisForm2.Write_Message(Message);
        }
