        #region State Machines
        public void Master_State_Machine()
        {
            byte[] buf = new byte[2];
            int seconds = 0;
            int hour = 0;
            bool status = false;

            //MonitorTextBoxText(" Master_State_Machine. STATE: " + Convert.ToString(Master_Controls.Manage_Controls_State));
            switch (Master_Controls.Manage_Controls_State)
            {
                case 0:
                    //MonitorTextBoxText(" Master_State_Machine. Call_count: " + Convert.ToString(Spectrum_Panadapter_Controls.Call_count));
                    //MonitorTextBoxText(" process_spectrum_count: " + Convert.ToString(process_spectrum_count));
                    //MonitorTextBoxText(" process_spectrum_op_code: " + Convert.ToString(process_spectrum_op_code));
                    if (Transceiver_Model_Settings.New_Freq_Pointer)
                    {
                        Set_Freq_Digit_Pointer();
                        Transceiver_Model_Settings.New_Freq_Pointer = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 1:
                    if (RIT.Rit_Controls.Previous_Rit_Offset_From_Server != RIT.Rit_Controls.RIT_Offset_From_Server)
                    {
                        Manage_Rit_From_Server();
                        RIT.Rit_Controls.Previous_Rit_Offset_From_Server = RIT.Rit_Controls.RIT_Offset_From_Server;
                    }
                    ritScroll.Enabled = RIT.Rit_Controls.RIT_Scroll_Bar_Status;
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 2:
                    if (Transceiver_Model_Settings.Volume_Settings.Set_By_Server)
                    {
                        //MonitorTextBoxText(" Manage_RPI_Controls -> Transceiver_Model_Settings.Volume_Settings.Set_By_Server. Mode: " +
                        //      Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital));
                        if (Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                        {
                            Set_Button_Color(false, Volume_Mute_button2, "VOLUME");
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                            Transceiver_Model_Settings.Volume_Settings.Speaker_MutED = false;
                            Transceiver_Model_Settings.Volume_Settings.Speaker_Mute = 0;
                        }

                        if (!Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
                        {
                            Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume;
                            Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume);
                        }
                        else
                        {
                            Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Speaker_Volume;
                            Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Speaker_Volume);
                        }
                        Transceiver_Model_Settings.Volume_Settings.Previous_Speaker_Volume = Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume;
                        Transceiver_Model_Settings.Volume_Settings.Set_By_Server = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 3:
                    if (Transceiver_Model_Settings.Previous_Freq_Step != Transceiver_Model_Settings.Freq_Step)
                    {
                        Master_Controls.Step_Index = Transceiver_Model_Settings.Freq_Step;
                        Transceiver_Model_Settings.Previous_Freq_Step = Transceiver_Model_Settings.Freq_Step;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 4:
                    if (Transceiver_Model_Settings.Freq_Digit != Master_Controls.FreqDigit)
                    {
                        buf[0] = Master_Controls.Extended_Commands.CMD_MFC_SET_ZERO;
                        buf[1] = (byte)Master_Controls.FreqDigit;
                        oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND,
                                                                                buf, buf.Length);
                        Transceiver_Model_Settings.Freq_Digit = Master_Controls.FreqDigit;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 5:
                    if (IQ_Controls.RPi.Calibration_Slider_Value != IQ_Controls.RPi.Previous_Calibration_Slider_Value)
                    {
                        MonitorTextBoxText(" Master_State_Machine -> IQ_Controls.RPi.Calibration_Slider_Value: " +
                                                Convert.ToString(IQ_Controls.RPi.Calibration_Slider_Value));
                        if (IQ_Controls.RX_toggle)
                        {
                            LefthScrollBar1.Value = IQ_Controls.RPi.Calibration_Slider_Value;
                            IQLefttextBox2.Text = Convert.ToString(IQ_Controls.RPi.Calibration_Slider_Value);
                        }
                        else
                        {
                            IQBD_TX_hScrollBar.Value = IQ_Controls.RPi.Calibration_Slider_Value;
                            IQ_Controls.IQ_Offset = IQ_Controls.RPi.Calibration_Slider_Value;
                            IQ_TX_Label.Text = "TX IQ OFFSET: " + Convert.ToString(IQ_Controls.RPi.Calibration_Slider_Value);
                            //(false, IQBD_Apply_button8, "APPLY");
                        }
                        IQ_Controls.RPi.Previous_Calibration_Slider_Value = IQ_Controls.RPi.Calibration_Slider_Value;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 6:

                    if (Transceiver_Model_Settings.Amplifier_Values.Previous_Power_Output !=
                        Transceiver_Model_Settings.Amplifier_Values.Power_Output)
                    {
                        Transceiver_Model_Settings.Amplifier_Values.Previous_Power_Output =
                            Transceiver_Model_Settings.Amplifier_Values.Power_Output;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 7:
                    if (Transceiver_Model_Settings.Amplifier_Values.Previous_Power_Calibration !=
                                                            Transceiver_Model_Settings.Amplifier_Values.Power_Calibration)
                    {
                        Transceiver_Model_Settings.Amplifier_Values.Previous_Power_Calibration =
                                                             Transceiver_Model_Settings.Amplifier_Values.Power_Calibration;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 8:
                    if (Filter_control.Previous_Filter_High_Index != Filter_control.Filter_High_Index)
                    {
                        Display_High_Cut_Value(Filter_control.Filter_High_Index);
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_HICUT, Filter_control.Filter_High_Index);
                        Filter_control.Previous_Filter_High_Index = Filter_control.Filter_High_Index;
                        MonitorTextBoxText(" Master_State_Machine. Filter_High_Index: " + Convert.ToString(Filter_control.Filter_High_Index));
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 9:
                    if (Filter_control.Previous_Filter_Low_Index != Filter_control.Filter_Low_Index)
                    {
                        Display_Low_Cut_Value(Filter_control.Filter_Low_Index);
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_LOCUT, Filter_control.Filter_Low_Index);
                        Filter_control.Previous_Filter_Low_Index = Filter_control.Filter_Low_Index;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 10:
                    if (Filter_control.Previous_CW_Filter_Index != Filter_control.CW_Filter_Index)
                    {
                        Display_CW_Value(Filter_control.CW_Filter_Index);
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_BW, Filter_control.CW_Filter_Index);
                        Filter_control.Previous_CW_Filter_Index = Filter_control.CW_Filter_Index;
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_PITCH,
                            (short)Filter_control.CW_Pitch_Index);
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 11:
                    if (VFOA_Default_Filters_Configured)
                    {
                        if (VFOA_Default_Filters_Configured)
                        {
                            VFOA_Default_Filters_Configured = false;
                            Filter_control.Filter_High_Index = (short)Filter_control.Defaults.Hi_Cut_Default;
                            Filter_control.Filter_Low_Index = (short)Filter_control.Defaults.Lo_Cut_Default;
                            Filter_control.CW_Filter_Index = (short)Filter_control.Defaults.CW_Default;
                            MonitorTextBoxText(" Master_State_Machine. VFOA Default_Filters_Configured");
                        }
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 12:
                    if (Power_Calibration_Controls.Previous_Received_Power_Value != Power_Calibration_Controls.Received_Power_Value)
                    {
                        Power_Calibration_Controls.Previous_Received_Power_Value = Power_Calibration_Controls.Received_Power_Value;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 13:
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 14:
                    seconds = DateTime.Now.Second;
                    hour = DateTime.Now.Hour;
                    if (hour == 0 && !Master_Controls.Reset_Log_File)
                    {
                        Manage_Log_File();
                        Master_Controls.Reset_Log_File = true;
                    }
                    if (hour != 0 && Master_Controls.Reset_Log_File)
                    {
                        Master_Controls.Reset_Log_File = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 15:
                    if (IQ_Controls.IQBD_Committed == true)
                    {
                        Set_Button_Color(false, IQ_Commit_button2, "APPLY");
                        IQ_Controls.IQBD_Committed = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 16:
                    if (IQ_Controls.Previous_IQBD_Value != IQ_Controls.IQBD_Value)
                    {
                        Set_Label_Color(false, IQBD_Monitor_label);
                        IQBD_Monitor_label.Text = Convert.ToString(IQ_Controls.IQBD_Value);
                        IQBD_Meter.Level = IQ_Controls.IQBD_Value;
                        IQ_Controls.Previous_IQBD_Value = IQ_Controls.IQBD_Value;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 17:
                    if (--Spectrum_waterfall_init_delay <= 0)
                    {
                        if (Spectrum_waterfall_init_fail_count_previous != Spectrum_waterfall_init_fail_count)
                        {
                            MonitorTextBoxText(" Master_State_Machine. Spectrum_waterfall_init_fail_count: " +
                                Convert.ToString(Spectrum_waterfall_init_fail_count));
                            Spectrum_waterfall_init_fail_count_previous = Spectrum_waterfall_init_fail_count;
                        }
                        switch (Spectrum_Watefall_init_toggle)
                        {
                            case true:
                                if (waterfall_init_running == false)
                                {
                                    status = Init_Waterfall_values();
                                    if (!status)
                                    {
                                        Spectrum_waterfall_init_fail_count++;
                                        //MessageBox.Show("Init_Waterfall_values FAILED. Will RETRY",
                                        //"MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
                                        //Application.Exit();
                                    }
                                }
                                Spectrum_Watefall_init_toggle = false;
                                break;

                            case false:
                                status = Init_Spectrum_values();
                                if (!status)
                                {
                                    Spectrum_waterfall_init_fail_count++;
                                    //MessageBox.Show("Init_Spectrum_values FAILED. Will Retry",
                                    //"MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
                                    //Application.Exit();
                                }
                                Spectrum_Watefall_init_toggle = true;
                                break;
                        }
                        Spectrum_waterfall_init_delay = 3;
                    }   
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 18:
                    if (Frequency_Calibration_controls.Progress_Toggle == true)
                    {
                        Calibration_progressBar1.PerformStep();
                        Freq_CAl_Progress_Lable.Text = Convert.ToString(Frequency_Calibration_controls.Progress_Value);
                        Frequency_Calibration_controls.Progress_Toggle = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 19:
                    if (IQ_Controls.RX_toggle)
                    {
                        if (IQ_Controls.Previous_Image_Value != IQ_Controls.Image_Value)
                        {
                            IQ_Controls.Previous_Image_Value = IQ_Controls.Image_Value;
                            IQ_Controls.Graph_Display_Value = IQ_Controls.Image_Value / 100;
                            if (IQ_Controls.Graph_Display_Value <= IQ_Image_meter.LevelMax)
                            {
                                //IQ_Image_meter.Level = IQ_Controls.Graph_Display_Value;
                            }
                            //MonitorTextBoxText(" Master_State_Machine -> Image_Value: " + Convert.ToString(IQ_Controls.Graph_Display_Value));
                        }
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 20:
                    Manage_Keep_Alive();
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 21:
                    if (Master_Controls.Client_Update_Flag && Transceiver_Model_Settings.Client_Initialized)
                    {
                        Update_Client_Settings();
                        Master_Controls.Client_Update_Flag = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 22:
                    if (Frequency_Calibration_controls.Calibration_Status_toggle)
                    {
                        Frequency_Calibration_controls.Calibration_Status_toggle = false;
                        Freq_Calibration_Status();
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 23:
                    if (Frequency_Calibration_controls.Freq_reported && Frequency_Calibration_controls.Message_Displayed)
                    {
                        if (Frequency_Calibration_controls.Delta < 10000)
                        {
                            Freq_Calibration_Status_label.Text = Freq_Calibration_Status_label.Text + "\n\r" +
                                Convert.ToString(Frequency_Calibration_controls.Delta) + " Hz";
                        }
                        Frequency_Calibration_controls.Freq_reported = false;
                        Frequency_Calibration_controls.Message_Displayed = false;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 24:
                    Set_Antenna_Switch();
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 25:
                    if (VFO_Controls.previous_vfo != VFO_Controls.vfo)
                    {
                        //
                        VFO_Controls.previous_vfo = VFO_Controls.vfo;
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 26:
                    if (VFO_Controls.Update_VFO_Equal == true)
                    {
                        if (VFO_Controls.Update_Tic++ > VFO_Controls.UPDATE_TIC_LIMIT)
                        {
                            Set_Button_Color(false, VFO_button);
                            VFO_Controls.Update_VFO_Equal = false;
                            VFO_Controls.Update_Tic = 0;
                        }
                    }

                    if (VFOA_Last_Used.Update_Band_Stack == true)
                    {
                        if (VFO_Controls.Update_Tic++ > VFO_Controls.UPDATE_TIC_LIMIT)
                        {
                            Set_Button_Color(false, Freq_Stack_button);
                            VFOA_Last_Used.Update_Band_Stack = false;
                            VFO_Controls.Update_Tic = 0;
                        }
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 27:
                    if (Master_Controls.Server_Message_Received)
                    {
                        Server_Message_label.Text = Master_Controls.Server_Message;
                        MonitorTextBoxText(Master_Controls.Server_Message + "\r\n");
                        Message_button.Enabled = true;
                        Message_button.Visible = true;
                        Master_Controls.Server_Message_Received = false;
                        Message_Blink_timer.Enabled = true;
                        Message_Blink_timer.Start();
                    }
                    Master_Controls.Manage_Controls_State++;
                    break;
                case 28: //Mensuro stuff
                    /*if (Smeter_controls.Mensuro_Attached && !Smeter_controls.Mensuro_Calibrated &&
                                                                                    !Smeter_controls.Mensure_Message_Reported)
                    {
                        MessageBox.Show("THE MENSURO HAS NOT BEEN CALIBRATED.\r\nCLICK ON THE Audio/Sys TAB TO CALIBRATE ",
                                     "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                        Smeter_controls.Mensure_Message_Reported = true;
                    }
                    if (Smeter_controls.Mensure_Calibration_Message)
                    {
                        if (Smeter_controls.Mensuro_Calibrated == false)
                        {
                            Mensuro_Calibrate_button.Enabled = false;
                            MessageBox.Show("MENSURO CALIBRATION FAILED\r\nMENSURO MEASUREMENT HAS STOPPED",
                                "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
                        }
                        else
                        {
                            MessageBox.Show("MENSURO CALIBRATION SUCCESS", "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Information);
                            Set_Button_Color(true, Mensuro_Calibrate_button);
                        }
                        Smeter_controls.Mensure_Calibration_Message = false;
                    }*/
                    Master_Controls.Manage_Controls_State = 0;
                    break;
            }
        }
        public void Manage_PTT_By_Server()
        {
            if (Master_Controls.Previous_TX_By_Server != Master_Controls.TX_By_Server)
            {
                if (!Master_Controls.TX_By_Server)
                {
                    RIT.Rit_Controls.Update_RIT = true;
                    Master_Controls.Transmit_Mode = false;
                    Master_Controls.PPT_Mode = false;
                    Set_Button_Color(false, button1);
                    QRP_Button.Enabled = true;
                    //Manage_Fortis_Buttons(true);
                    button1.Enabled = true;
                    buttTune.Enabled = true;
                    GEM_Group_Box.Enabled = true;
                    Monitor_button8.Enabled = true;
                    buttTune.Enabled = true;
                    button1.Enabled = true;
                    //Antenna_Switch_groupBox.Enabled = true;
                    if (Beta_checkBox.Checked)
                    {
                        VFO_button.Enabled = true;
                        Split_Button.Enabled = true;
                        Freq_Stack_button.Enabled = true;
                    }
                    if (VFO_Controls.Split.Split_toggle)
                    {
                        VFOB_TX_Indicator_button.Visible = false;
                    }
                    //Main_Power_hScrollBar1.Visible = false;
                    if (Master_Controls.Tuning_Mode == true)
                    {
                        Set_Button_Color(false, buttTune);
                        Master_Controls.Tuning_Mode = false;
                        AM_Carrier_hScrollBar1.Enabled = true;
                        Power_hScrollBar1.Enabled = true;
                        CW_Power_hScrollBar1.Enabled = true;
                        Set_Button_Color(false, Tune_vButton2);
                    }
                }
                else
                {
                    Master_Controls.Client_Update_Flag = true;
                    RIT.Rit_Controls.Update_RIT = false;
                    Master_Controls.Transmit_Mode = true;
                    Master_Controls.PPT_Mode = true;
                    Set_Button_Color(true, button1);
                    QRP_Button.Enabled = false;
                    //Manage_Fortis_Buttons(false);
                    Monitor_button8.Enabled = false;
                    GEM_Group_Box.Enabled = false;
                    //Manage_Fortis_Buttons(false);
                    buttTune.Enabled = false;
                    button1.Enabled = false;
                    //Antenna_Switch_groupBox.Enabled = false;
                    Smeter_controls.VU.New_Session = true;
                    if (Beta_checkBox.Checked)
                    {
                        VFO_button.Enabled = false;
                        Split_Button.Enabled = false;
                        Freq_Stack_button.Enabled = false;
                    }
                    if (VFO_Controls.Split.Split_toggle)
                    {
                        VFOB_TX_Indicator_button.Visible = true;
                    }
                }
                Master_Controls.Previous_TX_By_Server = Master_Controls.TX_By_Server;
                MonitorTextBoxText(" Manage_PTT_By_Server. FINISHED");
            }
        }
