        public void Manage_Keep_Alive()
        {
            if (++Master_Controls.Keep_Alive_Counter >= 8)
            {
                //MonitorTextBoxText(" Keep Alive Counter: " + Convert.ToString(Master_Controls.Keep_Alive_Counter));
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_KEEP_ALIVE, 1);
                if (Master_Controls.Keep_Alive == false)
                {
                    MessageBox.Show("SERVER DID NOT SEND KEEP ALIVE.  MSCC WILL STOP NOW.", "MSCC",
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                    Application.Exit();
                }
                Master_Controls.Keep_Alive_Counter = 0;
                Master_Controls.Keep_Alive = false;
            }
            if (!Tuning_Knob_Controls.MFC_Initialized)
            {
                MFC_Initialize();
            }
            else
            {
                if (!Tuning_Knob_Controls.Send_Finished)
                {
                    MFC_Update_Timer.Enabled = true;
                    MFC_Update_Timer.Start();
                    Tuning_Knob_Controls.Send_Finished = true;
                }
            }
        }
        public static string getBetween(string strSource, string strStart, string strEnd)
        {
            int Start, End;

            if (strSource.Contains(strStart) && strSource.Contains(strEnd))
            {
                Start = strSource.IndexOf(strStart, 0) + strStart.Length;
                End = strSource.IndexOf(strEnd, Start);
                return strSource.Substring(Start, End - Start);
            }
            else
            {
                return "";
            }
        }
