        public int Bool_To_Int(bool true_false)
        {
            int value = 0;

            switch (true_false)
            {
                case true:
                    value = 1;
                    break;
                default:
                    value = 0;
                    break;
            }
            return value;
        }
        public bool Int_To_Bool(int value)
        {
            bool true_false = false;
            switch (value)
            {
                case 1:
                    true_false = true;
                    break;
                default:
                    true_false = false;
                    break;

            }
            return true_false;
        }
