        public void CW_Manage_Keyer_Controls(bool on)
        {
            if (on)
            {
                CW_Mode_listBox1.Enabled = true;
                CW_Space_listBox1.Enabled = true;
                CW_Weight_listBox1.Enabled = true;
                CW_Paddle_listBox1.Enabled = true;
                CW_Speed_numericUpDown.Enabled = true;
            }
            else
            {
                CW_Mode_listBox1.Enabled = false;
                CW_Space_listBox1.Enabled = false;
                CW_Weight_listBox1.Enabled = false;
                CW_Paddle_listBox1.Enabled = false;
                CW_Speed_numericUpDown.Enabled = false;
            }
        }
        public bool Init_CW_Settings()
        {
            int temp = 0;

            MonitorTextBoxText(" Init_CW_Settings Called");
            oCode.Get_CW_Params();
            if (CW_Parameters.Tx_Hold == 0)
            {
                CW_Parameters.Tx_Hold = 1;
            }
            if (CW_Parameters.Tx_Hold > 100)
            {
                CW_Parameters.Tx_Hold = 100;
            }
            CW_Hold_numericUpDown2.Value = CW_Parameters.Tx_Hold;
            CW_Mode_listBox1.SelectedIndex = CW_Parameters.Keyer_Mode;
            temp = CW_Parameters.Spacing - 1;
            if (temp < 0)
            {
                temp = 0;
            }
            CW_Space_listBox1.SelectedIndex = temp;
            switch (CW_Parameters.Weight)
            {
                case 25:
                    CW_Weight_listBox1.SelectedIndex = 0;
                    break;
                case 50:
                    CW_Weight_listBox1.SelectedIndex = 1;
                    break;
                case 75:
                    CW_Weight_listBox1.SelectedIndex = 2;
                    break;
            }
            if (CW_Parameters.Keyer_Installed == 1)
            {
                CW_Manage_Keyer_Controls(true);
            }
            else
            {
                CW_Manage_Keyer_Controls(false);
            }
            CW_Paddle_listBox1.SelectedIndex = CW_Parameters.Paddle;
            Thread.Sleep(100);
            CW_Speed_numericUpDown.Value = CW_Parameters.Speed;
            Thread.Sleep(100);
            MonitorTextBoxText(" Init_CW_Settings Finished");
            return true;
        }
