        public bool Init_Client_Settings()
        {
            String path, line;
            System.IO.StreamReader file;
            short temp_int = 0;
            Int32 temp_32 = 0;
            String temp_string;
            int line_count = 0;
            int volume_count = 0;
            byte[] buf = new byte[2];

            String Message = " Main_Form -> Init_RPi_Settings STARTED";
            Write_Debug_Message(Message);
            // get path to local Appdata folder
            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            // add our folder and file name
#if RPI
            path += "/mscc-GEMINUS/client-settings.ini";
#endif

            // try to open the file
            try
            {
                //file = new System.IO.StreamReader(path);
                file = new System.IO.StreamReader(File.OpenRead(path));
            }

            // if the file open fails, whine prettily and return false
            catch (IOException e)
            {
                string er = e.Message;
                DialogResult ret = MessageBox.Show(" Open Failed: client-settings.ini" + er,
                    "MSCC-Core", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return false;
            }
            while ((line = file.ReadLine()) != null)
            {
                line_count++;

                temp_string = getBetween(line, "MENSURO_CALIBRATED=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Smeter_controls.Mensuro_Calibrated = Int_To_Bool(temp_int);
                    Message = " MENSURO_CALIBRATED: " + Convert.ToString(Smeter_controls.Mensuro_Calibrated);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "POTENTIA=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Master_Controls.PA_Button_ON = Int_To_Bool(temp_int);
                    if (Master_Controls.PA_Button_ON)
                    {
                        Set_Button_Color(true, PA_button);
                        Set_Button_Color(true, QRP_Button);
                        IQBD_TX_groupBox.Enabled = false;
                        Smeter_controls.Mensuro_Hi_Lo = 1;
                        Master_Controls.QRP_Mode = false;
                        AMP_groupBox3.Enabled = true;
                        oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 1);
                        Tune_Power_label37.Text = Convert.ToString(Power_Controls.TUNE_Power);
                        Tune_Power_hScrollBar1.Value = Power_Controls.TUNE_Power;
                    }
                    else
                    {
                        Transceiver_Calibrate_groupBox.Enabled = true;
                        IQBD_TX_groupBox.Enabled = true;
                    }
                    Smeter_controls.Mensuro_Hi_Lo = (byte)temp_int;
                    oCode.SendCommand(txsocket, txtarget, Smeter_controls.CMD_SET_METER_HILO, Smeter_controls.Mensuro_Hi_Lo);
                    Message = " POTENTIA: " + Convert.ToString(Master_Controls.PA_Button_ON);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "VFOB_HICUT=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    VFOB_Last_Used.Last_used.Filter_High_Index = temp_int;
                    Message = " VFOB_HICUT: " + Convert.ToString(VFOB_Last_Used.Last_used.Filter_High_Index);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "VFOB_LOCUT=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    VFOB_Last_Used.Last_used.Filter_Low_Index = temp_int;
                    Message = " VFOB_LOCUT: " + Convert.ToString(VFOB_Last_Used.Last_used.Filter_Low_Index);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "VFOB_CW=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    VFOB_Last_Used.Last_used.Filter_CW_index = temp_int;
                    Message = " VFOB_CW: " + Convert.ToString(VFOB_Last_Used.Last_used.Filter_CW_index);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "AUTO_TUNE_TIME=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Master_Controls.Auto_Tune.Auto_Tune_Time = (byte)temp_int;
                    Auto_Tune_Time_button.Text = "AUTO TUNE HOLD: " + Convert.ToString(Master_Controls.Auto_Tune.Auto_Tune_Time);
                    Message = " AUTO_TUNE_TIME: " + Convert.ToString(Master_Controls.Auto_Tune.Auto_Tune_Time);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "AUTO_TUNE_MODE=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Master_Controls.Auto_Tune.Auto_Tune_Mode = (byte)temp_int;
                    if (Master_Controls.Auto_Tune.Auto_Tune_Mode == Master_Controls.QRO_MODE)
                    {
                        Set_Button_Color(true, Auto_Tune_button, "AUTO TUNE: QRO");
                        Master_Controls.Auto_Tune.Auto_Tune_Toggle = true;
                    }
                    else
                    {
                        Set_Button_Color(false, Auto_Tune_button, "AUTO TUNE: QRP");
                        Master_Controls.Auto_Tune.Auto_Tune_Toggle = false;
                    }
                    Message = " AUTO_TUNE_MODE: " + Convert.ToString(Master_Controls.Auto_Tune.Auto_Tune_Mode);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "S_METER_HOLD_INDEX=", ";");
                if (temp_string != "")
