                    Int16.TryParse(temp_string, out temp_int);
                    Smeter_controls.smeter_hold_time_index = temp_int;
                    Smeter_controls.smeter_hold = Smeter_controls.smeter_hold_time_index;
                    Message = " S_METER_HOLD_INDEX: " + Convert.ToString(Smeter_controls.smeter_hold_time_index);
                    Smeter_Hold_Time_button_Click(null, null);
