                    Power_Calibration_Controls.Calibrated_Bands.B_630 = (byte)temp_int;
                    Message = " GEMINUS_B630: " + Convert.ToString(Power_Calibration_Controls.Calibrated_Bands.B_630);
                    Write_Debug_Message(Message);
