                    Message = " PEAK_NEEDLE_COLOR_INDEX: " + Convert.ToString(Smeter_controls.Meter_Peak_Needle_Color_Index);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "TIME_DISPLAY=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Transceiver_Model_Settings.Time_Display = temp_int;
                    if (Transceiver_Model_Settings.Time_Display == 1)
                    {
                        Master_Controls.Time_Check_Box = true;
                        Time_checkBox2.Checked = true;
                    }
                    else
                    {
                        Master_Controls.Time_Check_Box = false;
                        Time_checkBox2.Checked = false;
                    }
                    Message = " TIME_DISPLAY: " + Convert.ToString(Transceiver_Model_Settings.Time_Display);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "METER_MODE=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Smeter_controls.Meter_Mode = temp_int;
                    Smeter_controls.selected_mode = (byte)Smeter_controls.Meter_Mode;
                    Reset_Meter_Buttons();
                    Set_Meter_Indicator(Smeter_controls.selected_mode);
                    Message = " METER_MODE: " + Convert.ToString(Smeter_controls.Meter_Mode);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "SHUTDOWN=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Transceiver_Model_Settings.Shutdown = (byte)temp_int;
                    Message = " SHUTDOWN: " + Convert.ToString(Transceiver_Model_Settings.Shutdown);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "FAN_CONTROL=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Master_Controls.Solidus_Fan_Control = temp_int;
                    if (Master_Controls.Solidus_Fan_Control == 0)
                    {
                        Set_Button_Color(true, Fan_Control_button8, "PWM ON");
                    }
                    else
                    {
                        Set_Button_Color(false, Fan_Control_button8, "PWM OFF");
                    }
                    oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_FAN_CONTROL,
                        (short)Master_Controls.Solidus_Fan_Control);
                    Message = " FAN_CONTROL: " + Convert.ToString(Master_Controls.Solidus_Fan_Control);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "FAN_TEMPERATURE=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Master_Controls.Solidus_Fan_On_Temperature = temp_int;
                    Solidus_Fan_On_Temperature_button8.Text = "FAN: " +
                        Convert.ToString(Master_Controls.Solidus_Fan_On_Temperature) + "°C";
                    oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_FAN_ON_TEMPERATURE,
                        (short)Master_Controls.Solidus_Fan_On_Temperature);
                    Message = " FAN_CONTROL: " + Convert.ToString(Master_Controls.Solidus_Fan_On_Temperature);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "METER_HOLD=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Smeter_controls.Meter_Hold = temp_int;
                    Power_Meter_Hold.Value = Smeter_controls.Meter_Hold;
                    Message = " METER_HOLD: " + Convert.ToString(Smeter_controls.Meter_Hold);
                    Write_Debug_Message(Message);
                    buf[0] = Master_Controls.Extended_Commands.CMD_SET_METER_HOLD;
                    buf[1] = (byte)Smeter_controls.Meter_Hold;
                    oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND,
                        buf, buf.Length);
                }

                temp_string = getBetween(line, "QRP_TUNE_POWER=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Transceiver_Model_Settings.QRP_Tune_Power = temp_int;
                    Message = " QRP_TUNE_POWER: " + Convert.ToString(Transceiver_Model_Settings.QRP_Tune_Power);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "SMETER_COLOR=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Smeter_controls.Meter_Background_Color_Index = temp_int;
                    S_Meter_Color_button_Click(null, null);
                    //Meter_Background_listBox1.SelectedIndex = Transceiver_Model_Settings.Meter_Background_Color_Index;
                    Message = " SMETER_COLOR: " + Convert.ToString(Smeter_controls.Meter_Background_Color_Index);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "BAND_CHANGE_TUNE=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Master_Controls.Auto_Tune.Band_Change_Tune = temp_int;
                    switch (temp_int)
                    {
                        case 0:
                            Band_Change_Auto_Tune_checkBox2.Checked = false;
                            break;
                        case 1:
                            Band_Change_Auto_Tune_checkBox2.Checked = true;
                            break;
                    }
                    Message = " BAND_CHANGE_TUNE: " + Convert.ToString(Master_Controls.Auto_Tune.Band_Change_Tune);
                    Write_Debug_Message(Message);
                }

                temp_string = getBetween(line, "MIC_MODE=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Transceiver_Model_Settings.Volume_Settings.Mic_Mode = temp_int;
                    switch (Transceiver_Model_Settings.Volume_Settings.Mic_Mode)
                    {
                        case 1:
                            Set_Button_Color(false, Audio_Digital_button3, "D");
                            //Configure Audio IN configuration
                            Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital = true;
                            Volume_Controls.Mic_Volume = (short)Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume;
                            Compression_button4.Enabled = false;
                            Compression_button2.Enabled = false;
                            Mic_Pre_Gain_button8.Enabled = false;
                            Mic_Digital_Pre_Gain_button.Enabled = true;
                            Volume_Attn_button8.Enabled = false;
                            Digital_Volume_Attn_button5.Enabled = true;
                            MicVolume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume;
                            Microphone_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume);
                            oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_CONFIGURATION,
                                                    Master_Controls.Server_Configuration_Commands.DIGITAL_AUDIO);
                            oCode.SendCommand(txsocket, txtarget,
                                Volume_Controls.CMD_SET_MIC_VOLUME, (short)Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_COMPRESSION_STATE, 0);
                            //Configure Audio OUT configuration
                            Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume = Transceiver_Model_Settings.Volume_Settings.Speaker_Volume;
                            Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume;
                            Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME,
                                                                (short)Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_VOLUME_ATTN,
                                                            (short)Transceiver_Model_Settings.Volume_Settings.Digital_Volume_ATTN_index);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_DIGITAL_MIC_GAIN,
                                                                    (short)Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Pre_Gain);
                            break;
                        default:
                            Set_Button_Color(true, Audio_Digital_button3, "P");
                            //Configure Audio IN configuration
                            Compression_button4.Enabled = true;
                            Compression_button2.Enabled = true;
                            Mic_Pre_Gain_button8.Enabled = true;
                            Mic_Digital_Pre_Gain_button.Enabled = false;
                            Volume_Attn_button8.Enabled = true;
                            Digital_Volume_Attn_button5.Enabled = false;
                            Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital = false;
                            Volume_Controls.Mic_Volume = (short)Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume;
                            MicVolume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume;
                            Microphone_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume);
                            oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_CONFIGURATION,
                                                    Master_Controls.Server_Configuration_Commands.OPERATOR_AUDIO);
                            oCode.SendCommand(txsocket, txtarget,
                                Volume_Controls.CMD_SET_MIC_VOLUME, (short)Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume);
                            //Configure Audio OUT configuration
                            Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume =
                                                                Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume;
                            Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume;
                            Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME,
                                                                (short)Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_VOLUME_ATTN,
                                                (short)Transceiver_Model_Settings.Volume_Settings.Volume_ATTN_Index);
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_MIC_GAIN,
                                                                    (short)Transceiver_Model_Settings.Volume_Settings.Mic_Pre_Gain);
                            break;

                    }
                    Message = " MIC_MODE: " + Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Mode);
                    Write_Debug_Message(Message);
                }
                temp_string = getBetween(line, "METER_PREFERRED_MODE=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Smeter_controls.Preferred_Mode = temp_int;
                    switch (Smeter_controls.Preferred_Mode)
                    {
                        case Smeter_controls.POWER_MODE:
                            Set_Button_Color(true, Main_Meter_Power_Preferred);
                            break;
                        case Smeter_controls.ALC_MODE:
                            Set_Button_Color(true, Main_Meter_ALC_Preferred);
                            break;
                        case Smeter_controls.SWR_MODE:
                            Set_Button_Color(true, Main_Meter_SWR_Preferred);
                            break;
                        case Smeter_controls.I_MODE:
                            Set_Button_Color(true, Main_Meter_I_Preferred);
                            break;
                        case Smeter_controls.TEMPERATURE_MODE:
                            Set_Button_Color(true, Main_Meter_Temperature_Preferred);
                            break;
                    }
                    Message = " METER_PREFERRED_MODE: " + Convert.ToString(Smeter_controls.Preferred_Mode);
                    Write_Debug_Message(Message);
                }
            }
            file.Close();
            Init_CW_Settings();
            Manage_Colors();
            //Transceiver_Model_Settings.RPi_Configured = true;
            Message = " Main_form -> Init_RPi_Settings Finished. Line_Count: " + Convert.ToString(line_count);
            Write_Debug_Message(Message);
            return true;
        }
        public void Finish_Initialization()
        {
            byte[] buf = new byte[2];

#if RPI
            Transceiver_Model_Settings.Client_Initialized = Init_Client_Settings();
#endif
            Master_Controls.Current_tab = powertabControl1.SelectedTab;
            Multus_mscc_ini_path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            Multus_mscc_ini_path += "/mscc-GEMINUS/Multus_mscc.ini";
            Master_Controls.FreqDigit = 2;    //Select the startup frequency digit to control
            MSCC_Core_Version_label45.Text = Master_Controls.build_date;
            //Set up the start up defaults for the filters
            Filter_control.Filter_High_Index = 4;
            Filter_control.Previous_Filter_High_Index = 10;
            Filter_control.Previous_Filter_Low_Index = 0;
            //Initialize_Main_Comm_Port();
            //Initialize_HR50_Comm_Port();
            TX_Bandwidth_listBox1.SetSelected(1, true);
            Filter_control.Filter_TX_High_Index = 1;
            Init_Power_values();
            Initialize_RIT();
            //Initialize_Docking();
            Manage_Colors();
            Master_Controls.FreqDigit = 2;    //Select the startup frequency digit to control
            Master_Controls.Step_Index = 3;
            VFOA_Master_Controls.Freq_Tune_Index = 3;
            //Default_CW_Filter_listBox1.SetSelected(2, true);
            Set_Freq_Digit_Pointer();
            Time_checkBox2.Enabled = true;
            Button_Color_label49.BackColor = Master_Controls.Display_Colors.Button_Active_Background;
            Button_Color_label49.ForeColor = Master_Controls.Display_Colors.Button_Active_Foreground;
            this.HorizontalScroll.Maximum = 0;
            this.HorizontalScroll.Minimum = 0;
            this.HorizontalScroll.Visible = false;
            this.AutoScroll = false;
            this.VerticalScroll.Visible = false;
            this.AutoScroll = true;
            this.HorizontalScroll.Enabled = false;
            this.HorizontalScroll.Visible = false;

            Set_Meter_Indicator(Smeter_controls.selected_mode);
            
#if !RPI
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            buf[1] = Settings.Default.Antenna_Switch;
            oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND,
                buf, buf.Length);
#endif
            oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_STEP_VALUE, VFOA_Master_Controls.Freq_Tune_Index);
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_METER_HOLD;
            buf[1] = Smeter_controls.SWR_Meter_Hold;
            oCode.SendCommand_MultiByte(txsocket, txtarget,
                                         Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
            Master_Controls.isLoading = false;        // All done, clear the global and carry on.
        }
        public void Post_Initialization()
        {
            //int status = 0;
            byte[] buf = new byte[2];
            //bool status = false;
            //String Message;
           
            MonitorTextBoxText(" Post_Initialization Called");
            Set_Startup_Band();
            //Volume_textBox2.Text = Convert.ToString(Settings.Default.Speaker_Volume);
            //Volume_hScrollBar1.Value = Settings.Default.Speaker_Volume;
            //buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            //buf[1] = Set_Antenna_Switch_Value(Settings.Default.Antenna_Switch);
            //oCode.SendCommand_MultiByte(txsocket, txtarget,
            //      Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
            //Message = " Post_Initialization -> ANTENNA_SWITCH: " + Convert.ToString(buf[1]);
            //Write_Debug_Message(Message);
#if RPI
            buf[0] = Master_Controls.Extended_Commands.CMD_MFC_AUTO_ZERO;
            buf[1] = 1;
            oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND,
                                                                buf, buf.Length);
#endif

#if !RPI
            switch (Settings.Default.Speaker_MutED)
            {
                case true:
                    Volume_Mute_button2.ForeColor = Color.Red;
                    Volume_Mute_button2.Text = "MUTED";
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 1);
                    MonitorTextBoxText(" Post_Initialization Called -> Settings.Default.Speaker_MutED: " +
                                                    Convert.ToString(Settings.Default.Speaker_MutED));
                    break;
                default:
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME, (short)Settings.Default.Speaker_Volume);
                    MonitorTextBoxText(" Post_Initialization Called -> Settings.Default.Speaker_MutED: " +
                                                                Convert.ToString(Settings.Default.Speaker_MutED));
                    break;
            }
#endif
            //AMP_Tune_button4.Enabled = true;
            Peak_Needle_checkBox2.CheckedChanged -= Peak_Needle_checkBox2_CheckedChanged;
            switch (Smeter_controls.Meter_Peak_Needle)
            {
                case true:
                    Peak_Needle_checkBox2.Checked = true;
                    vuMeter1.PeakHold = true;
                    break;
                default:
                    Peak_Needle_checkBox2.Checked = false;
                    vuMeter1.PeakHold = false;
                    break;
            }
            Peak_Needle_checkBox2.CheckedChanged += Peak_Needle_checkBox2_CheckedChanged;
            if (Master_Controls.Time_Check_Box == true)
            {
                Time_display_label33.Visible = true;
                Local_Date_label46.Visible = true;
                Time_display_UTC_label34.Visible = true;
                UTC_Date_label46.Visible = true;
                Time_checkBox2.Checked = true;
            }
            else
            {
                Time_display_label33.Visible = false;
                Local_Date_label46.Visible = false;
                Time_display_UTC_label34.Visible = false;
                UTC_Date_label46.Visible = false;
                Time_checkBox2.Checked = false;
            }

            if (Frequency_Calibration_controls.Frequency_Calibrated == 0 &&
                                                   !Frequency_Calibration_controls.Freq_Calibration_reported)
            {
                MessageBox.Show("TRANSCEIVER HAS NOT BEEN FREQUENCY CALIBRATED.\r\nCLICK ON THE FREQ CAL TAB TO PERFORM CALIBRATION ",
                         "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                Frequency_Calibration_controls.Freq_Calibration_reported = true;
            }

            if (Transceiver_Model_Settings.Fortis_Devices == Transceiver_Model_Settings.FORTIS_GEMINUS)
            {
                Master_Controls.Geminus_Calibrated_band = Geminus_Check_Calibrated_Bands();
                if (!Master_Controls.Geminus_Calibrated_band)
                {
                    MessageBox.Show("ONE OR BOTH GEMINUS BANDS HAVE NOT BEEN POWER CALIBRATED.\r\nCLICK ON THE QRP TAB TO CALIBRATE ",
                         "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                }
            }
            else
            {
                Proficio_Check_Calibrated_Bands();
            }

            if (Master_Controls.QRP_Mode)
            {
                Tune_Power_hScrollBar1.Value = Transceiver_Model_Settings.QRP_Tune_Power;
                Tune_Power_label37.Text = Convert.ToString(Transceiver_Model_Settings.QRP_Tune_Power);
            }
            else
            {
                Tune_Power_hScrollBar1.Value = Power_Controls.TUNE_Power;
                Tune_Power_label37.Text = Convert.ToString(Power_Controls.TUNE_Power);
            }

            //The following routes are work arounds for the Bogus implementation of Mono
            AM_Carrier_hScrollBar1.Value = Power_Controls.AM_Power;
            CW_Power_hScrollBar1.Value = Power_Controls.CW_Power;
            Power_hScrollBar1.Value = Power_Controls.Main_Power;
            switch (Master_Controls.modeswitch)
            {
                case Power_Controls.Mode.LSB_mode:
                    Main_Power_hScrollBar1.Value = Power_Controls.Main_Power;
                    break;
                case Power_Controls.Mode.USB_mode:
                    Main_Power_hScrollBar1.Value = Power_Controls.Main_Power;
                    break;
                case Power_Controls.Mode.CW_mode:
                    Main_Power_hScrollBar1.Value = Power_Controls.CW_Power;
                    break;
            }
            Master_Controls.Band_Stack_Initialized = Initialize_Band_Stack();
            oCode.SendCommand(txsocket, txtarget, AGC_ALC_Notch_Controls.CMD_SET_ALC_MULTIPLIER,
                                                                    (short)AGC_ALC_Notch_Controls.ALC_Value);
            //status = Init_I2C_Setting();
            MonitorTextBoxText(" Full Size: " + Convert.ToString(Full_size));
            MonitorTextBoxText(" Post_Initialization Finished");
            GEM_Group_Box.BringToFront();
            Master_Controls.Post_Init = true;
        }
        #region Power_Initialization
        public bool Init_Power_values()
        {
            String path, line;
            System.IO.StreamReader file;
            short temp_int = 0;
            String temp_string;

            MonitorTextBoxText(" Init_Power_values -> Entered");
            List<string> MyList = new List<string>();
            //oCode.Platform = (int)Environment.OSVersion.Platform;
            // get path to local Appdata folder
            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
#if RPI
            path += "/mscc-GEMINUS/power.ini";
#else
            path += "\\multus-sdr-client\\power.ini";
#endif

            // try to open the file
            try
            {
                //file = new System.IO.StreamReader(path);
                file = new System.IO.StreamReader(File.OpenRead(path));
            }

            // if the file open fails, whine prettily and return false
            catch (IOException e)
            {
                string er = e.Message;
                DialogResult ret = MessageBox.Show(" Power.ini Open Failed: " + er +
                    " Make note of the error and contact Multus SDR, LLC.",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return false;
            }
            while ((line = file.ReadLine()) != null)
            {
                temp_string = getBetween(line, "AM_POWER=", ",");
                Int16.TryParse(temp_string, out temp_int);
                //AM_Carrier_hScrollBar1.Value = temp_int;
                Power_Controls.AM_Power = temp_int;
                AM_Carrier_label36.Text = Convert.ToString(temp_int) + " %";
                MonitorTextBoxText(" AM Power: " + Convert.ToString(temp_int));

                temp_string = getBetween(line, "LSB_POWER=", ",");
                Int16.TryParse(temp_string, out temp_int);
                //Power_hScrollBar1.Value = temp_int;
                Power_Controls.Main_Power = temp_int;
                SSB_Power_label36.Text = Convert.ToString(temp_int) + " %";
                MonitorTextBoxText(" LSB Power: " + Convert.ToString(temp_int));

                temp_string = getBetween(line, "USB_POWER=", ",");
                Int16.TryParse(temp_string, out temp_int);
                //Power_hScrollBar1.Value = temp_int;
                Power_Controls.Main_Power = temp_int;
                SSB_Power_label36.Text = Convert.ToString(temp_int) + " %";
                MonitorTextBoxText(" USB Power: " + Convert.ToString(temp_int));

                temp_string = getBetween(line, "CW_POWER=", ",");
                Int16.TryParse(temp_string, out temp_int);
                //CW_Power_hScrollBar1.Value = temp_int;
                Power_Controls.CW_Power = temp_int;
                CW_Power_label36.Text = Convert.ToString(temp_int) + " %";
                MonitorTextBoxText(" CW Power: " + Convert.ToString(temp_int));

                temp_string = getBetween(line, "TUNE_POWER=", ";");
                Int16.TryParse(temp_string, out temp_int);
                Tune_Power_hScrollBar1.Value = temp_int;
                Power_Controls.TUNE_Power = temp_int;
                IQ_Controls.Tune_power = temp_int;
                Tune_Power_label37.Text = Convert.ToString(temp_int);
                MonitorTextBoxText(" TUNE Power: " + Convert.ToString(temp_int));
            }
            file.Close();
            MonitorTextBoxText(" Init_Power_values -> finished");
            return true;
        }
        #endregion Power_Initialization
        #endregion Initialization Routines

