        private void MFC_Enter(object sender, EventArgs e)
        {
            MonitorTextBoxText(" MFC_Enter -> MFC tab entered");
            MonitorTextBoxText(" MFC_Enter -> Master_Controls.QRP_Mode: " + Convert.ToString(Master_Controls.QRP_Mode));
            Master_Controls.Mouse_Controls.control_window = Master_Controls.Mouse_Controls.NO_OP;
            if (Transceiver_Model_Settings.Transceiver_Type == Transceiver_Model_Settings.TRANCEIVER_SOLIDUS)
            {
                MonitorTextBoxText(" MFC_Enter. Transceiver_Model_Settings.Transceiver_Type: " + Convert.ToString(Transceiver_Model_Settings.Transceiver_Type));
                //oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 1);
                //Solidus_Band_label4.Text = Convert.ToString(VFOA_Master_Controls.current_band) + " M";
                if (Master_Controls.Tuning_Mode || Master_Controls.Transmit_Mode)
                {
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_TX_ON, 0);
                    if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                    {
                        oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    }
                }
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                MonitorTextBoxText(" MFC_Enter -> Current Band: " + VFOA_Master_Controls.current_band);
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, Power_Controls.Mode.TUNE_mode);
                Set_Button_Color(false, buttTune);
                Set_Button_Color(false, Tune_vButton2, "TUN");
                Set_Button_Color(false, button1, "PTT");
                Set_Button_Color(false, buttTune);
                Master_Controls.PPT_Mode = false;
                Master_Controls.Transmit_Mode = false;
