        public void Set_Button_Color(bool active, Button mybutton, FontStyle style)
        {
            switch (active)
            {
                case true:
                    mybutton.BackColor = Master_Controls.Display_Colors.Button_Active_Background;
                    mybutton.ForeColor = Master_Controls.Display_Colors.Button_Active_Foreground;
                    mybutton.Font = new Font(mybutton.Font, style);
                    break;
                default:
