        //The following routes are work arounds for the Bogus implementation of Winforms by Mono
        #region Mono_Management
        public void Main_MouseWheel(object sender, MouseEventArgs e)
        {
            Int32 n = e.Delta;

            if (n > 0) n = 1; else n = -1;      // convert mousewheel delta to either 1 or -1
            switch (Master_Controls.Mouse_Controls.control_window)
            {
                case Master_Controls.Mouse_Controls.MAIN_FREQUENCY:
                    Manage_Main_Frequency(n);
                    break;
                case Master_Controls.Mouse_Controls.VOLUME_BUTTON:
                    Volume_textbox2_MouseWheel(n);
                    break;
                case Master_Controls.Mouse_Controls.MIC_GAIN_BUTTON:
                    Microphone_textBox2_MouseWheel(n);
                    break;
                case Master_Controls.Mouse_Controls.MAIN_POWER_SLIDER:
                    Main_Power_MouseWheel(n);
                    break;
                case Master_Controls.Mouse_Controls.RIT:
                    RIT_MouseWheel(n);
                    break;
                case Master_Controls.Mouse_Controls.IQBD_SLIDER:
                    IQBD_MouseWheel(n);
                    break;
                case Master_Controls.Mouse_Controls.COMPRESSION_SLIDER:
                    Compression_MouseWheel(n);
                    break;
                case Master_Controls.Mouse_Controls.NO_OP:
                    break;
            }
        }
        private void Mouse_Timer_Tick(object sender, EventArgs e)
        {
            int mouse_interval = 100;
            Master_Controls.Mouse_Controls.Mouse_Down_Count++;
            mouse_interval = Mouse_Timer.Interval;
            switch (Master_Controls.Mouse_Controls.Mouse_Down_Count)
            {
                case 3:
                    mouse_interval -= 100;
                    break;
                case 6:
                    mouse_interval -= 100;
                    break;
                case 9:
                    mouse_interval -= 100;
                    break;
                case 12:
                    mouse_interval -= 100;
                    break;
            }
            if (mouse_interval >= 100)
            {
                Mouse_Timer.Interval = mouse_interval;
            }
            switch (Master_Controls.Mouse_Controls.Mouse_Buttons.mouse_button)
            {
                case Master_Controls.Mouse_Controls.Mouse_Buttons.FREQ_UP:
                    Freq_Up_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.FREQ_DOWN:
                    Freq_Down_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.VOLUME_UP:
                    Volume_UP_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.VOLUME_DOWN:
                    Volume_Down_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.MIC_GAIN_UP:
                    MIC_Gain_Up_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.MIC_GAIN_DOWN:
                    MIC_Gain_Down_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.RIT_UP:
                    RIT_Up_button_Click(null, null);
                    break;
                case Master_Controls.Mouse_Controls.Mouse_Buttons.RIT_DOWN:
                    RIT_Down_button_Click(null, null);
                    break;
            }
        }
        #endregion Mono_Management

        #region IQBD_RX_MANAGEMENT
        private void IQ_Freq_hScrollBar1_Scroll(object sender, ScrollEventArgs e)
        {
            int value;
            int total_freq;
            if (Master_Controls.isLoading) return;
            value = IQ_Freq_hScrollBar1.Value;
            if (IQ_Controls.IQ_RX_Offset != value)
            {
                IQ_Controls.IQ_RX_Offset = value;
                if (IQ_Controls.Up_24KHz)
                {
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, (IQ_Controls.IQ_RX_Freq +
                                                                                IQ_Controls.IQ_RX_Up_24K_freq + IQ_Controls.IQ_RX_Offset));
                    total_freq = IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Up_24K_freq + IQ_Controls.IQ_RX_Offset;
                }
                else
                {
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, (IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Offset));
                    total_freq = IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Offset;
                }
                Display_IQ_freq(total_freq);
            }
        }
        private void IQ_UP24KHz_checkBox2_CheckedChanged(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            Freq_Cal_groupBox4.Enabled = false;
            Freq_Cal_groupBox4.Visible = false;
            oCode.SendCommand(txsocket, txtarget, Transceiver_Model_Settings.CMD_SET_DISPLAY_MODE, 2);

            if (!IQ_Controls.Up_24KHz)
            {
                IQ_Controls.Up_24KHz = true;
                Set_Check_Box_Color(true, IQ_UP24KHz_checkBox2);
                Reset_Freq_button3.Enabled = false;
                Display_IQ_freq(IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Up_24K_freq + IQ_Controls.IQ_RX_Offset);
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, (IQ_Controls.IQ_RX_Freq +
                                                                        IQ_Controls.IQ_RX_Up_24K_freq + IQ_Controls.IQ_RX_Offset));
            }
            else
            {
                IQ_Controls.Up_24KHz = false;
                Set_Check_Box_Color(false, IQ_UP24KHz_checkBox2);
                Reset_Freq_button3.Enabled = true;
                Display_IQ_freq(IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Offset);
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, (IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Offset));
            }
        }
        private void Reset_Freq_button3_Click(object sender, EventArgs e)
        {
            IQ_Freq_hScrollBar1.Value = 0;
            IQ_Controls.IQ_RX_Offset = 0;
            if (IQ_Controls.Up_24KHz)
            {
                Display_IQ_freq(IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Up_24K_freq);
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, IQ_Controls.IQ_RX_Freq + IQ_Controls.IQ_RX_Up_24K_freq);
            }
            else
            {
                Display_IQ_freq(IQ_Controls.IQ_RX_Freq);
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, IQ_Controls.IQ_RX_Freq);
            }
        }
        private int Set_IQ_RX_Band()
        {
            int status = 0;
            if (!Band_Bank.General_Bank.General_Bank_Selected)
            {
                switch (VFOA_Master_Controls.current_band)
                {
                    case 160:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B160.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 160);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B160;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B160.Freq);
                        break;

                    case 80:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B80.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 80);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B80;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B80.Freq);
                        break;

                    case 60:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B60.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 60);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B60;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B60.Freq);
                        break;

                    case 40:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B40.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 40);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B40;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B40.Freq);
                        break;

                    case 30:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B30.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 30);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B30;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B30.Freq);
                        break;

                    case 20:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B20.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 20);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B20;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B20.Freq);
                        break;

                    case 17:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B17.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 17);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B17;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B17.Freq);
                        break;

                    case 15:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B15.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 15);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B15;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B15.Freq);
                        break;

                    case 12:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B12.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 12);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B12;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B12.Freq);
                        break;

                    case 10:
                        IQ_Controls.IQ_RX_Freq = VFOA_Last_Used.Last_used.B10.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 10);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B10;
                        Display_IQ_freq(VFOA_Last_Used.Last_used.B10.Freq);
                        break;

                    default:
                        status = 1;
                        break;
                }
            }
            else
            {
                status = 1;
            }
            MonitorTextBoxText(" Set_IQ_RX_Band. VFOA_Master_Controls.current_band: " + 
                    Convert.ToString(VFOA_Master_Controls.current_band));
            return status;
        }
        private int Geminus_Set_IQ_RX_Band()
        {
            int status = 0;
            if (Band_Bank.Geminus_Bank.Band != Band_Bank.Geminus_Bank.GEN)
            {
                switch (Band_Bank.Geminus_Bank.Band)
                {
                    case Band_Bank.Geminus_Bank.B2200:
                        IQ_Controls.IQ_RX_Freq = Band_Bank.Geminus_Bank.Last_Used.B2200.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 2200);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B2200;
                        Display_IQ_freq(Band_Bank.Geminus_Bank.Last_Used.B2200.Freq);
                        break;
                    case Band_Bank.Geminus_Bank.B630:
                        IQ_Controls.IQ_RX_Freq = Band_Bank.Geminus_Bank.Last_Used.B630.Freq;
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 630);
                        IQ_Controls.Current_RX_Band = IQ_Controls.B630;
                        Display_IQ_freq(Band_Bank.Geminus_Bank.Last_Used.B630.Freq);
                        break;

