        private void Freq_Cal_Smeter_Timer_Tick(object sender, EventArgs e)
        {
            Signal_Average((Db_to_Smeter(Smeter_controls.smeter_value)), false);
        }
        private void Signal_Average(int svalue, bool reset)
        {
            String smeter_message;
            int low_smeter_limit = 5;

            if (Frequency_Calibration_controls.Freq_Cal_Loose == true)
            {
                low_smeter_limit = 5;
            }
            else
            {
                low_smeter_limit = 7;
            }
            Signal_Average_data.Average = 0;
            Signal_Average_data.S_Value_Array[0] = svalue;
            for (Signal_Average_data.Average_Count = 0;
                Signal_Average_data.Average_Count < Signal_Average_data.AVERAGE_LIMIT;
                Signal_Average_data.Average_Count++)
            {
                Signal_Average_data.Average = Signal_Average_data.Average +
                    Signal_Average_data.S_Value_Array[Signal_Average_data.Average_Count];
            }
            Signal_Average_data.Smeter_Average = Signal_Average_data.Average / Signal_Average_data.Average_Count;
            for (Signal_Average_data.i = (Signal_Average_data.AVERAGE_LIMIT - 1);
                Signal_Average_data.i > 0; Signal_Average_data.i--)
            {
                Signal_Average_data.S_Value_Array[Signal_Average_data.i] =
                                            Signal_Average_data.S_Value_Array[(Signal_Average_data.i - 1)];
            }
            smeter_message = "S" + Convert.ToString(Signal_Average_data.Smeter_Average);
            //Set_Label_Color(false, Signal_Average_label,smeter_message, smeter_message, Color.Red);
            if (Signal_Average_data.Smeter_Average < low_smeter_limit)
            {
                Set_Label_Color(true, Signal_Average_label, smeter_message, Color.Red);
            }
            else
            {
                Set_Label_Color(true, Signal_Average_label, smeter_message, Color.Green);
            }
            if (reset)
            {
                MonitorTextBoxText(" reset: " + Convert.ToString(reset));
                for (Signal_Average_data.Average_Count = 0; Signal_Average_data.Average_Count < Signal_Average_data.AVERAGE_LIMIT;
                    Signal_Average_data.Average_Count++)
                {
                    Signal_Average_data.S_Value_Array[Signal_Average_data.Average_Count] = 0;
                }
                Signal_Average_data.i = 0;
                Signal_Average_data.Average = 0;
            }
        }
