        private void Freq_Calibration_Status()
        {
            Frequency_Calibration_controls.Calibration_In_Progress = false;
            Set_Button_Color(false, Freq_Auto_Calibrate_button);
            Manage_Frequency_Controls(true);
            if (Frequency_Calibration_controls.Calibration_Status == 1)
            {
                if (Frequency_Calibration_controls.Check_only)
                {
                    Set_Label_Color(true, Freq_Calibration_Status_label, "CHECK COMPLETED", Color.Green);
                    Frequency_Calibration_controls.Check_only = false;
                }
                else
                {
                    Frequency_Calibration_controls.Frequency_Calibrated = 1;
                    //Frequency_Calibration_controls.Reset = false;
                    Master_Controls.Client_Update_Flag = true;
                    if (Frequency_Calibration_controls.Fine_Calibration && !Frequency_Calibration_controls.Coarse_Calibration)
                    {
                        Set_Label_Color(true, Freq_Calibration_Status_label, "FINE CALIBRATION COMPLETED", Color.Green);
                    }
                    if (Frequency_Calibration_controls.Coarse_Calibration && !Frequency_Calibration_controls.Fine_Calibration)
                    {
                        Set_Label_Color(true, Freq_Calibration_Status_label, "COARSE CALIBRATION COMPLETED", Color.Green);
                    }
                    if (Frequency_Calibration_controls.Coarse_Calibration && Frequency_Calibration_controls.Fine_Calibration)
                    {
                        Set_Label_Color(true, Freq_Calibration_Status_label, "FINE CALIBRATION COMPLETED", Color.Green);
                    }
                }
            }
            else
            {
                if (Frequency_Calibration_controls.Check_only)
                {
                    Set_Label_Color(true, Freq_Calibration_Status_label, "CHECK FAILED", Color.Red);
                    Frequency_Calibration_controls.Check_only = false;
                }
                else
                {
                    Set_Label_Color(true, Freq_Calibration_Status_label, "CALIBRATION FAILED", Color.Red);
                }
            }
            Frequency_Calibration_controls.Message_Displayed = true;
        }
