        private void Freq_Auto_Calibrate_button_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            if (!Band_Bank.General_Bank.General_Bank_Selected)
            {
                DialogResult ret = MessageBox.Show("GENERAL BAND NOT SELECTED\r\n" + "RETURN TO THE MAIN TAB AND SELECT THE GENERAL BAND.",
                   "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return;
            }
            Adjust_PPM_Coarse_hScrollBar.Value = 0;
            Adjust_PPM_Coarse_hScrollBar.Enabled = false;
            PPM_Coarse_Value_Label.Visible = false;
            PPM_Coarse_Value_Label.Enabled = false;
            Set_Calibration_button.Enabled = false;
            if (Frequency_Calibration_controls.Frequency_Calibrated == 0)
            {
                MessageBox.Show("PROFICIO FREQUENCY CALIBRATION HAS NOT BEEN CALIBRATED.\n\r" +
                    "PERFORM A DEFAULT CALIBRATION OR MANUAL CALIBRATION\r\nAND THEN PROCEED",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return;
            }
            if (Frequency_Calibration_controls.Reset == true)
            {
                if (Filter_control.CW_Pitch_Index != Filter_control.CW_PITCH_600_INDEX)
                {
                    oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_BW, Filter_control.CW_FILTER_200_INDEX);
                    oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_PITCH, Filter_control.CW_PITCH_600_INDEX);
                }
                if (Signal_Average_data.Smeter_Average <= 6)
                {
                    DialogResult smeter_answer =
                           MessageBox.Show("SIGNAL IS BELOW REQUIRED STRENGTH FOR CALIBRATION\r\nDO YOU WISH TO PROCEED?",
                                                                        "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk,
                                                                        MessageBoxDefaultButton.Button2);
                    if (smeter_answer == DialogResult.No)
                    {
                        return;
                    }
                }
                DialogResult ret = MessageBox.Show("THE TRANSCEIVER WILL BE AUTO CALIBRATED.\r\n" +
                      "PLEASE WAIT UNTIL THIS BOX DISPLAYS: CALIBRATED\r\n" +
                      "DO NOT LEAVE THIS PAGE OR PRESS ANY OTHER BUTTONS OR SLIDERS " +
                      "UNTIL THE CALIBRATION HAS COMPLETED\r\n" +
                      "DOING OTHERWISE WILL CAUSE THE CALIBRATION TO FAIL WITH INDETERMINATE RESULTS \r\n" + "\r\n" +
                      "DO YOU WISH TO PROCEED?",
                      "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk, MessageBoxDefaultButton.Button2);
                if (ret == DialogResult.Yes)
                {
                    Calibration_progressBar1.Value = 0;
                    //oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_STANDARD_CARRIER,
                    //                                            Frequency_Calibration_controls.Target_Calibration_Frequency);
                    if (Frequency_Calibration_controls.Freq_Cal_Loose == true)
                    {
                        oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CAL_LOOSE, 1);
                    }
                    else
                    {
                        oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CAL_LOOSE, 0);
                    }
                    Frequency_Calibration_controls.freq_text_box_cleared = false;
                    Set_Button_Color(true, Freq_Auto_Calibrate_button);
                    Master_Controls.popup_button_config = 0;
                    oCode.SendCommand(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_FREQ_CAL_CHECK, 0);
                    DialogResult calibration_type = MessageBox.Show("COURSE OR FINE CALIBRATION?\r\nYES - COURSE, NO - FINE, OR CANCEL",
                                                                        "MSCC", MessageBoxButtons.YesNoCancel, MessageBoxIcon.Question,
                                                                        MessageBoxDefaultButton.Button3);
                    if (calibration_type == DialogResult.Yes)
                    {
                        Set_Label_Color(false, Freq_Calibration_Status_label, "RUNNING COARSE CALIBRATION\r\n!WAIT!", Color.Black);
                        oCode.SendCommand(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CAL_MODE, 0);
                        Frequency_Calibration_controls.Coarse_Calibration = true;
                        Frequency_Calibration_controls.Fine_Calibration = false;
                    }
                    if (calibration_type == DialogResult.No)
                    {
                        Set_Label_Color(false, Freq_Calibration_Status_label, "RUNNING FINE CALIBRATION\r\n!WAIT!", Color.Black);
                        oCode.SendCommand(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CAL_MODE, 1);
                        Frequency_Calibration_controls.Fine_Calibration = true;
                    }
                    if (calibration_type == DialogResult.Cancel)
                    {
                        Set_Button_Color(false, Freq_Auto_Calibrate_button, "AUTO CALIBRATE");
                        return;
                    }

                    oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_START_CALIBRATE,
                                                                        Frequency_Calibration_controls.Target_Calibration_Frequency);
                    Freq_CAl_Progress_Lable.Visible = true;
                    Frequency_Calibration_controls.Calibration_In_Progress = true;
                    Manage_Frequency_Controls(false);
                    Freq_Auto_Calibrate_button.Enabled = false;
                }
            }
            else
            {
                MessageBox.Show("A DEFAULT CALIBRATION OR MANUAL CALIBRATION HAS NOT PERFORMED", "MSCC",
                                 MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
        }
        private void Manage_Frequency_Controls(bool on_off)
        {
            switch (on_off)
            {
                case false:
                    Freq_Cal_Reset_button4.Enabled = false;
                    Freq_Cal_Loose_button.Enabled = false;
                    Freq_Check_Button.Enabled = false;
                    Freq_Auto_Calibrate_button.Enabled = false;
                    break;
                default:

                    Freq_Cal_Reset_button4.Enabled = true;
                    Freq_Cal_Loose_button.Enabled = true;
                    Freq_Check_Button.Enabled = true;
                    Freq_Cal_Reset_button4.Enabled = true;
                    Freq_Cal_Loose_button.Enabled = true;
                    Freq_Auto_Calibrate_button.Enabled = true;
                    Set_Calibration_button.Enabled = true;
                    break;
            }
        }
