        private void Freq_Cal_Reset_button4_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            DialogResult ret = MessageBox.Show("RESET WILL RESET THE FREQUENCY CALIBRATION TO THE DEFAULT CALIBRATION\r\n" +
                "DO YOU WISH TO PROCEED? ", "MSCC", MessageBoxButtons.YesNo,
                                                    MessageBoxIcon.Asterisk, MessageBoxDefaultButton.Button2);
            if (ret == DialogResult.Yes)
            {
                if (!Frequency_Calibration_controls.Calibration_In_Progress)
                {
                    if (Filter_control.CW_Pitch_Index != Filter_control.CW_PITCH_600_INDEX)
                    {
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_BW, Filter_control.CW_FILTER_200_INDEX);
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_PITCH, Filter_control.CW_PITCH_600_INDEX);
                    }
                    oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CAL_RESET, 1);
                    Frequency_Calibration_controls.Frequency_Calibrated = 1;
                    Frequency_Calibration_controls.Reset = true;
                    Frequency_Calibration_controls.Reset_pressed = true;
                    Master_Controls.Client_Update_Flag = true;
                    Set_Calibration_button.Enabled = true;
                    Freq_Auto_Calibrate_button.Enabled = true;
                }
                else
                {
                    MessageBox.Show("Frequency Calibration Check In Progress.", "MSCC",
                                    MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                    return;
                }
            }
            else
            {
                return;
            }
        }
        private void Freq_Check_Button_Click(object sender, EventArgs e)
