        private void Set_Calibration_button_Click(object sender, EventArgs e)
        {
            if (!Band_Bank.General_Bank.General_Bank_Selected)
            {
                DialogResult ret = MessageBox.Show("GENERAL BAND NOT SELECTED\r\n" + "RETURN TO THE MAIN TAB AND SELECT THE GENERAL BAND.",
                   "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return;
            }
            if (Frequency_Calibration_controls.Frequency_Calibrated == 1)
            {
                if (Frequency_Calibration_controls.Manual_Calibration_Button_Toggle == false){
                    if (Filter_control.CW_Pitch_Index != Filter_control.CW_PITCH_600_INDEX)
                    {
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_BW, Filter_control.CW_FILTER_200_INDEX);
                        oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_PITCH, Filter_control.CW_PITCH_600_INDEX);
                    }
                    Set_Button_Color(true, Set_Calibration_button);
                    MonitorTextBoxText(" Perform_Manual_Calibration_Click");
                    DialogResult ret = MessageBox.Show("MANUAL CALIBRATION\r\n" +
                     "DO YOU WISH TO PROCEED?",
                     "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk, MessageBoxDefaultButton.Button2);
                    if (ret == DialogResult.Yes)
                    {
                        Adjust_PPM_Coarse_hScrollBar.Visible = true;
                        PPM_Coarse_Value_Label.Visible = true;
                        DialogResult adjustment = MessageBox.Show("NOW ADJUST THE SLIDER\r\n" +
                            "UNTIL THE SIGNAL IS IN THE CENTER OF THE DISPLAY AND S METER DISPLAYS HIGHEST VALUE",
                            "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Information);
                        Adjust_PPM_Coarse_hScrollBar.Enabled = true;
                        Adjust_PPM_Coarse_hScrollBar.Value = 0;
                        PPM_Coarse_Value_Label.Text = "MANUAL OFFSET VALUE: 0";
                        Freq_Cal_Reset_button4.Enabled = false;
                        Freq_Cal_Loose_button.Enabled = false;
                        Freq_Check_Button.Enabled = false;
                        Freq_Auto_Calibrate_button.Enabled = false;
                        Freq_Calibration_Status_label.Text = "MANUAL CALIBRATION";
                        Set_Label_Color(true, Freq_Calibration_Status_label);
                        Frequency_Calibration_controls.Manual_Calibration = true;
                        Frequency_Calibration_controls.Fine_Calibration = false;
                        Frequency_Calibration_controls.Coarse_Calibration = false;
                        Frequency_Calibration_controls.Frequency_Calibrated = 1;
                        Frequency_Calibration_controls.Reset = true;
                        Frequency_Calibration_controls.Reset_pressed = true;
                        Master_Controls.Client_Update_Flag = true;
                        Frequency_Calibration_controls.Manual_Calibration_Button_Toggle = true;
                        oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_FORCE_CALIBRATION,1);
                    }
                    else
                    {
                        Set_Button_Color(false, Set_Calibration_button);
                        Set_Label_Color(false, Freq_Calibration_Status_label, "CALIBRATION STATUS", Color.Black);
                        return;
                    } 
                }
                else
                {
                    Frequency_Calibration_controls.Manual_Calibration_Button_Toggle = false;
                    Freq_Cal_Reset_button4.Enabled = true;
                    Freq_Cal_Loose_button.Enabled = true;
                    Freq_Check_Button.Enabled = true;
                    Freq_Auto_Calibrate_button.Enabled = true;
                    Set_Button_Color(false, Set_Calibration_button);
                    Adjust_PPM_Coarse_hScrollBar.Enabled = false;
                    Adjust_PPM_Coarse_hScrollBar.Visible = false;
                    PPM_Coarse_Value_Label.Visible = false;
                    if (Frequency_Calibration_controls.Manual_Calibration == true)
                    {
                        Frequency_Calibration_controls.Manual_Calibration = false;
                        Set_Label_Color(false, Freq_Calibration_Status_label);
                        DialogResult accept = MessageBox.Show("ACCEPT THIS CALIBRATION SETTING?.\r\n",
                                    "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk, MessageBoxDefaultButton.Button2);
                        if (accept == DialogResult.Yes)
                        {
                            oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CALIBRATION_FINISHED, 1);
                            Freq_Calibration_Status_label.Text = "MANUAL CALIBRATION \r\nCALIBRATED";
                        }
                        else
                        {
                            oCode.SendCommand32(txsocket, txtarget, Frequency_Calibration_controls.CMD_SET_CALIBRATION_FINISHED, 0);
                            Freq_Calibration_Status_label.Text = "MANUAL CALIBRATION \r\nNOT CALIBRATED";
                        }
                    }
                }
            }
            else
            {
                DialogResult calibrated = MessageBox.Show("PROFICIO IS NOT DEFAULT CALIBRATED.\r\n" + "" +
                        "CLICK THE DEFAULT BUTTON TO SET THE FACTORY CALIBRATION",
                        "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
        }
