        private short get_previous_power(short band)
        {
            short power = 0;
            switch (band)
            {
                case 160:
                    switch (VFOA_Last_Used.Last_used.B160.Mode)
                    {
                        case 'A':
                            power = VFOA_Last_Used.Last_used.B160.AM_power;
                            break;

                        case 'U':
                            power = VFOA_Last_Used.Last_used.B160.SSB_power;
                            break;

                        case 'L':
                            power = VFOA_Last_Used.Last_used.B160.SSB_power;
                            break;

