        private void mainmodebutton2_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading == true) return;
            // mode button clicked
            MonitorTextBoxText(" mainmodebutton2 Entered ");
            char mode = 'N';
            Master_Controls.modeswitch++;
            if (Master_Controls.modeswitch > Power_Controls.Mode.CW_mode)
            {
                Master_Controls.modeswitch = Power_Controls.Mode.AM_mode;
            }
            switch (Master_Controls.modeswitch)
            {
                case Power_Controls.Mode.AM_mode:
                    mainmodebutton2.Text = "AM";
                    mode = 'A';
                    break;

                case Power_Controls.Mode.LSB_mode:
                    mainmodebutton2.Text = "LSB";
                    mode = 'L';
                    break;

                case Power_Controls.Mode.USB_mode:
                    mainmodebutton2.Text = "USB";
                    mode = 'U';
                    break;

                case Power_Controls.Mode.CW_mode:
                    mainmodebutton2.Text = "CW";
                    mode = 'C';
                    break;
            }
            VFOA_Last_Used.Last_used.Current_mode = mode;
            if (Band_Bank.Geminus_Bank.Geminus_Selected)
            {
                Set_Gem_Band_Mode(mode);
            }
            else
            if (!Band_Bank.General_Bank.General_Bank_Selected)
            {
                Band_Bank.HAM_Last_Used.Mode = mode;
            }
            else
            {
                Set_Gen_Band_Mode(mode);
            }
            MonitorTextBoxText(" mainmodebutton2 -> New Mode: " + mode + ", Current_band: " +
                VFOA_Master_Controls.current_band);
            switch (VFOA_Master_Controls.current_band)
            {
                case 160:
                    VFOA_Last_Used.Last_used.B160.Mode = mode;
                    break;
                case 80:
                    VFOA_Last_Used.Last_used.B80.Mode = mode;
                    break;
                case 60:
                    VFOA_Last_Used.Last_used.B60.Mode = mode;
                    break;
                case 40:
                    VFOA_Last_Used.Last_used.B40.Mode = mode;
                    break;
                case 30:
                    VFOA_Last_Used.Last_used.B30.Mode = mode;
                    break;
                case 20:
                    VFOA_Last_Used.Last_used.B20.Mode = mode;
                    break;
                case 17:
                    VFOA_Last_Used.Last_used.B17.Mode = mode;
                    break;
                case 15:
                    VFOA_Last_Used.Last_used.B15.Mode = mode;
                    break;
                case 12:
                    VFOA_Last_Used.Last_used.B12.Mode = mode;
                    break;
                case 10:
                    VFOA_Last_Used.Last_used.B10.Mode = mode;
                    break;
                default:
                    VFOA_Last_Used.Last_used.GEN.Mode = mode;
                    break;
            }
            VFOA_Last_Used.Last_used.Current_mode = mode;
            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, (short)Master_Controls.modeswitch);
            Manage_CW_Phones();
            //Manage_CW_QSK(mode);
            MonitorTextBoxText(" mainmodebutton2 finished ");
        }
