        private void Step_button8_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            Master_Controls.Step_Index--;
            if (Master_Controls.Step_Index < 0) Master_Controls.Step_Index = 5;
            switch (Master_Controls.Step_Index)
            {
                case 5:
                    Step_button8.Text = "1Hz";
                    break;
                case 4:
                    Step_button8.Text = "10Hz";
                    break;
                case 3:
                    Step_button8.Text = "100Hz";
                    break;
                case 2:
                    Step_button8.Text = "1KHz";
                    break;
                case 1:
                    Step_button8.Text = "10KHz";
                    break;
                case 0:
                    Step_button8.Text = "100KHz";
                    break;
            }
            VFOA_Master_Controls.Freq_Tune_Index = (short)Master_Controls.Step_Index;
            oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_STEP_VALUE, VFOA_Master_Controls.Freq_Tune_Index);
            Master_Controls.FreqDigit = (short)Swap_tuning_step(VFOA_Master_Controls.Freq_Tune_Index);
            Set_Freq_Digit_Pointer();
        }
        private void button4_Click(object sender, EventArgs e)
        {
            String message;

            DialogResult ret = MessageBox.Show("STOP MSCC?", "MSCC", MessageBoxButtons.YesNo,
                MessageBoxIcon.Question, MessageBoxDefaultButton.Button2);
            if (ret == DialogResult.Yes)
            {
                Master_Controls.Shutdown_By_User = true;
                //if (Band_Bank.General_Bank.General_Bank_Selected || Band_Bank.Geminus_Bank.Geminus_Selected)
                //{
                //    Restore_HAM_Band();
                //}
                if (Band_Bank.Geminus_Bank.Geminus_Selected)
                {
                    Restore_GEM_Band();
                }
                Master_Controls.Shutdown = true;
                Smeter_Timer.Enabled = false;
                Smeter_Timer.Stop();
                Master_State_Machine_Timer.Enabled = false;
                Master_State_Machine_Timer.Stop();
                //Thread.Sleep(5);
                if (Transceiver_Model_Settings.Client_Initialized)
                {
                    Update_Client_Settings();
                }
                MonitorTextBoxText(" MSCC shutdown by user");
                if (Transceiver_Model_Settings.Shutdown == 0)
                {
                    if (Master_Controls.Initialize_network_status == true)
                    {
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_STOP, Transceiver_Model_Settings.Stop_States.STOP_NORMAL);
                    }
                }
                else
                {
                    if (Transceiver_Model_Settings.Transceiver_Type == Transceiver_Model_Settings.TRANCEIVER_SOLIDUS)
                    {
                        message = "SHUTDOWN SOLIDUS? \r\nTHIS WILL TAKE A FEW MOMENTS. \r\n!WAIT! UNTIL RUN LITE IS OFF TO POWER OFF";
                    }
                    else
                    {
                        message = "SHUTDOWN FORTIS CUBE? \r\nTHIS WILL TAKE A FEW MOMENTS. \r\n!WAIT! UNTIL RUN LITE IS OFF TO POWER OFF";
                    }
                    DialogResult shutdown_ret = MessageBox.Show(message, "MSCC",
                        MessageBoxButtons.YesNo, MessageBoxIcon.Question, MessageBoxDefaultButton.Button2);
                    if (shutdown_ret == DialogResult.Yes)
                    {
                        if (Master_Controls.Initialize_network_status == true)
                        {
                            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_STOP, Transceiver_Model_Settings.Stop_States.STOP_SHUTDOWN);
                        }
                    }
                    else
                    {
                        if (Master_Controls.Initialize_network_status == true)
                        {
                            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_STOP, Transceiver_Model_Settings.Stop_States.STOP_NORMAL);
                        }
                    }
                }
                Settings.Default.Main_Window_Location = this.Location;
                Settings.Default.Save();
                Thread.Sleep(5);
                Application.Exit();
            }
        }
        private void ACG_button_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            MonitorTextBoxText(" AGC_label16_Click -> AGC_ALC_Notch_Controls.AGC_Level: " + AGC_ALC_Notch_Controls.AGC_Level);
            AGC_ALC_Notch_Controls.AGC_Level++;
            if (AGC_ALC_Notch_Controls.AGC_Level > 2) AGC_ALC_Notch_Controls.AGC_Level = 0;

            switch (AGC_ALC_Notch_Controls.AGC_Level)
            {
                case 0:
                    ACG_button.Text = "SLO";
                    AGC_listBox1.SelectedIndex = 0;
                    break;

                case 1:
                    ACG_button.Text = "MED";
                    AGC_listBox1.SelectedIndex = 1;
                    break;

                case 2:
                    ACG_button.Text = "FST";
                    AGC_listBox1.SelectedIndex = 2;
                    break;
            }
            oCode.SendCommand(txsocket, txtarget, AGC_ALC_Notch_Controls.CMD_GET_SET_AGC, (byte)AGC_ALC_Notch_Controls.AGC_Level);
            MonitorTextBoxText(" AGC_label16_Click -> AGC_ALC_Notch_Controls.AGC_Level: " + AGC_ALC_Notch_Controls.AGC_Level);
        }
