                    case 10:
                        VFOA_Last_Used.Last_used.B10.Filter_CW_index = (short)index;
                        break;

                    default:
                        VFOA_Last_Used.Last_used.GEN.Filter_CW_index = (short)index;
                        break;
                }
            }
            else
            {
                switch (VFOB_Master_Controls.current_band)
