                        break;

                    case 80:
                        VFOB_Last_Used.Last_used.B80.Filter_CW_index = (short)index;
                        break;

                    case 60:
                        VFOB_Last_Used.Last_used.B60.Filter_CW_index = (short)index;
                        break;

                    case 40:
                        VFOB_Last_Used.Last_used.B40.Filter_CW_index = (short)index;
                        break;

                    case 30:
                        VFOB_Last_Used.Last_used.B30.Filter_CW_index = (short)index;
                        break;

                    case 20:
                        VFOB_Last_Used.Last_used.B20.Filter_CW_index = (short)index;
                        break;

                    case 17:
                        VFOB_Last_Used.Last_used.B17.Filter_CW_index = (short)index;
                        break;

                    case 15:
                        VFOB_Last_Used.Last_used.B15.Filter_CW_index = (short)index;
                        break;

                    case 12:
                        VFOB_Last_Used.Last_used.B12.Filter_CW_index = (short)index;
                        break;

                    case 10:
                        VFOB_Last_Used.Last_used.B10.Filter_CW_index = (short)index;
                        break;

                    default:
                        VFOB_Last_Used.Last_used.GEN.Filter_CW_index = (short)index;
                        break;
                }
            }
            Panadapter_Controls.Filter_Index = index;
            Filter_control.CW_Bw = index;
#if FTDI
                Tuning_Knob_Controls.CW_BW_Function.BW_index = index;
#endif
            //Panadapter_Controls.CW_Filter_Size_Name = CW_Filter_listBox1.GetItemText(CW_Filter_listBox1.SelectedItem);
            MonitorTextBoxText(" CW_Filter_button8_Click -> Filter_control.CW_Filter_Index: " +
                Convert.ToString(Filter_control.CW_Filter_Index));
            /////////////////////////////////////////////////////////////////////////////////////////
            //Sending CMD_SET_CW_BW to the server is handled by case 10 of the  Master_State_Machine.
            /////////////////////////////////////////////////////////////////////////////////////////
        }
