                VFO_button.Enabled = true;
                Split_Button.Enabled = true;
                Freq_Stack_button.Enabled = true;
                MessageBox.Show("WARNING: THIS ACTIVATES THE FUNCTIONS IN BETA TEST. \r\nONE OR MORE FUNCTIONS MAY NOT FUNCTION PROPERLY.\r\nMSCC MAY FAIL",
                    "MSCC", MessageBoxButtons.OK);
                //Freq_Add_Stack_Button.Enabled = true;
            }
            else
            {
                VFO_button.Enabled = false;
                Split_Button.Enabled = false;
                Freq_Stack_button.Enabled = false;
                //Freq_Add_Stack_Button.Enabled = false;
            }
        }
