        public void VFO_Set_Band(byte vfo)
        {
            MonitorTextBoxText(" VFO_Set_Band. vfo: " + Convert.ToString(vfo) +
                " VFO_Controls.Current_Band_Set.band: " + Convert.ToString(VFO_Controls.Current_Band_Set.band));
            switch (vfo)
            {
                case VFO_Controls.VFOA:
                    switch (VFO_Controls.Current_Band_Set.band)
                    {
                        case 160:
                            Manage_B160_Band_VFOA();
                            break;
                        case 80:
                            Manage_B80_Band_VFOA();
                            break;
                        case 60:
                            Manage_B60_Band_VFOA();
                            break;
                        case 40:
                            Manage_B40_Band_VFOA();
                            break;
                        case 30:
                            Manage_B30_Band_VFOA();
                            break;
                        case 20:
                            Manage_B20_Band_VFOA();
                            break;
                        case 17:
                            Manage_B17_Band_VFOA();
                            break;
                        case 15:
                            Manage_B15_Band_VFOA();
                            break;
                        case 12:
                            Manage_B12_Band_VFOA();
                            break;
                        case 10:
                            Manage_B10_Band_VFOA();
                            break;
                    }
                    break;
                case VFO_Controls.VFOB:
                    switch (VFO_Controls.Current_Band_Set.band)
                    {
                        case 160:
                            Manage_B160_Band_VFOB();
                            break;
                        case 80:
                            Manage_B80_Band_VFOB();
                            break;
                        case 60:
                            Manage_B60_Band_VFOB();
                            break;
                        case 40:
                            Manage_B40_Band_VFOB();
                            break;
                        case 30:
                            Manage_B30_Band_VFOB();
                            break;
                        case 20:
                            Manage_B20_Band_VFOB();
                            break;
                        case 17:
                            Manage_B17_Band_VFOB();
                            break;
                        case 15:
                            Manage_B15_Band_VFOB();
                            break;
                        case 12:
                            Manage_B12_Band_VFOB();
                            break;
                        case 10:
                            Manage_B10_Band_VFOB();
                            break;
                    }
                    break;
            }
        }
        private void VFO_button_Click(object sender, EventArgs e)
        {
            switch (VFO_Controls.VFO_toggle)
            {
                case true:
                    VFO_Controls.vfo = VFO_Controls.VFOB;
                    groupBox3.Text = "VFO B";
                    VFO_Controls.VFO_toggle = false;
                    VFOB_Active_button.Visible = true;
                    //Set_GroupBox_Color(true, groupBox3);
                    break;
                default:
                    groupBox3.Text = "VFO A";
                    VFO_Controls.vfo = VFO_Controls.VFOA;
                    //Set_GroupBox_Color(false, groupBox3);
                    VFOB_Active_button.Visible = false;
                    VFO_Controls.VFO_toggle = true;
                    break;
            }
            MonitorTextBoxText(" VFO_button_Click. VFO_Controls.vfo: " + Convert.ToString(VFO_Controls.vfo));
            oCode.SendCommand(txsocket, txtarget, VFO_Controls.CMD_SET_VFO, VFO_Controls.vfo);
            Thread.Sleep(10);
            VFO_Set_Band(VFO_Controls.vfo);

        }
        private void VFO_button_Click(object sender, MouseEventArgs e)
        {
            MonitorTextBoxText(" VFO_button_Click. Buttons:  " + Convert.ToString(e.Button));
            if (e.Button == MouseButtons.Right)
            {
                if (VFO_Controls.vfo == VFO_Controls.VFOA)
                {
                    Set_VFOB_Equal(VFO_Controls.Current_Band_Set.band);
                }
                else
                {
                    Set_VFOA_Equal(VFO_Controls.Current_Band_Set.band);
                }
            }
        }
