        private void Split_Button_Click(object sender, EventArgs e)
        {
            if (VFO_Controls.Split.TX_band == 0)
            {
                MessageBox.Show("TX BAND AND FREQUENCY NOT SET.\r\nCLICK ON VFO BUTTON TO SELECT VFO B AND SET TX FREQUENCY",
                                                       "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
            else
            {
                if (VFO_Controls.Split.RX_band != VFO_Controls.Split.TX_band)
                {
                    MessageBox.Show("SELECT VFO B AND RETURN TO VFO A BEFORE ACTIVATING SPLIT.",
                                                            "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Error);

                }
                else
                {
                    if (!VFO_Controls.Split.Split_toggle)
                    {
                        Set_Button_Color(true, Split_Button);
                        oCode.SendCommand(txsocket, txtarget, VFO_Controls.CMD_SET_SPLIT, 1);
                        oCode.SendCommand32(txsocket, txtarget, VFO_Controls.CMD_SET_SPLIT_RX_FREQ, VFO_Controls.Split.RX_freq);
                        oCode.SendCommand32(txsocket, txtarget, VFO_Controls.CMD_SET_SPLIT_TX_FREQ, VFO_Controls.Split.TX_freq);
                        VFO_Controls.Split.Split_toggle = true;
                    }
                    else
                    {
                        Set_Button_Color(false, Split_Button);
                        oCode.SendCommand(txsocket, txtarget, VFO_Controls.CMD_SET_SPLIT, 0);
                        VFO_Controls.Split.Split_toggle = false;
                    }
                }
            }
        }
