        #region Band Stack Management
        private bool Update_Band_Stack_band(int band)
        {
            String path, band_stack_name;
            System.IO.StreamWriter file;

            if (!VFOA_Last_Used.Update_Band_Stack)
            {
                // get path to local Appdata folder
                path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
                band_stack_name = Band_Stack_Get_File_Name(band);
                path += "/mscc-GEMINUS/band-stack/";
                path += band_stack_name;
                MonitorTextBoxText(" Update_Band_Stack_band. Band Stack Name: " + path);

                // try to open the file
                if (File.Exists(path))
                {
                    File.Delete(path);
                }
                try
                {
                    //file = new System.IO.StreamReader(path);
                    file = new System.IO.StreamWriter(File.OpenWrite(path));
                }

                // if the file open fails, whine prettily and return false
                catch (IOException e)
                {
                    string er = e.Message;
                    DialogResult ret = MessageBox.Show("Update_Band_Stack_band. Open FAILED: " + er,
                        "MSCC-Core", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                    return false;
                }
                switch (band)
                {
                    case VFO_Controls.B160:
                        file.WriteLine("REGISTER=0,FREQ=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Freq) +
                            ",LOWCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_Low_Index) +
                             ",HIGHTCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_High_Index) +
                              ",CW=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_CW_index) +
                               ",MODE=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Mode) +
                               ";");
                        file.WriteLine("REGISTER=1,FREQ=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Freq) +
                            ",LOWCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_Low_Index) +
                             ",HIGHTCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_High_Index) +
                              ",CW=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_CW_index) +
                               ",MODE=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Mode) +
                               ";");
                        file.WriteLine("REGISTER=2,FREQ=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Freq) +
                            ",LOWCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Filter_Low_Index) +
                             ",HIGHTCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Filter_High_Index) +
                              ",CW=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Filter_CW_index) +
                               ",MODE=" + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Mode) +
                               ";");
                        break;
                    case VFO_Controls.B80:
                        file.WriteLine("REGISTER=0,FREQ=" + Convert.ToString(VFOA_Last_Used.Last_used.B80.Stacks.Stack_0.Freq) +
                            ",LOWCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B80.Stacks.Stack_0.Filter_Low_Index) +
                             ",HIGHTCUT=" + Convert.ToString(VFOA_Last_Used.Last_used.B80.Stacks.Stack_0.Filter_High_Index) +
                              ",CW=" + Convert.ToString(VFOA_Last_Used.Last_used.B80.Stacks.Stack_0.Filter_CW_index) +
                               ",MODE=" + Convert.ToString(VFOA_Last_Used.Last_used.B80.Stacks.Stack_0.Mode) +
                               ";");
                        file.WriteLine("REGISTER=1,FREQ=" + Convert.ToString(VFOA_Last_Used.Last_used.B80.Stacks.Stack_1.Freq) +
