        private string Band_Stack_Get_File_Name(int band)
        {
            string name = "TEST";
            switch (band)
            {
                case VFO_Controls.B160:
                    name = "b160.ini";
                    break;
                case VFO_Controls.B80:
                    name = "b80.ini";
                    break;
                case VFO_Controls.B60:
                    name = "b60.ini";
                    break;
                case VFO_Controls.B40:
                    name = "b40.ini";
                    break;
                case VFO_Controls.B30:
                    name = "b30.ini";
                    break;
                case VFO_Controls.B20:
                    name = "b20.ini";
                    break;
                case VFO_Controls.B17:
                    name = "b17.ini";
                    break;
                case VFO_Controls.B15:
                    name = "b15.ini";
                    break;
                case VFO_Controls.B12:
                    name = "b12.ini";
                    break;
                case VFO_Controls.B10:
                    name = "b10.ini";
                    break;
            }
            return name;
        }
        private void Update_Register(int band, short register, int freq, short low_cut, short high_cut, short cw, char mode)
        {
            MonitorTextBoxText(" Update_Register. register:" + Convert.ToString(register) + "Freq: " + Convert.ToString(freq));
            switch (band)
            {
                case VFO_Controls.B160:
                    switch (register)
                    {
                        case 0:
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Freq = freq;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_Low_Index = low_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_High_Index = high_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_CW_index = cw;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Mode = mode;
                            break;
                        case 1:
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Freq = freq;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_Low_Index = low_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_High_Index = high_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_CW_index = cw;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Mode = mode;
                            break;
