        private bool Init_Band_Stack_band(int band)
        {
            String path, line, band_stack_name;
            System.IO.StreamReader file;
            short temp_int = 0;
            int temp_freq = 0;
            String temp_string;
            short register = 0;
            int freq = 0;
            short low_cut = 0;
            short high_cut = 0;
            short cw = 0;
            char mode = 'N';

            // get path to local Appdata folder
            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            band_stack_name = Band_Stack_Get_File_Name(band);
            path += "/mscc-GEMINUS/band-stack/";
            path += band_stack_name;
            MonitorTextBoxText(" Init_Band_Stack. Band Stack Name: " + path);

            // try to open the file
            try
            {
                //file = new System.IO.StreamReader(path);
                file = new System.IO.StreamReader(File.OpenRead(path));
            }

            // if the file open fails, whine prettily and return false
            catch (IOException e)
            {
                string er = e.Message;
                DialogResult ret = MessageBox.Show(" Init_Band_Stack_band Open FAILED: " + er + " Make note of the error and contact Multus SDR, LLC.",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return false;
            }
            while ((line = file.ReadLine()) != null)
            {
                temp_string = getBetween(line, "REGISTER=", ",");
                Int16.TryParse(temp_string, out temp_int);
                register = temp_int;

                temp_string = getBetween(line, "FREQ=", ",");
                Int32.TryParse(temp_string, out temp_freq);
                freq = temp_freq;

                temp_string = getBetween(line, "LOWCUT=", ",");
                Int16.TryParse(temp_string, out temp_int);
                low_cut = temp_int;

                temp_string = getBetween(line, "HIGHCUT=", ",");
                Int16.TryParse(temp_string, out temp_int);
                //CW_Power_hScrollBar1.Value = temp_int;
                high_cut = temp_int;

                temp_string = getBetween(line, "CW=", ",");
                Int16.TryParse(temp_string, out temp_int);
                cw = temp_int;

                temp_string = getBetween(line, "MODE=", ";");
                //Int16.TryParse(temp_string, out temp_int);
                mode = temp_string[0];

                Update_Register(band, register, freq, low_cut, high_cut, cw, mode);
            }
            file.Close();
            MonitorTextBoxText(" Init_Band_Stack_band -> finished");
            return true;
        }
        public bool Initialize_Band_Stack()
        {
            bool status = false;

            status = Init_Band_Stack_band(VFO_Controls.B160);
            status = Init_Band_Stack_band(VFO_Controls.B80);
            status = Init_Band_Stack_band(VFO_Controls.B60);
            status = Init_Band_Stack_band(VFO_Controls.B40);
            status = Init_Band_Stack_band(VFO_Controls.B30);
            status = Init_Band_Stack_band(VFO_Controls.B20);
            status = Init_Band_Stack_band(VFO_Controls.B17);
            status = Init_Band_Stack_band(VFO_Controls.B15);
            status = Init_Band_Stack_band(VFO_Controls.B12);
            status = Init_Band_Stack_band(VFO_Controls.B10);
            return status;
        }
