        private void Freq_Add_Freq(int band, Int32 freq, short high_cut, short low_cut, short cw, char mode)
        {
            switch (band)
            {
                case VFO_Controls.B160:
                    switch (VFOA_Last_Used.Last_used.B160.Stacks.Stack_Add_Index)
                    {
                        case 0:
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Freq = freq;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_High_Index = high_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_Low_Index = low_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Filter_CW_index = cw;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Mode = mode;
                            break;
                        case 1:
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Freq = freq;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_High_Index = high_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_Low_Index = low_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Filter_CW_index = cw;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_1.Mode = mode;
                            break;
                        case 2:
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Freq = freq;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Filter_High_Index = high_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Filter_Low_Index = low_cut;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Filter_CW_index = cw;
                            VFOA_Last_Used.Last_used.B160.Stacks.Stack_2.Mode = mode;
                            break;
                    }
                    MonitorTextBoxText(" Freq_Add_Freq. Freq_0: " + Convert.ToString(VFOA_Last_Used.Last_used.B160.Stacks.Stack_0.Freq));
