        private void Freq_Add_Stack_Button_Click(object sender, EventArgs e)
        {
            MonitorTextBoxText(" Freq_Add_Stack_Button_Click");
            if (VFO_Controls.vfo == VFO_Controls.VFOA)
            {
                switch (VFOA_Master_Controls.current_band)
                {
                    case VFO_Controls.B160:
                        Freq_Add_Freq(VFO_Controls.B160, VFOA_Last_Used.Last_used.B160.Freq, VFOA_Last_Used.Last_used.B160.Filter_High_Index,
                                        VFOA_Last_Used.Last_used.B160.Filter_Low_Index, VFOA_Last_Used.Last_used.B160.Filter_CW_index,
