        #region Main Freq Management
        private void Main_Frequency_Update_timer4_Tick(object sender, EventArgs e)
        {
            int freq = 0;

            if (!Tuning_Knob_Controls.Freq_Queue.E_queue_busy)
            {
                freq = Dequeue_freq();
                if (freq != 0 && Tuning_Knob_Controls.Freq_Queue.E_queue_count < Tuning_Knob_Controls.Freq_Queue.DISPLAY_COUNT)
                {
                    if (VFO_Controls.vfo == VFO_Controls.VFOA)
                    {
                        VFOA_Master_Controls.DisplayFreq = freq;
                    }
                    else
                    {
                        VFOA_Master_Controls.DisplayFreq = freq;
                    }
                    Update_Frequency();
                    Main_Frequency_Update_timer4.Interval = Tuning_Knob_Controls.Freq_Queue.QUEUE_PROCESS_DELAY;
                }
                else
                {
                    if (Tuning_Knob_Controls.Freq_Queue.E_queue_count >= Tuning_Knob_Controls.Freq_Queue.DISPLAY_COUNT)
                    {
                        MonitorTextBoxText(" Main_Frequency_Update_timer4_Tick -> Queue greater than DISPLAY_COUNT: " +
                           Convert.ToString(Tuning_Knob_Controls.Freq_Queue.E_queue_count));
                        while (Tuning_Knob_Controls.Freq_Queue.E_queue_count >= Tuning_Knob_Controls.Freq_Queue.DISPLAY_COUNT)
                        {
                            if (!Tuning_Knob_Controls.Freq_Queue.E_queue_busy)
                            {
                                freq = Dequeue_freq();
                            }
                        }
                        Main_Frequency_Update_timer4.Interval = Tuning_Knob_Controls.Freq_Queue.QUEUE_CHECK_DELAY;
                    }
                }
            }
        }
