        private void Set_mode_display(char mode)
        {
            if (VFO_Controls.vfo == VFO_Controls.VFOA)
            {
                VFOA_Last_Used.Last_used.Current_mode = mode;
                MonitorTextBoxText(" Set_mode_display called. VFOA_Last_Used.Last_used.Current_mode: " + VFOA_Last_Used.Last_used.Current_mode);
            }
            else
            {
                VFOA_Last_Used.Last_used.Current_mode = mode;
                MonitorTextBoxText(" Set_mode_display called. VFOB_Last_Used.Last_used.Current_mode: " + VFOB_Last_Used.Last_used.Current_mode);
            }
            switch (mode)
            {
                case 'U':
                    mainmodebutton2.Text = "USB";
