                    break;
                case 'C':
                    mainmodebutton2.Text = "CW";
                    break;
                case 'E':
                    mainmodebutton2.Text = "ECSS";
                    break;
                case 'D':
                    mainmodebutton2.Text = "DRM";
                    break;
            }
            //Manage_CW_QSK(mode);
            MonitorTextBoxText(" Set_mode_display called -> Finished");
        }
        private void Zero_Frequency_VFOA()
        {
            Int32 remainder = 0;
            byte[] buf = new byte[2];
            MonitorTextBoxText(" Zero_Frequency_VFOA -> Called");
            switch (Master_Controls.FreqDigit)
            {
                case 7: //10 Millions
                    remainder = VFOA_Master_Controls.DisplayFreq % 10000000;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                         + " Remainder: " + Convert.ToString(remainder));
                    break;
                case 6: //Millions
                    remainder = VFOA_Master_Controls.DisplayFreq % 1000000;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                         + " Remainder: " + Convert.ToString(remainder));
                    break;
                case 5:
                    remainder = VFOA_Master_Controls.DisplayFreq % 100000;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                        + " Remainder: " + Convert.ToString(remainder));
                    break;
                case 4:
                    remainder = VFOA_Master_Controls.DisplayFreq % 10000;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                        + " Remainder: " + Convert.ToString(remainder));
                    break;
                case 3:
                    remainder = VFOA_Master_Controls.DisplayFreq % 1000;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                         + " Remainder: " + Convert.ToString(remainder));
                    break;
                case 2:
                    remainder = VFOA_Master_Controls.DisplayFreq % 100;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                        + " Remainder: " + Convert.ToString(remainder));
                    break;
                case 1:
                    remainder = VFOA_Master_Controls.DisplayFreq % 10;
                    MonitorTextBoxText(" Zero_Frequency -> FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit)
                         + " Remainder: " + Convert.ToString(remainder));
                    break;

                default:
                    MonitorTextBoxText(" Zero_Frequency -> default. FreqDigit: " + Convert.ToString(Master_Controls.FreqDigit) +
                        " Remainder: " + Convert.ToString(remainder));
                    break;
            }
            buf[0] = Master_Controls.Extended_Commands.CMD_MFC_SET_ZERO;
            buf[1] = (byte)Master_Controls.FreqDigit;
            VFOA_Master_Controls.DisplayFreq = VFOA_Master_Controls.DisplayFreq - remainder;
            //oCode.SendCommand_MultiByte(txsocket, txtarget,
            //                                 Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);

        }
