        public void Display_Main_Freq_VFOA()
        {
            short power = 0;
            short mode_number = 0;
            Int32 meg10 = 0;
            Int32 meg = 0;
            Int32 hundred_thousand = 0;
            Int32 ten_thousand = 0;
            Int32 thousand = 0;
            Int32 hundred = 0;
            Int32 ten = 0;
            Int32 one = 0;
            //Decompose the frequency into individual digits

            if (Settings.Default.Auto_Zero)
            {
                Zero_Frequency_VFOA();
            }
            meg10 = VFOA_Master_Controls.DisplayFreq / 10000000;
            meg = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000)) / 1000000;
            hundred_thousand = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000) - (meg * 1000000))
                / 100000;
            ten_thousand = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000) - (meg * 1000000) -
                (hundred_thousand * 100000)) / 10000;
            thousand = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000) - (meg * 1000000) -
                (hundred_thousand * 100000) - (ten_thousand * 10000)) / 1000;
            hundred = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000) - (meg * 1000000) -
                (hundred_thousand * 100000) - (ten_thousand * 10000) - (thousand * 1000)) / 100;
            ten = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000) - (meg * 1000000) -
                (hundred_thousand * 100000) - (ten_thousand * 10000) - (thousand * 1000) -
                                                   (hundred * 100)) / 10;
            one = (VFOA_Master_Controls.DisplayFreq - (meg10 * 10000000) - (meg * 1000000) -
                (hundred_thousand * 100000) - (ten_thousand * 10000) - (thousand * 1000) -
                                                   (hundred * 100) - (ten * 10));

            Ones.Text = Convert.ToString(one);
            Tens.Text = Convert.ToString(ten);
            Hundreds.Text = Convert.ToString(hundred);
            Thousands.Text = Convert.ToString(thousand);
            Tenthousands.Text = Convert.ToString(ten_thousand);
            Hundredthousand.Text = Convert.ToString(hundred_thousand);
            Millions.Text = Convert.ToString(meg);
            if (Transceiver_Model_Settings.Fortis_Devices != Transceiver_Model_Settings.FORTIS_GEMINUS)
            {
                if (meg10 == 0)
                {
                    MonitorTextBoxText(" meg10 Position is zero");
                    Tenmillions.Text = " ";
                }
                else
                {
                    Tenmillions.Text = Convert.ToString(meg10);
                }
            }
            else
            {
                MonitorTextBoxText(" Display_Main_Freq_VFOA. GEMINUS MODE. SETTING LF/MF");
                //Set_Label_Color(true, Millions, "F", Color.Red);
                Millions.Text = "F";
                switch (Band_Bank.Geminus_Bank.Band)
                {
                    case Band_Bank.Geminus_Bank.B2200:
                        Tenmillions.Text = "L";
                        break;
                    case Band_Bank.Geminus_Bank.B630:
                        Tenmillions.Text = "M";
                        break;
                    case Band_Bank.Geminus_Bank.BCN:
                        Tenmillions.Text = "B";
                        switch (Band_Bank.Geminus_Bank.Becon_Band)
                        {
                            case 0:
                                Millions.Text = "0";
                                break;
                            case 1:
                                Millions.Text = "1";
                                break;
                            case 2:
                                Millions.Text = "2";
                                break;
                        }
                        break;
                    default:
                        Tenmillions.Text = "G";
                        Millions.Text = "B";
                        break;
                }
                /*if (Band_Bank.Geminus_Bank.Band == Band_Bank.Geminus_Bank.B2200)
                {
                    Tenmillions.Text = "L";
                    //Set_Label_Color(true, Tenmillions, "L", Color.Red);
                }
                else
                {
                    Tenmillions.Text = "M";
                    //Set_Label_Color(true, Tenmillions, "M", Color.Red);
                }*/
            }
            Panadapter_Controls.Frequency = VFOA_Master_Controls.DisplayFreq;
            Panadapter_Controls.Freq_Set_By_Master = true;

            Master_Controls.TX_Inhibited = true;
            if (VFOA_Master_Controls.DisplayFreq >= 135700 && VFOA_Master_Controls.DisplayFreq <= 137800) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 472000 && VFOA_Master_Controls.DisplayFreq <= 479000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 1800000 && VFOA_Master_Controls.DisplayFreq <= 2000000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 3500000 && VFOA_Master_Controls.DisplayFreq <= 4000000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 5330000 && VFOA_Master_Controls.DisplayFreq <= 5404000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 7000000 && VFOA_Master_Controls.DisplayFreq <= 7300000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 10100000 && VFOA_Master_Controls.DisplayFreq <= 10150000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 14000000 && VFOA_Master_Controls.DisplayFreq <= 14350000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 18068000 && VFOA_Master_Controls.DisplayFreq <= 18168000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 21000000 && VFOA_Master_Controls.DisplayFreq <= 21450000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 24890000 && VFOA_Master_Controls.DisplayFreq <= 24990000) Master_Controls.TX_Inhibited = false;
            if (VFOA_Master_Controls.DisplayFreq >= 28000000 && VFOA_Master_Controls.DisplayFreq <= 30000000) Master_Controls.TX_Inhibited = false;
            if (Master_Controls.TX_Inhibited)
            {
                if (!Band_Bank.General_Bank.General_Bank_Selected || !(Band_Bank.Geminus_Bank.Band == Band_Bank.Geminus_Bank.BCN))
                {
                    Out_Of_Band_button.Visible = true;
                    Master_Controls.Out_Of_Band_Toggle = true;
                }
                else
                {
                    Out_Of_Band_button.Visible = false;
                }
                if (Master_Controls.PPT_Mode)
                {
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_TX_ON, 0);
                    Set_Button_Color(false, button1);
                    Master_Controls.PPT_Mode = false;
                    Master_Controls.Transmit_Mode = false;
                    Master_Controls.Two_Tone = false;
                }
                if (Master_Controls.Tuning_Mode)
                {
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                    power = get_previous_power(VFOA_Master_Controls.current_band);
                    mode_number = Convert_mode_char_to_digit(VFOA_Last_Used.Last_used.Current_mode);
                    MonitorTextBoxText(" Tune -> Current Band: " + VFOA_Master_Controls.current_band +
                        " Current Mode Number: " + mode_number);
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                    Set_Button_Color(false, buttTune);
                    Master_Controls.Tuning_Mode = false;
                    Master_Controls.Transmit_Mode = false;
                    Set_Button_Color(false, Tune_vButton2, "TUN");
                }
            }
            else
            {
                if (Master_Controls.Out_Of_Band_Toggle)
                {
                    Out_Of_Band_button.Visible = false;
                    Master_Controls.Out_Of_Band_Toggle = false;
                }
            }
#if FTDI
            Tuning_Knob_Controls.Freq = VFOA_Master_Controls.DisplayFreq;
            Master_Controls.Main_frequency = VFOA_Master_Controls.DisplayFreq;
            Freq_Digits.previous_frequency = VFOA_Master_Controls.DisplayFreq;
#endif
        }
