        private void Manage_Main_Frequency(Int32 n)
        {
            MonitorTextBoxText(" Manage_Main_Frequency -> n: " + Convert.ToString(n));
            if (Transceiver_Model_Settings.Fortis_Devices == Transceiver_Model_Settings.FORTIS_GEMINUS)
            {
                Master_Controls.Mouse_Controls.Silent_Update = true;
            }
            if (VFO_Controls.vfo == VFO_Controls.VFOA)
            {
                switch (Master_Controls.FreqDigit)
                {
                    case 0:
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 1;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 1) VFOA_Master_Controls.DisplayFreq -= 1;
                                break;
                        }

                        break;

                    case 1:
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 10;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 10) VFOA_Master_Controls.DisplayFreq -= 10;
                                break;
                        }

                        break;

                    case 2:
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 100;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 100) VFOA_Master_Controls.DisplayFreq -= 100;
                                break;
                        }
                        break;

                    case 3:
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 1000;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 1000) VFOA_Master_Controls.DisplayFreq -= 1000;
                                break;
                        }
                        break;

                    case 4:
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 10000;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 10000) VFOA_Master_Controls.DisplayFreq -= 10000;
                                break;
                        }
                        break;

                    case 5:
                        Master_Controls.Mouse_Controls.Silent_Update = true;
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 100000;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 100000) VFOA_Master_Controls.DisplayFreq -= 100000;
                                break;
                        }
                        break;

                    case 6:
                        Master_Controls.Mouse_Controls.Silent_Update = true;
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 1000000;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 1000000) VFOA_Master_Controls.DisplayFreq -= 1000000;
                                break;
                        }
                        break;

                    case 7:
                        Master_Controls.Mouse_Controls.Silent_Update = true;
                        switch (n)
                        {
                            case 1:
                                if (VFOA_Master_Controls.DisplayFreq < 40000000) VFOA_Master_Controls.DisplayFreq += 10000000;
                                break;

                            default:
                                if (VFOA_Master_Controls.DisplayFreq >= 10000000) VFOA_Master_Controls.DisplayFreq -= 10000000;
                                break;
                        }
                        break;

                    default:

                        break;
                }
                if (VFOA_Master_Controls.DisplayFreq < 0) return;
                if (VFOA_Master_Controls.DisplayFreq > 40000000) VFOA_Master_Controls.DisplayFreq = 40000000;
                if (!Band_Bank.General_Bank.General_Bank_Selected)
                {
                    Band_Bank.HAM_Last_Used.Freq = VFOA_Master_Controls.DisplayFreq;
                }
                Display_Main_Freq_VFOA();
                Panadapter_Controls.Freq_Set_By_Master = true;
                int freq_plus_rit = VFOA_Master_Controls.DisplayFreq + RIT.Rit_Controls.Offset;
                int MHz = freq_plus_rit / 1000000;
                int KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
                int Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
                ritfreqtextBox1.Text = string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
                //ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
                Panadapter_Controls.Frequency = VFOA_Master_Controls.DisplayFreq;
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Master_Controls.DisplayFreq);
                Set_Last_Used_VFOA(VFOA_Master_Controls.DisplayFreq);
                //VFOA_Last_Used.Last_used.Freq = VFOA_Master_Controls.DisplayFreq;
                Master_Controls.Mouse_Controls.Silent_Update = false;
