                    switch (Band_Bank.Geminus_Bank.Band)
                    {
                        case Band_Bank.Geminus_Bank.B2200:
                            Band_Bank.Geminus_Bank.Last_Used.B2200.Freq = VFOA_Master_Controls.DisplayFreq;
                            break;
                        case Band_Bank.Geminus_Bank.B630:
                            Band_Bank.Geminus_Bank.Last_Used.B630.Freq = VFOA_Master_Controls.DisplayFreq;
                            break;
                        default:
                            Band_Bank.Geminus_Bank.Last_Used.GEN.Freq = VFOA_Master_Controls.DisplayFreq;
                            break;
                    }

                if (VFOA_Master_Controls.current_band == Master_Controls.general_band)
                {
                    VFOA_Last_Used.Last_used.GEN.Freq = VFOA_Master_Controls.DisplayFreq;
                }
            }
            else
            {
                switch (Master_Controls.FreqDigit)
                {
                    case 0:
                        switch (n)
                        {
                            case 1:
                                if (VFOB_Master_Controls.DisplayFreq < 40000000) VFOB_Master_Controls.DisplayFreq += 1;
