                        }

                        break;

                    case 2:
                        switch (n)
                        {
                            case 1:
                                if (VFOB_Master_Controls.DisplayFreq < 40000000) VFOB_Master_Controls.DisplayFreq += 100;
                                break;

                            default:
                                if (VFOB_Master_Controls.DisplayFreq >= 100) VFOB_Master_Controls.DisplayFreq -= 100;
