                                if (VFOB_Master_Controls.DisplayFreq < 40000000) VFOB_Master_Controls.DisplayFreq += 10000;
                                break;

                            default:
                                if (VFOB_Master_Controls.DisplayFreq >= 10000) VFOB_Master_Controls.DisplayFreq -= 10000;
                                break;
                        }
                        break;

                    case 5:
                        Master_Controls.Mouse_Controls.Silent_Update = true;
                        switch (n)
                        {
                            case 1:
                                if (VFOB_Master_Controls.DisplayFreq < 40000000) VFOB_Master_Controls.DisplayFreq += 100000;
                                break;

                            default:
                                if (VFOB_Master_Controls.DisplayFreq >= 100000) VFOB_Master_Controls.DisplayFreq -= 100000;
                                break;
                        }
                        break;

                    case 6:
                        Master_Controls.Mouse_Controls.Silent_Update = true;
                        switch (n)
                        {
                            case 1:
                                if (VFOB_Master_Controls.DisplayFreq < 40000000) VFOB_Master_Controls.DisplayFreq += 1000000;
                                break;

                            default:
                                if (VFOB_Master_Controls.DisplayFreq >= 1000000) VFOB_Master_Controls.DisplayFreq -= 1000000;
