                                if (VFOB_Master_Controls.DisplayFreq < 40000000) VFOB_Master_Controls.DisplayFreq += 10000000;
                                break;

                            default:
                                if (VFOB_Master_Controls.DisplayFreq >= 10000000) VFOB_Master_Controls.DisplayFreq -= 10000000;
                                break;
                        }
                        break;

                    default:

                        break;
                }
                if (VFOB_Master_Controls.DisplayFreq < 0) return;
                if (VFOB_Master_Controls.DisplayFreq > 40000000) VFOB_Master_Controls.DisplayFreq = 40000000;
