        private void Manage_B10_Band_VFOA()
        {
            int MHz;
            int KHz;
            int Hz;

            if (Master_Controls.isLoading == true) return;
            Master_Controls.Auto_Tune.Inhibit = false;
            MonitorTextBoxText(" Manage_10_Band_VFOA called ");
            VFO_Controls.Current_Band_Set.vfo = VFO_Controls.VFOA;
            VFO_Controls.Current_Band_Set.band = 10;
            Set_mode_display(VFOA_Last_Used.Last_used.B10.Mode);
            VFOA_Master_Controls.gen_band_active = false;
            VFOA_Master_Controls.previous_main_band = 10;
            VFOA_Master_Controls.current_band = 10;
            VFO_Controls.Split.RX_band = 10;
            VFO_Controls.Split.RX_freq = VFOA_Last_Used.Last_used.B10.Freq;
            if (!Power_Calibration_Controls.Power_Tab_Active && !Amplifier_Power_Controls.Tab_Active)
            {
                short mode_number = Convert_mode_char_to_digit(VFOA_Last_Used.Last_used.B10.Mode);
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B10.Freq);
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B10.Freq);
                Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B10.Filter_High_Index;
                Filter_control.CW_Filter_Index = VFOA_Last_Used.Last_used.B10.Filter_CW_index;
                Filter_control.Filter_Low_Index = VFOA_Last_Used.Last_used.B10.Filter_Low_Index;
                Filter_control.Filter_TX_High_Index = VFOA_Last_Used.Last_used.B10.TX_HI_Cut_Index;
                Master_Controls.modeswitch = mode_number;
                //Band_button_clicked_get_freq_and_mode();
            }
            VFOA_Master_Controls.DisplayFreq = VFOA_Last_Used.Last_used.B10.Freq;
            Display_Main_Freq_VFOA();
            int freq_plus_rit = VFOA_Last_Used.Last_used.B10.Freq + RIT.Rit_Controls.Offset;
            RIT.Rit_Controls.RIT_Freq = VFOA_Last_Used.Last_used.B10.Freq;
            MHz = freq_plus_rit / 1000000;
            KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
            Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
            ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            Panadapter_Controls.Frequency = VFOA_Master_Controls.DisplayFreq;
            Band_Bank.HAM_Last_Used.Freq = VFOA_Last_Used.Last_used.B10.Freq;
            Band_Bank.HAM_Last_Used.Mode = VFOA_Last_Used.Last_used.B10.Mode;
            Band_Bank.HAM_Last_Used.Filter_CW_index = VFOA_Last_Used.Last_used.B10.Filter_CW_index;
            Band_Bank.HAM_Last_Used.Filter_High_Index = VFOA_Last_Used.Last_used.B10.Filter_High_Index;
            Band_Bank.HAM_Last_Used.Filter_Low_Index = VFOA_Last_Used.Last_used.B10.Filter_Low_Index;
            //Panadapter_Controls.Updated_Frequency = VFOA_Master_Controls.DisplayFreq;
            Panadapter_Controls.Freq_Set_By_Master = true;
#if FTDI
                Relay_Board_Controls.sentBytes[0] = (byte)(Relay_Board_Controls.sentBytes[0] = 2);
#endif
            Master_Controls.Auto_Tune.Band_Change_Toggle = true;
            MonitorTextBoxText(" Manage_10_Band_VFOA -> " + "Current Mode: " + VFOA_Last_Used.Last_used.B10.Mode);
            MonitorTextBoxText(" Manage_10_Band_VFOA Finished ");
        }
