        private void Set_Freq_Digit_Pointer()
        {
            Freq_Pointer_0.Text = "";
            Freq_Pointer_1.Text = "";
            Freq_Pointer_2.Text = "";
            Freq_Pointer_3.Text = "";
            Freq_Pointer_4.Text = "";
            Freq_Pointer_5.Text = "";
            Freq_Pointer_6.Text = "";
            Freq_Pointer_7.Text = "";

            MonitorTextBoxText(" Select_Freq_Digit_Pointer: " + Convert.ToString(Master_Controls.FreqDigit));
            switch (Master_Controls.FreqDigit)
            {
                case 0:
                    Freq_Pointer_0.Text = "^";
                    Step_button8.Text = "1Hz";
                    break;
                case 1:
                    Freq_Pointer_1.Text = "^";
                    Step_button8.Text = "10Hz";
                    break;
                case 2:
                    Freq_Pointer_2.Text = "^";
                    Step_button8.Text = "100Hz";
                    break;
                case 3:
                    Freq_Pointer_3.Text = "^";
                    Step_button8.Text = "1KHz";
                    break;
                case 4:
                    Freq_Pointer_4.Text = "^";
                    Step_button8.Text = "10KHz";
                    break;
                case 5:
                    Freq_Pointer_5.Text = "^";
                    Step_button8.Text = "100KHz";
                    break;
                case 6:
                    Freq_Pointer_6.Text = "^";
                    break;
                case 7:
                    Freq_Pointer_7.Text = "^";
                    break;
            }
        }
        private void Set_Freq_Digit_By_Mouse(int digit)
        {
            Master_Controls.Step_Index = digit;
            switch (Master_Controls.Step_Index)
            {
                case 5:
                    Step_button8.Text = "1Hz";
                    break;
                case 4:
                    Step_button8.Text = "10Hz";
                    break;
                case 3:
                    Step_button8.Text = "100Hz";
                    break;
                case 2:
                    Step_button8.Text = "1KHz";
                    break;
                case 1:
                    Step_button8.Text = "10KHz";
                    break;
                case 0:
                    Step_button8.Text = "100KHz";
                    break;
            }
            VFOA_Master_Controls.Freq_Tune_Index = (short)Master_Controls.Step_Index;
            oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_STEP_VALUE, VFOA_Master_Controls.Freq_Tune_Index);
            Master_Controls.FreqDigit = (short)Swap_tuning_step(VFOA_Master_Controls.Freq_Tune_Index);
            Set_Freq_Digit_Pointer();
        }
        private void Set_Default_Digit()
        {
            switch (VFOA_Master_Controls.Freq_Tune_Index)
            {
                case 0:
                    Master_Controls.FreqDigit = 5;
                    break;

                case 1:
                    Master_Controls.FreqDigit = 4;
                    break;

                case 2:
                    Master_Controls.FreqDigit = 3;
                    break;

                case 3:
                    Master_Controls.FreqDigit = 2;
                    break;

                case 4:
                    Master_Controls.FreqDigit = 1;
                    break;

                case 5:
                    Master_Controls.FreqDigit = 0;
                    break;
            }
            MonitorTextBoxText(" Set_Default_Digit: " + Convert.ToString(VFOA_Master_Controls.Freq_Tune_Index));
        }
