        #region Power_Management
        private void Main_Power_hScrollBar1_Scroll(object sender, ScrollEventArgs e)
        {
            int value = 0;
            value = Main_Power_hScrollBar1.Value;
            if (Power_Controls.Main_Tab_Power == value) return;
            Power_Controls.Main_Tab_Power = (short)value;
            switch (Master_Controls.modeswitch)
            {
                case Power_Controls.Mode.USB_mode:
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_MAIN_POWER, (short)value);
                    break;
                case Power_Controls.Mode.LSB_mode:
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_MAIN_POWER, (short)value);
                    break;
                case Power_Controls.Mode.CW_mode:
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_CW_POWER, (short)value);
                    break;
            }
        }
        private void Main_Power_hScrollBar1_Enter(object sender, EventArgs e)
        {
            Master_Controls.Mouse_Controls.control_window = Master_Controls.Mouse_Controls.MAIN_POWER_SLIDER;
        }
        private void Main_Power_hScrollBar1_Leave(object send, EventArgs e)
        {
            Master_Controls.Mouse_Controls.control_window = Master_Controls.Mouse_Controls.MAIN_FREQUENCY;
        }
        private void Main_Power_MouseWheel(Int32 e)
        {
            Int32 n = e;

            Power_Controls.Main_Tab_Power += (short)n;
            if (Power_Controls.Main_Tab_Power > 100) { Power_Controls.Main_Tab_Power = 100; }
            if (Power_Controls.Main_Tab_Power < 0) { Power_Controls.Main_Tab_Power = 0; }
            Main_Power_hScrollBar1.Value = Power_Controls.Main_Tab_Power;
            switch (Master_Controls.modeswitch)
            {
                case Power_Controls.Mode.LSB_mode:
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_MAIN_POWER, (short)Power_Controls.Main_Tab_Power);
                    break;
                case Power_Controls.Mode.USB_mode:
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_MAIN_POWER, (short)Power_Controls.Main_Tab_Power);
                    break;
                case Power_Controls.Mode.CW_mode:
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_CW_POWER, (short)Power_Controls.Main_Tab_Power);
                    break;
            }
        }
        #endregion Power_Management

        #region Volume_Management
        private void Manage_CW_Phones()
        {
            if (VFOA_Last_Used.Last_used.Current_mode == 'C')
            {
                if (Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
                {
                    Transceiver_Model_Settings.Volume_Settings.Previous_Mode = 1;
                    if (CW_Parameters.Phones == 1)
                    {
                        Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital = true;
                        Audio_Digital_button3_Click(null, null);
                    }
                }
            }
            else
            {
                if (Transceiver_Model_Settings.Volume_Settings.Previous_Mode == 1)
                {
                    Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital = false;
                    Transceiver_Model_Settings.Volume_Settings.Previous_Mode = 0;
                    Audio_Digital_button3_Click(null, null);
                }
            }
        }
