        public void Volume_textbox2_MouseWheel(Int32 e)
        {
            Int32 n = e;

            if (Master_Controls.isLoading) return;
            MonitorTextBoxText(" Volume_textbox2_MouseWheel -> Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume: " +
                                                   Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume));
            Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume += n;
            if (Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume > 100) 
            { 
                Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume = 100; 
            }
            if (Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume < 0) 
            { 
                Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume = 0; 
            }

            if (!Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
            {
                Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume = 
                    Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume;
            }
            else
            {
                Transceiver_Model_Settings.Volume_Settings.Speaker_Volume = 
                    Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume;
            }

            Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume;
            Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
            if (Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
            {
                Set_Button_Color(false, Volume_Mute_button2, "VOLUME");
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                Transceiver_Model_Settings.Volume_Settings.Speaker_MutED = false;
                Transceiver_Model_Settings.Volume_Settings.Speaker_Mute = 0;
            }
            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME,
                (short)Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
        }
        private void Volume_Mute_button2_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading == true) return;
            if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
            {
                MonitorTextBoxText(" Volume_Mute_button2 -> Called -> Set Mute ON");
                Set_Button_Color(true, Volume_Mute_button2, "MUTED");
                MonitorTextBoxText(" Volume_Mute_button2 -> CMD_SET_SPEAKER_MUTE: 1");
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 1);
                Transceiver_Model_Settings.Volume_Settings.Speaker_Mute = 1;
                Transceiver_Model_Settings.Volume_Settings.Speaker_MutED = true;
                //Transceiver_Model_Settings.RPi_Needs_Updated = true;
            }
            else
            {
                MonitorTextBoxText(" Volume_Mute_button2 -> Called -> Set Mute OFF");
                Set_Button_Color(false, Volume_Mute_button2, "VOLUME");
                MonitorTextBoxText(" Volume_Mute_button2 -> CMD_SET_SPEAKER_MUTE: 0");
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_VOLUME_ATTN,
                    (short)Transceiver_Model_Settings.Volume_Settings.Volume_ATTN_Index);
                Transceiver_Model_Settings.Volume_Settings.Speaker_Mute = 0;
                Transceiver_Model_Settings.Volume_Settings.Speaker_MutED = false;
                //Transceiver_Model_Settings.RPi_Needs_Updated = true;
            }
        }
