        private void Volume_textBox2_Mouse_Click(object sender, MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                Transceiver_Model_Settings.Volume_Settings.Temp += e.Clicks;
            }
            else
            {
                Transceiver_Model_Settings.Volume_Settings.Temp -= e.Clicks;
            }
            MonitorTextBoxText(" Volume_textBox2_Mouse_Click -> Temp value: " + 
                Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Temp));
        }
        private void Volume_hScrollBar1_Scroll(object sender, ScrollEventArgs e)
        {
            int value;
            if (Master_Controls.isLoading == true) return;
            value = Volume_hScrollBar1.Value;
            if (Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume == value) return;

#if FTDI
            Tuning_Knob_Controls.Volume_Function.Volume_Slider_Active = true;
#endif
            if (!Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
            {
                Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume = value;
            }
            else
            {
                Transceiver_Model_Settings.Volume_Settings.Speaker_Volume = value;
            }
            Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume = value;
            //Transceiver_Model_Settings.RPi_Needs_Updated = true;

#if FTDI
            Tuning_Knob_Controls.Volume_Function.Volume = Volume_Controls.Speaker_Volume;
#endif
            Volume_textBox2.Text = Convert.ToString(value);

            if (Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
            {
                Set_Button_Color(false, Volume_Mute_button2, "VOLUME");
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                Transceiver_Model_Settings.Volume_Settings.Speaker_MutED = false;
                Transceiver_Model_Settings.Volume_Settings.Speaker_Mute = 0;
            }
            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME,
                (short)Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume);
#if FTDI
            Tuning_Knob_Controls.Volume_Function.Volume_Slider_Active = false;
#endif
        }
