        public void Microphone_textBox2_MouseWheel(Int32 e)
        {
            Int32 n = e;

            if (Master_Controls.isLoading == true) return;
            Master_Controls.Mouse_Controls.Allow_Frequency_Updates = false;
            Volume_Controls.Mic_Volume += (short)n;
            if (Volume_Controls.Mic_Volume > 100) { Volume_Controls.Mic_Volume = 100; }
            if (Volume_Controls.Mic_Volume < 0) { Volume_Controls.Mic_Volume = 0; }
            if (Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
            {
                Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume = Volume_Controls.Mic_Volume;
                MonitorTextBoxText(" MicVolume_hScrollBar1 -> Digital: " +
                    Convert.ToString(Volume_Controls.Mic_Volume));
            }
            else
            {
                Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume = Volume_Controls.Mic_Volume;
                MonitorTextBoxText(" MicVolume_hScrollBar1 -> Voice: " +
                    Convert.ToString(Volume_Controls.Mic_Volume));
            }
            Microphone_textBox2.Text = Convert.ToString(Volume_Controls.Mic_Volume);
            if (Volume_Controls.Mic_MutED)
            {
                Set_Button_Color(false, TX_Mute_button2, "MIC GAIN");
                Volume_Controls.Mic_MutED = false;
                Transceiver_Model_Settings.Volume_Settings.Mic_Mute = 0;
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_MIC_MUTE, 0);
            }
            MicVolume_hScrollBar1.Value = Volume_Controls.Mic_Volume;
            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_MIC_VOLUME, Volume_Controls.Mic_Volume);
            Master_Controls.Mouse_Controls.Allow_Frequency_Updates = true;
