        #region RIT_Management
        private void Set_Rit(int freq)
        {
            if (RIT.Rit_Controls.Update_RIT)
            {
                int freq_plus_rit = freq + RIT.Rit_Controls.Offset;
                RIT.Rit_Controls.RIT_Freq = freq;
                int MHz = freq_plus_rit / 1000000;
                int KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
                int Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
                ritfreqtextBox1.Text = string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
                //ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            }
        }
        private void RIT_Buttons(short up_down)
        {
            if (Master_Controls.isLoading == true) return;
            int MHz;
            int KHz;
            int Hz;
            int freq_plus_rit;

            if (Master_Controls.isLoading) return;
            int ritValue = RIT.Rit_Controls.RIT_Scroll_Bar_Value;
            ritValue += up_down;
#if FTDI
            Tuning_Knob_Controls.RIT_OFFSET_Function.RIT_Slider_Active = true;
#endif
            if (ritValue > ritScroll.Maximum) { ritValue = ritScroll.Maximum; }
            if (ritValue < ritScroll.Minimum) { ritValue = ritScroll.Minimum; }
            ritScroll.Value = ritValue;
            RIT.Rit_Controls.RIT_Scroll_Bar_Value = ritValue;
            RIT.Rit_Controls.RIT_Freq = VFOA_Master_Controls.DisplayFreq;
            RIT.Rit_Controls.Offset = ritValue;
            freq_plus_rit = RIT.Rit_Controls.RIT_Freq + RIT.Rit_Controls.Offset;
            MHz = freq_plus_rit / 1000000;
            KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
            Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
            //RIT.Rit_Controls.Rit_Freq = freq_plus_rit;
            ritfreqtextBox1.Text = string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            //ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." +
            //    (string.Format("{0:000}", Hz));
            oCode.SendCommand32(txsocket, txtarget, RIT.Rit_Controls.CMD_SET_RIT_FREQ, RIT.Rit_Controls.Offset);
#if FTDI
            Tuning_Knob_Controls.RIT_OFFSET_Function.RIT_Slider_Active = false;
#endif
        }
