        private void Manage_AMP_Power(bool on_off, byte caller)
        {
            
            switch (on_off)
            {
                case true:  //AMP is attached
                    switch (caller)
                    {
                        case Master_Controls.PA_BUTTON:
                            Set_Button_Color(true, QRP_Button);
                            Master_Controls.QRP_Button_ON = true;
                            break;
                        case Master_Controls.QRP_BUTTON:
                            Set_Button_Color(true,PA_button);
                            Master_Controls.PA_Button_ON = true;
                            break;
                    }
                    IQBD_TX_groupBox.Enabled = false;
                    AMP_groupBox3.Enabled = true;
                    Master_Controls.QRP_Mode = false;

                    oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 1);
                    Tune_Power_label37.Text = Convert.ToString(Power_Controls.TUNE_Power);
                    Tune_Power_hScrollBar1.Value = Power_Controls.TUNE_Power;
                    break;

                case false: //AMP is NOT attached
                    switch (caller)
                    {
                        case Master_Controls.PA_BUTTON:
                            Set_Button_Color(false, QRP_Button);
                            Master_Controls.QRP_Button_ON = false;
                            break;
                        case Master_Controls.QRP_BUTTON:
                            Set_Button_Color(false, PA_button);
                            Master_Controls.PA_Button_ON = false;
                            break;
                    }
                    IQBD_TX_groupBox.Enabled = true;
                    AMP_groupBox3.Enabled = false;
                    Master_Controls.QRP_Mode = true;

                    oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                    Tune_Power_label37.Text = Convert.ToString(Transceiver_Model_Settings.QRP_Tune_Power);
                    Tune_Power_hScrollBar1.Value = Transceiver_Model_Settings.QRP_Tune_Power;
                    break;
            }
        }
