        public short Set_band(Int32 freq)
        {
            short band = 0;
            if (freq >= 135700 && freq <= 137800) band = 2200;
            if (freq >= 472000 && freq <= 479000) band = 630;
            if (freq >= 1800000 && freq <= 2000000) band = 160;
            if (freq >= 3500000 && freq <= 4000000) band = 80;
            if (freq >= 5330500 && freq <= 5403500) band = 60;
            if (freq >= 7000000 && freq <= 7300000) band = 40;
            if (freq >= 10100000 && freq <= 10150000) band = 30;
            if (freq >= 14000000 && freq <= 14350000) band = 20;
            if (freq >= 18068000 && freq <= 18168000) band = 17;
            if (freq >= 21000000 && freq <= 21450000) band = 15;
            if (freq >= 24890000 && freq <= 24990000) band = 12;
            if (freq >= 28000000 && freq <= 30000000) band = 10;
            return band;
        }
        private void Set_main_mode_display(char mode)
        {
            MonitorTextBoxText(" set_main_mode_display Entered ");
            switch (mode)
            {
                case 'A':
                    mainmodebutton2.Text = "AM";
                    Master_Controls.modeswitch = Power_Controls.Mode.AM_mode;
                    break;
                case 'L':
                    mainmodebutton2.Text = "LSB";
                    Master_Controls.modeswitch = Power_Controls.Mode.LSB_mode;
                    break;
                case 'U':
                    mainmodebutton2.Text = "USB";
                    Master_Controls.modeswitch = Power_Controls.Mode.USB_mode;
                    break;
                case 'C':
                    mainmodebutton2.Text = "CW";
                    Master_Controls.modeswitch = Power_Controls.Mode.CW_mode;
                    break;

            }
            VFOA_Last_Used.Last_used.Current_mode = mode;
            MonitorTextBoxText(" set_main_mode_display -> New Mode: " + mode + ", Current_band: " + VFOA_Master_Controls.current_band);
            switch (VFOA_Master_Controls.current_band)
            {
                case 160:
                    VFOA_Last_Used.Last_used.B160.Mode = mode;
                    if (mode == 'C')
                    {

                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B160.Filter_CW_index;
                    }
                    else
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B160.Filter_High_Index;
                    }
                    break;
                case 80:
                    VFOA_Last_Used.Last_used.B80.Mode = mode;
                    if (mode == 'C')
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B80.Filter_CW_index;
                    }
                    else
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B80.Filter_High_Index;
                    }
                    break;
                case 60:
                    VFOA_Last_Used.Last_used.B60.Mode = mode;
