                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B40.Filter_CW_index;
                        MonitorTextBoxText(" set_main_mode_display -> Band 40 -> New Mode: " +
                            mode + ",CW Index: " + VFOA_Last_Used.Last_used.B40.Filter_CW_index);
                    }
                    else
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B40.Filter_High_Index;
                        MonitorTextBoxText(" set_main_mode_display -> Band 40 -> New Mode: " +
                            mode + ",High Cut Index: " +
                            VFOA_Last_Used.Last_used.B40.Filter_High_Index);
                    }
                    break;
                case 30:
