                    if (mode == 'C')
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B30.Filter_CW_index;
                    }
                    else
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B30.Filter_High_Index;
                    }
                    break;
                case 20:
