                    else
                    {
                        Filter_control.Filter_High_Index = VFOA_Last_Used.Last_used.B10.Filter_High_Index;
                    }
                    break;
                default:
                    VFOA_Last_Used.Last_used.GEN.Mode = mode;
                    break;
            }
            MonitorTextBoxText(" set_main_mode_display finished ");
        }
