        private short Convert_mode_char_to_digit(char mode)
        {
            short mode_number;
            mode_number = 0;
            switch (mode)
            {
                case 'A':
                    mainmodebutton2.Text = "AM";
                    mode_number = 0;
                    break;

                case 'L':
                    mainmodebutton2.Text = "LSB";
                    mode_number = 1;
                    break;

                case 'U':
                    mainmodebutton2.Text = "USB";
                    mode_number = 2;
                    break;

                case 'C':
                    mainmodebutton2.Text = "CW";
                    mode_number = 3;
                    break;

                case 'F':
                    mainmodebutton2.Text = "FM";
                    mode_number = 4;
                    break;

                case 'E':
                    mainmodebutton2.Text = "ECSS";
                    mode_number = 5;
                    break;

                case 'D':
                    mainmodebutton2.Text = "DRM";
                    mode_number = 6;
                    break;
            }
            return mode_number;
        }
