            {
                if (Amplifier_Power_Controls.Bias_On == false)
                {
                    Amplifier_Power_Controls.Bias_On = true;
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_TUNE_POWER, 0);
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, Power_Controls.Mode.TUNE_mode);
                    oCode.SendCommand(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_BIAS, 1);
                    Set_Button_Color(true, Solidus_Bias_button8);
                    Master_Controls.Tuning_Mode = false;
                    Master_Controls.Transmit_Mode = false;
                    IQBD_TX_groupBox.Enabled = false;
                    Calibration_Band_button8.Enabled = false;
                }
                else
                {
                    Amplifier_Power_Controls.Bias_On = false;
                    oCode.SendCommand(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_BIAS, 0);
                    oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_TUNE_POWER,
