                    Set_Button_Color(false, Solidus_Bias_button8);
                    IQBD_TX_groupBox.Enabled = true;
                    Calibration_Band_button8.Enabled = true;
                }
            }
            else
            {
                _ = MessageBox.Show("Select Any Band", "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
