        private void Audio_Digital_button3_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            if (Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
            {
                Set_Button_Color(false, Volume_Mute_button2, "VOLUME");
                Transceiver_Model_Settings.Volume_Settings.Speaker_MutED = false;
            }
            if (!Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
            {
                Set_Button_Color(false, Audio_Digital_button3, "D");
                Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital = true;
                Transceiver_Model_Settings.Volume_Settings.Mic_Mode = 1;
                Set_Button_Color(false, Compression_button2);
                Set_Button_Color(false, Compression_button4);
                Compression_button4.Enabled = false;
                Compression_button2.Enabled = false;
                Mic_Pre_Gain_button8.Enabled = false;
                Mic_Digital_Pre_Gain_button.Enabled = true;
                Volume_Attn_button8.Enabled = false;
                Digital_Volume_Attn_button5.Enabled = true;
                oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_CONFIGURATION,
                    Master_Controls.Server_Configuration_Commands.DIGITAL_AUDIO);
                MicVolume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume;
                Microphone_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_MIC_VOLUME,
                                                            (short)Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_COMPRESSION_STATE, 0);
                //Set the speaker volume
                Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Speaker_Volume;
                Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Speaker_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME,
                                                    (short)Transceiver_Model_Settings.Volume_Settings.Speaker_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_VOLUME_ATTN,
                                                            (short)Transceiver_Model_Settings.Volume_Settings.Digital_Volume_ATTN_index);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_DIGITAL_MIC_GAIN,
                                                                    (short)Transceiver_Model_Settings.Volume_Settings.Mic_Digital_Pre_Gain);
            }
            else
            {
                Set_Button_Color(true, Audio_Digital_button3, "P");
                Compression_button4.Enabled = true;
                Compression_button2.Enabled = true;
                Mic_Pre_Gain_button8.Enabled = true;
                Mic_Digital_Pre_Gain_button.Enabled = false;
                Volume_Attn_button8.Enabled = true;
                Digital_Volume_Attn_button5.Enabled = false;
                Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital = false;
                Transceiver_Model_Settings.Volume_Settings.Mic_Mode = 0;
                if (Volume_Controls.Compression_State == 1)
                {
                    Set_Button_Color(true, Compression_button2);
                    Set_Button_Color(true, Compression_button4);
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_COMPRESSION_STATE, 1);
                }
                oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_CONFIGURATION,
                    Master_Controls.Server_Configuration_Commands.OPERATOR_AUDIO);
                MicVolume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume;
                Microphone_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_MIC_VOLUME,
                                                            (short)Transceiver_Model_Settings.Volume_Settings.Mic_Voice_Volume);
                //Set the speaker volume
                Volume_hScrollBar1.Value = Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume;
                Volume_textBox2.Text = Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_VOLUME,
                                                    (short)Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_VOLUME_ATTN,
                                                        (short)(short)Transceiver_Model_Settings.Volume_Settings.Volume_ATTN_Index);
                oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_MIC_GAIN,
                                                                    (short)Transceiver_Model_Settings.Volume_Settings.Mic_Pre_Gain);
            }
            MonitorTextBoxText(" Audio_Digital_button3: " + Convert.ToString(Transceiver_Model_Settings.Volume_Settings.Mic_Mode));
        }
