        private string Favs_Get_File_Name(int band)
        {
            string name = "TEST";
            switch (band)
            {
                case 0:
                    name = "b10_favs.ini";
                    break;
                case 1:
                    name = "b12_favs.ini";
                    break;
                case 2:
                    name = "b15_favs.ini";
                    break;
                case 3:
                    name = "b17_favs.ini";
                    break;
                case 4:
                    name = "b20_favs.ini";
                    break;
                case 5:
                    name = "b30_favs.ini";
                    break;
                case 6:
                    name = "b40_favs.ini";
                    break;
                case 7:
                    name = "b60_favs.ini";
                    break;
                case 8:
                    name = "b80_favs.ini";
                    break;
                case 9:
                    name = "b160_favs.ini";
                    break;
            }
            return name;
        }
        private char Convert_Favs_Mode(string favs_mode)
        {
            char mode = 'N';

            if (favs_mode == "USB")
            {
                mode = 'U';
            }
            if (favs_mode == "LSB")
            {
                mode = 'L';
            }
            if (favs_mode == "AM")
            {
                mode = 'A';
            }
            if (favs_mode == "CW")
            {
                mode = 'C';
            }
            return mode;
        }
