        private int Get_Favs_Record_Index(int band)
        {
            int count = 0;
            switch (band)
            {
                case 10:
                    count = Favorites_Controls.B10_Count;
                    break;

                case 12:
                    count = Favorites_Controls.B12_Count;
                    break;

                case 15:
                    count = Favorites_Controls.B15_Count;
                    break;

                case 17:
                    count = Favorites_Controls.B17_Count;
                    break;

                case 20:
                    count = Favorites_Controls.B20_Count;
                    break;

                case 30:
                    count = Favorites_Controls.B30_Count;
                    break;

                case 40:
                    count = Favorites_Controls.B40_Count;
                    break;

                case 60:
                    count = Favorites_Controls.B60_Count;
                    break;

                case 80:
                    count = Favorites_Controls.B80_Count;
                    break;

                case 160:
                    count = Favorites_Controls.B160_Count;
                    break;
            }
            if (count != 0)
            {
                Favorites_Controls.Index_Count++;
                if (Favorites_Controls.Index_Count >= count)
                {
                    Favorites_Controls.Index_Count = 0;
                }
            }
            return Favorites_Controls.Index_Count;
        }
        public void Set_Fav_by_MFC_VFOA()
        {
            string fav_freq;
            string fav_mode;
            string fav_name;
            Int32 frequency;
            char mode;
            int index = 0;

            MonitorTextBoxText(" Set_Fav_by_MFC_VFOA. CALLED");
            index = Get_Favs_Record_Index(VFOA_Master_Controls.current_band);
            //Favorites_Controls.Favs_Records.Fav_Record[0].name = "me";
            switch (VFOA_Master_Controls.current_band)
            {
                case 10:
                    fav_freq = Favorites_Controls.Favs_Records.B10[index].freq;
                    fav_mode = Favorites_Controls.Favs_Records.B10[index].mode;
                    fav_name = Favorites_Controls.Favs_Records.B10[index].name;
                    frequency = Convert.ToInt32(fav_freq);

                    VFOA_Last_Used.Last_used.B10.Freq = frequency;
                    mode = Convert_Favs_Mode(fav_mode);
                    VFOA_Last_Used.Last_used.B10.Mode = mode;
                    VFOA_Master_Controls.previous_main_band = 0;
                    // main10radioButton1.Checked = true;
                    //main10radioButton1_CheckedChanged(null, null);

                    Filter_control.Filter_High_Index = (short)Favorites_Controls.Favs_Records.B10[index].hi_cut;
                    VFOA_Last_Used.Last_used.B10.Filter_High_Index = (short)Favorites_Controls.Favs_Records.B10[index].hi_cut;

                    Filter_control.CW_Filter_Index = (short)Favorites_Controls.Favs_Records.B10[index].cw_bw;
                    Filter_control.CW_Bw = (short)Favorites_Controls.Favs_Records.B10[index].cw_bw;
                    VFOA_Last_Used.Last_used.B10.Filter_CW_index = (short)Favorites_Controls.Favs_Records.B10[index].cw_bw;
                    VFOA_Last_Used.Last_used.B10.TX_HI_Cut_Index = (short)Favorites_Controls.Favs_Records.B10[index].tx_hi_cut;

                    VFOA_Master_Controls.DisplayFreq = frequency;
                    break;
                default:
                    break;
            }
               
            Display_Main_Freq_VFOA();
            MonitorTextBoxText(" Set_Fav_by_MFC_VFOA - > FINISHED");
        }
