        public int Load_Favorites(int band_number)
        {
            String path, line;
            System.IO.StreamReader file;
            String[] arr = new string[3];
            String temp_string;
            int param_pos;
            int end_pos;
            int record_count = 0;
            string file_name = "TEST";
            int record = 0;

            file_name = Favs_Get_File_Name(band_number);
            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
#if RPI
            path += "/mscc-GEMINUS/" + file_name;
#else
            path += "\\multus-sdr-client\\" + Band;
#endif
            MonitorTextBoxText(" Load_Favorites. File Name: " + path + " band_number: " + Convert.ToString(band_number));
            try
            {
                file = new System.IO.StreamReader(File.OpenRead(path));
            }
            catch (IOException e)
            {
                string er = e.Message;
                DialogResult ret = MessageBox.Show("IO Exception opening: " + file_name + "\r\n Error: "
                    + er + "\r\nMake note of the error and contact Multus SDR,LLC.",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return 0;
            }
            while ((line = file.ReadLine()) != null)
            {
                if (line.Length != 0)
                {
                    record_count++;
                    param_pos = line.IndexOf("NAME");                       // get the position of the NAME parameter
                    temp_string = line.Substring((param_pos + 5), (line.Length - param_pos - 5));   // parse everything between the end of NAME= and the end of the line.
                    end_pos = temp_string.IndexOf(","); //temp string will start with the NAME parameter value. Find the trailing comma
                    arr[0] = temp_string.Substring(0, end_pos);   // temp string will start with the NAME parameter value. 

                    param_pos = line.IndexOf("FREQ");                       // get the position of the FREQ parameter
                    temp_string = line.Substring((param_pos + 5), (line.Length - param_pos - 5));   // parse everything between the end of FREQ= and the end of the line.
                    end_pos = temp_string.IndexOf(","); //temp string will start with the FREQ parameter value. Find the trailing comma
                    arr[1] = temp_string.Substring(0, end_pos);   // temp string will start with the FREQ parameter value. 

                    param_pos = line.IndexOf("MODE");  // get the position of the MODE parameter
                    temp_string = line.Substring((param_pos + 5), (line.Length - param_pos - 5));
                    end_pos = temp_string.IndexOf(","); //temp string will start with the MODE parameter value. Find the trailing comma
                    arr[2] = temp_string.Substring(0, end_pos);

                    MonitorTextBoxText(" Load_Favorites(2). File Name: " + path + " band_number: " + Convert.ToString(band_number));
                    /*switch (band_number)
                    {
                        case 0:
                            B10_Favs_grid.Rows.Add(arr);
                            break;
                        case 1:
                            B12_Favs_grid.Rows.Add(arr);
                            break;
                        case 2:
                            B15_Favs_grid.Rows.Add(arr);
                            break;
                        case 3:
                            B17_Favs_grid.Rows.Add(arr);
                            break;
                        case 4:
                            B20_Favs_grid.Rows.Add(arr);
                            break;
                        case 5:
                            B30_Favs_grid.Rows.Add(arr);
                            break;
                        case 6:
                            B40_Favs_grid.Rows.Add(arr);
                            break;
                        case 7:
                            B60_Favs_grid.Rows.Add(arr);
                            break;
                        case 8:
                            B80_Favs_grid.Rows.Add(arr);
                            break;
                        case 9:
                            B160_Favs_grid.Rows.Add(arr);
                            break;
                    }*/
                }
                record++;
            }
            file.Close();
            MonitorTextBoxText(" Load_Favorites. File Name: " + path + " band_number: " + Convert.ToString(band_number) + " " +
                "record count:" + Convert.ToString(record_count));
            return record_count;
        }
        public bool Load_Favorites_Parameters(int band_number, int record_count)
        {
            String path, line;
            System.IO.StreamReader file;
            String[] arr = new string[7];
            String temp_string;
            int param_pos;
            int end_pos;
            String param;
            int record = 0;
            String file_name = "TEST";

            file_name = Favs_Get_File_Name(band_number);
            MonitorTextBoxText(" Load_Favorites_Parameters Called. Band: " + file_name + ", band_number: " +
                                                     Convert.ToString(band_number) + ", record_count: " + Convert.ToString(record_count));
            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
#if RPI
            path += "/mscc-GEMINUS/" + file_name;
#else
            path += "\\multus-sdr-client\\" + Band;
#endif
            try
            {
                file = new System.IO.StreamReader(File.OpenRead(path));
            }
            catch (IOException e)
            {
                string er = e.Message;
                DialogResult ret = MessageBox.Show("IO Exception opening: " + file_name + "\r\n Error: " + er +
                    "\r\nMake note of the error and contact Multus SDR,LLC.",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return false;
            }
            while ((line = file.ReadLine()) != null)
            {
                if (line.Length != 0)
                {
                    param_pos = line.IndexOf("NAME");                       // get the position of the NAME parameter
                    temp_string = line.Substring((param_pos + 5), (line.Length - param_pos - 5));   // parse everything between the end of NAME= and the end of the line.
                    end_pos = temp_string.IndexOf(","); //temp string will start with the NAME parameter value. Find the trailing comma
                    arr[0] = temp_string.Substring(0, end_pos);   // temp string will start with the NAME parameter value. 

                    param_pos = line.IndexOf("FREQ");                       // get the position of the FREQ parameter
                    temp_string = line.Substring((param_pos + 5), (line.Length - param_pos - 5));   // parse everything between the end of FREQ= and the end of the line.
                    end_pos = temp_string.IndexOf(","); //temp string will start with the FREQ parameter value. Find the trailing comma
                    arr[1] = temp_string.Substring(0, end_pos);   // temp string will start with the FREQ parameter value. 

                    param_pos = line.IndexOf("MODE");  // get the position of the MODE parameter
                    param = "MODE=";
                    param_pos = param_pos + param.Length;
                    temp_string = line.Substring(param_pos, line.Length - param_pos);
                    end_pos = temp_string.IndexOf(","); //temp string will start with the MODE parameter value. Find the trailing comma
                    arr[2] = temp_string.Substring(0, end_pos);

                    param_pos = line.IndexOf("HI_CUT");  // get the position of the HI_CUT parameter
                    param = "HI_CUT=";
                    param_pos = param_pos + param.Length;
                    temp_string = line.Substring(param_pos, line.Length - param_pos);
                    end_pos = temp_string.IndexOf(","); //temp string will start with the HI_CUT parameter value. Find the trailing comma
                    arr[3] = temp_string.Substring(0, end_pos);

                    param_pos = line.IndexOf("CW_BW");  // get the position of the CW_BW parameter
                    param = "CW_BW=";
                    param_pos = param_pos + param.Length;
                    temp_string = line.Substring(param_pos, line.Length - param_pos);
                    end_pos = temp_string.IndexOf(","); //temp string will start with the CW_BW parameter value. Find the trailing comma
                    arr[4] = temp_string.Substring(0, end_pos);

                    param_pos = line.IndexOf("TX_HI_CUT");  // get the position of the TX_HI_CUT parameter
                    param = "TX_HI_CUT=";
                    param_pos = param_pos + param.Length;
                    temp_string = line.Substring(param_pos, line.Length - param_pos);
                    end_pos = temp_string.IndexOf(","); //temp string will start with the TX_HI_CUT parameter value. Find the trailing comma
                    arr[5] = temp_string.Substring(0, end_pos);

                    try
                    {
                        switch (band_number)
                        {
                            case 0:
                                Favorites_Controls.Favs_Records.B10[record].name = arr[0];
                                Favorites_Controls.Favs_Records.B10[record].freq = arr[1];
                                Favorites_Controls.Favs_Records.B10[record].mode = arr[2];
                                Favorites_Controls.Favs_Records.B10[record].hi_cut = Convert.ToInt32(arr[3]);
                                Favorites_Controls.Favs_Records.B10[record].cw_bw = Convert.ToInt32(arr[4]);
                                Favorites_Controls.Favs_Records.B10[record].tx_hi_cut = Convert.ToInt32(arr[5]);
                                break;
                            case 1:
                                Favorites_Controls.Favs_Records.B12[record].name = arr[0];
                                Favorites_Controls.Favs_Records.B12[record].freq = arr[1];
                                Favorites_Controls.Favs_Records.B12[record].mode = arr[2];
                                Favorites_Controls.Favs_Records.B12[record].hi_cut = Convert.ToInt32(arr[3]);
                                Favorites_Controls.Favs_Records.B12[record].cw_bw = Convert.ToInt32(arr[4]);
