                                Favorites_Controls.Favs_Records.B30[record].mode = arr[2];
                                Favorites_Controls.Favs_Records.B30[record].hi_cut = Convert.ToInt32(arr[3]);
                                Favorites_Controls.Favs_Records.B30[record].cw_bw = Convert.ToInt32(arr[4]);
                                Favorites_Controls.Favs_Records.B30[record].tx_hi_cut = Convert.ToInt32(arr[5]);
                                break;
                            case 6:
