                                Favorites_Controls.Favs_Records.B40[record].tx_hi_cut = Convert.ToInt32(arr[5]);
                                MonitorTextBoxText(" Load_Favorites_Parameters.  40M tx_hi_cut: " +
                                                                    Convert.ToString(Favorites_Controls.Favs_Records.B40[record].tx_hi_cut));
                                break;
                            case 7:
                                Favorites_Controls.Favs_Records.B60[record].name = arr[0];
