                                Favorites_Controls.Favs_Records.B60[record].cw_bw = Convert.ToInt32(arr[4]);
                                Favorites_Controls.Favs_Records.B60[record].tx_hi_cut = Convert.ToInt32(arr[5]);
                                break;
                            case 8:
                                Favorites_Controls.Favs_Records.B80[record].name = arr[0];
                                Favorites_Controls.Favs_Records.B80[record].freq = arr[1];
                                Favorites_Controls.Favs_Records.B80[record].mode = arr[2];
                                Favorites_Controls.Favs_Records.B80[record].hi_cut = Convert.ToInt32(arr[3]);
                                Favorites_Controls.Favs_Records.B80[record].cw_bw = Convert.ToInt32(arr[4]);
                                Favorites_Controls.Favs_Records.B80[record].tx_hi_cut = Convert.ToInt32(arr[5]);
                                break;
                            case 9:
                                Favorites_Controls.Favs_Records.B160[record].name = arr[0];
                                Favorites_Controls.Favs_Records.B160[record].freq = arr[1];
                                Favorites_Controls.Favs_Records.B160[record].mode = arr[2];
                                Favorites_Controls.Favs_Records.B160[record].hi_cut = Convert.ToInt32(arr[3]);
                                Favorites_Controls.Favs_Records.B160[record].cw_bw = Convert.ToInt32(arr[4]);
                                Favorites_Controls.Favs_Records.B160[record].tx_hi_cut = Convert.ToInt32(arr[5]);
                                break;
                        }
                    }
                    catch (Exception e)
                    {
                        MonitorTextBoxText(" Load_Favorites_Parameters -> Switch FAILED: " + Convert.ToString(e));
                    }
                    record++;
                }
            }
            file.Close();
            return true;
        }

       
       
