        public bool Init_Waterfall_values()
        {
            String path, line;
            System.IO.StreamReader file;
            short temp_int = 0;
            String temp_string;

            waterfall_init_running = true;
            String Message = "Init_Waterfall_values started";
            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            // add our folder and file name
#if RPI
            path += "/mscc-GEMINUS/user_controls.ini";
#endif
            // try to open the file
            try
            {
                //file = new System.IO.StreamReader(path);
                file = new System.IO.StreamReader(File.OpenRead(path));
            }

            // if the file open fails, whine prettily and return false
            catch (IOException e)
            {
                Spectrum_Master_Controls.er = e.Message;
                return false;
            }
            while ((line = file.ReadLine()) != null)
            {
                temp_string = getBetween_spectrum(line, "PANADAPTER_MARKER=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);

                    Message = " PANADAPTER_MARKER: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);

                    switch (temp_int)
                    {
                        case 0:
                            Display_GDI.MarkerFilterColor = Color.Red;
                            break;
                        case 1:
                            Display_GDI.MarkerFilterColor = Color.Blue;
                            break;
                        case 2:
                            Display_GDI.MarkerFilterColor = Color.Green;
                            break;
                        case 3:
                            Display_GDI.MarkerFilterColor = Color.Yellow;
                            break;
                        case 4:
                            Display_GDI.MarkerFilterColor = Color.White;
                            break;
                        case 5:
                            Display_GDI.MarkerFilterColor = Color.Black;
                            break;
                    }
                }

                temp_string = getBetween_spectrum(line, "WATERFALL_GRID=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Waterfall_Controls.Time_grid = (byte)temp_int;
                    Message = " WATERFALL_GRID: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);
                }

                temp_string = getBetween_spectrum(line, "WATERFALL_PALLET=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Waterfall_Controls.pallet_index = temp_int;
                    switch (Waterfall_Controls.pallet_index)
                    {
                        case 0:
                            Display_GDI.ColorSheme = ColorSheme.original;
                            break;
                        case 1:
                            Display_GDI.ColorSheme = ColorSheme.enhanced;
                            break;
                        case 2:
                            Display_GDI.ColorSheme = ColorSheme.SPECTRAN;
                            break;
                        case 3:
                            Display_GDI.ColorSheme = ColorSheme.BLACKWHITE;
                            break;
                    }
                    Message = " WATERFALL_PALLET: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);
                }

                temp_string = getBetween_spectrum(line, "WATERFALL_DIRECTION=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    if (temp_int == 1)
                    {
                        Display_GDI.ReverseWaterfall = true;
                    }
                    else
                    {
                        Display_GDI.ReverseWaterfall = false;
                    }
                    waterfall_initialized = true;
                    Message = " WATERFALL_DIRECTION: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);
                }

                temp_string = getBetween_spectrum(line, "WATERFALL_GAIN=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Waterfall_Controls.gain = (temp_int * 100);
                    Message = " WATERFALL_GAIN: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);
                }

                temp_string = getBetween_spectrum(line, "WATERFALL_ZERO=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Waterfall_Controls.zero = (temp_int * 100);
                    Message = " WATERFALL_ZERO: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);
                }

                temp_string = getBetween_spectrum(line, "WATERFALL_SPEED=", ";");
                if (temp_string != "")
                {
                    Int16.TryParse(temp_string, out temp_int);
                    Waterfall_Controls.window_speed = (temp_int - 10);
                    if (Waterfall_Controls.window_speed < 0)
                    {
                        Waterfall_Controls.window_speed = 0;
                    }
                    Message = " WATERFALL_SPEED: " + Convert.ToString(temp_int);
                    //Write_Debug_Message(Message);
                }

            }
            file.Close();
            Display_GDI.WaterfallHighThreshold = 7000.0f - (float)Waterfall_Controls.gain;
            Message = " Init_Waterfall_values Finished";
            waterfall_init_running = false;
            //Write_Debug_Message(Message);
            return true;
        }
        private void Initialize_Waterfall()
        {
            String Message = " Initialize_Waterfall -> Called";
            Write_Debug_Message(Message);
            picWaterfall.Visible = true;
            Waterfall_pic_window_size = picWaterfall.Size;
            Waterfall_Controls.Pic_Waterfall_graphics = picWaterfall.CreateGraphics();
            Waterfall_Controls.Pic_Waterfall_graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.HighSpeed;
            Waterfall_Controls.Pic_Waterfall_graphics.CompositingMode = System.Drawing.Drawing2D.CompositingMode.SourceCopy;
            Waterfall_Controls.Pic_Waterfall_graphics.CompositingQuality = System.Drawing.Drawing2D.CompositingQuality.HighSpeed;
            Waterfall_Panadapter_Controls.Start_X_Position = picWaterfall.Location.X;
            Waterfall_Panadapter_Controls.Width = picWaterfall.Width;
            Waterfall_Panadapter_Controls.Height = picWaterfall.Height;
            Message = " pic_size W: " + Convert.ToString(Waterfall_pic_window_size.Width) + " H: " +
                Convert.ToString(Waterfall_pic_window_size.Height) +
                " pic X location: " + Convert.ToString(Waterfall_Panadapter_Controls.Start_X_Position);
            Display_GDI.CurrentDisplayMode = DisplayMode.WATERFALL;
            Display_GDI.WaterfallDataReady = true;
            Display_GDI.Initialize_Spectrum_Box(Waterfall_Controls.Pic_Waterfall_graphics, Waterfall_Panadapter_Controls.Width,
                                                                            Waterfall_Panadapter_Controls.Height);
            this.picWaterfall.BackColor = Color.White;

            //Display_GDI.WaterfallDataReady = false;
            Display_GDI.Waterfall_Ready = true;
            Display_GDI.MOX = false;
            Display_GDI.CurrentDisplayMode = DisplayMode.WATERFALL;
            Display_GDI.WaterfallLowThreshold = 1.0f;
            Display_GDI.WaterfallHighThreshold = 3090.0f;
            Display_GDI.Init();
            Message = " Initialize_Waterfall Finished";
            Write_Debug_Message(Message);
        }
        public void Process_Waterfall(ref byte[] udp_data, int read_size)
        {
            byte op_code;
            int operand;
            String Message;

            //read_size = udp_data.Length;
            op_code = udp_data[0];
            operand = udp_data[1];

            switch (op_code)
            {
                case Waterfall_Panadapter_Controls.CMD_GET_SET_PANADAPTER:
                    int sequence = 0;
                    int data_size = 0;
                    int temp_x = 0;
                    UInt16 x = 0;
                    UInt16 y = 0;
                    UInt16 y_gain = 0;

                    sequence = operand;
                    data_size = read_size - 2;

                    if (waterfall_initialized && Waterfall_Master_Controls.System_Ready && Display_GDI.Waterfall_Ready)
                    {
                        Waterfall_Master_Controls.No_Data = false;
                        Waterfall_Master_Controls.No_Data_Received_Count = 0;
                        switch (sequence)
                        {
                            case 0:
                                if (Waterfall_Panadapter_Controls.Sequence_1_Complete)
                                {
                                    Waterfall_Panadapter_Controls.Sequence_0_Complete = false;
                                    x = 0;
                                    y = 0;
                                    Waterfall_Panadapter_Controls.Buffer_0.X_value[x] = x;
                                    //Need skip past the first two control bytes
                                    Waterfall_Panadapter_Controls.Buffer_0.Y_value[x] = BitConverter.ToUInt16(udp_data, 2);
                                    x++;
                                    y = 4;
                                    temp_x = 1;
                                    while (temp_x < (data_size / 2))
                                    {
                                        Waterfall_Panadapter_Controls.Buffer_0.X_value[x] = x;
                                        Waterfall_Panadapter_Controls.Buffer_0.Y_value[x] = BitConverter.ToUInt16(udp_data, y);
                                        x++;
                                        y += 2;
                                        temp_x++;
                                    }
                                    x = 0;
                                    Waterfall_Panadapter_Controls.Sequence_0_Complete = true;
                                }
                                break;

                            case 1:
                                if (Waterfall_Panadapter_Controls.Sequence_0_Complete)
                                {
                                    Waterfall_Panadapter_Controls.Sequence_1_Complete = false;
                                    //Do the first copy of the message buffer outside of the loop to skip over the control bytes.
                                    x = 0;
                                    y = 0;
                                    Waterfall_Panadapter_Controls.Buffer_1.X_value[x] = x;
                                    //Need skip past the first two control bytes
                                    Waterfall_Panadapter_Controls.Buffer_1.Y_value[x] = BitConverter.ToUInt16(udp_data, 2);
                                    x++;
                                    y = 4;
                                    temp_x = 1;
                                    while (temp_x < (data_size / 2))
                                    {
                                        Waterfall_Panadapter_Controls.Buffer_1.X_value[x] = x;
                                        Waterfall_Panadapter_Controls.Buffer_1.Y_value[x] = BitConverter.ToUInt16(udp_data, y);
                                        x++;
                                        y += 2;
                                        temp_x++;
                                    }

                                    //Now copy the two receive buffers to the display buffer
                                    //Copy Buffer_0
                                    for (x = 0; x < Waterfall_Panadapter_Controls.Max_X; x++)
                                    {
                                        Waterfall_Panadapter_Controls.Display_Buffer.X_value[x] = x;
                                        y_gain = (UInt16)(Waterfall_Panadapter_Controls.Buffer_0.Y_value[x] + Waterfall_Controls.zero);
                                        Waterfall_Panadapter_Controls.Display_Buffer.Y_value[x] = y_gain;

                                    }
                                    y = (UInt16)Waterfall_Panadapter_Controls.Max_X;
                                    //Copy Buffer_1
                                    for (x = 0; x < Waterfall_Panadapter_Controls.Max_X; x++)
                                    {
                                        Waterfall_Panadapter_Controls.Display_Buffer.X_value[x + Waterfall_Panadapter_Controls.Max_X] =
                                            (UInt16)(x + Waterfall_Panadapter_Controls.Max_X);
                                        y_gain = (UInt16)(Waterfall_Panadapter_Controls.Buffer_1.Y_value[x] + Waterfall_Controls.zero);
                                        Waterfall_Panadapter_Controls.Display_Buffer.Y_value[x + Waterfall_Panadapter_Controls.Max_X] =
                                                                            y_gain;
                                        //Spectrum_Panadapter_Controls.Buffer_1.Y_value[x];
                                    }

                                    /*Array.Copy(Spectrum_Panadapter_Controls.Display_Buffer.Y_value, 
                                        Spectrum_Panadapter_Controls.Start_X_Position,
                                        Waterfall_Controls.new_waterfall_data, 0, Spectrum_Panadapter_Controls.Width);
                                    */
                                    Array.Copy(Waterfall_Panadapter_Controls.Display_Buffer.Y_value,
                                        Waterfall_Panadapter_Controls.Start_X_Position, Waterfall_Controls.current_waterfall_data,
                                        0, Waterfall_Panadapter_Controls.Width);
                                    if (Waterfall_Master_Controls.Display_Delay_Count == 0)
                                    {
                                        try
                                        {
                                            //Display_GDI.DrawWaterfall(Waterfall_Controls.Pic_Waterfall_graphics,
                                            //  Spectrum_Panadapter_Controls.Width, Spectrum_Panadapter_Controls.Height);
                                            //picWaterfall.Invalidate();
                                            Display_GDI.DrawWaterfall(Waterfall_Controls.Pic_Waterfall_graphics,
                                                 Waterfall_Panadapter_Controls.Width, Waterfall_Panadapter_Controls.Height);
                                            Waterfall_Panadapter_Controls.Sequence_1_Complete = true;
                                        }
                                        catch
                                        {
                                            Write_Debug_Message(" Call to Display_GDI.DrawWaterfall Failed");
                                        }
                                        break;
                                    }
                                    else
                                    {
                                        Waterfall_Master_Controls.Display_Delay_Count--;
                                    }
                                }
                                break;
                        }
                    }
                    else
                    {
                        if (Display_GDI.Waterfall_Ready == false)
                        {
                            Write_Debug_Message(" Waterfall NOT ready");
                        }
                    }
                    break;

                case Waterfall_Panadapter_Controls.CMD_SET_MONITOR:
                    switch (operand)
                    {
                        case 0:
                            Waterfall_Panadapter_Controls.Monitor = false;
                            break;
                        case 1:
                            Waterfall_Panadapter_Controls.Monitor = true;
                            break;
                    }
                    Message = " CMD_SET_MONITOR: " + Convert.ToString(Waterfall_Panadapter_Controls.Monitor);
                    Write_Debug_Message(Message);
                    break;

                case Waterfall_Panadapter_Controls.CMD_SET_SPECTRUM_WATERFALL_FREQ:
                    Waterfall_Panadapter_Controls.XCVR_Freq = BitConverter.ToInt32(udp_data, 1);
                    Write_Debug_Message(" CMD_SET_SPECTRUM_WATERFALL_FREQ: " +
                        Convert.ToString(Waterfall_Panadapter_Controls.XCVR_Freq));
                    break;

                case Waterfall_Panadapter_Controls.CMD_SET_MAIN_FREQ:
                    Waterfall_Panadapter_Controls.XCVR_Freq = BitConverter.ToInt32(udp_data, 1);
                    Write_Debug_Message(" CMD_SET_MAIN_FREQ: " +
                       Convert.ToString(Waterfall_Panadapter_Controls.XCVR_Freq));
                    break;

                case Waterfall_Panadapter_Controls.CMD_SET_TX_ON:
                    Waterfall_Master_Controls.TX_On = (byte)operand;
                    if (Waterfall_Master_Controls.Previous_TX_On != Waterfall_Master_Controls.TX_On)
                    {
                        Waterfall_Master_Controls.Display_Delay_Count = 9; //This removes the -12KHZ mixing spike when returning to RX
                        Waterfall_Master_Controls.Previous_TX_On = Waterfall_Master_Controls.TX_On;
                    }
                    Message = " CMD_SET_TX_ON received: " + Convert.ToString(Waterfall_Master_Controls.TX_On);
                    Write_Debug_Message(Message);
                    break;

                case Waterfall_Filter_control.CMD_SET_BW_HICUT:
                    Waterfall_Controls.Markers.band_marker_high = operand;
                    Waterfall_Filter_control.Filter_High_Index = (short)operand;
                    Message = " CMD_SET_BW_HICUT Received: " + operand;
                    Write_Debug_Message(Message);
                    break;

                case Waterfall_Panadapter_Controls.CMD_SET_CW_PITCH:
                    Message = " CMD_SET_CW_PITCH Received: " + operand;
                    Write_Debug_Message(Message);
                    Waterfall_Filter_control.CW_Pitch_Index = operand;
                    break;

                case Waterfall_Panadapter_Controls.CMD_SET_SPECTRUM_WATERFALL_MODE:
                    Waterfall_Last_used.Current_mode = Convert.ToChar(operand);
                    Message = " Waterfall_Last_used.Current_mode: " + Waterfall_Last_used.Current_mode;
                    Write_Debug_Message(Message);
                    break;

                default:
                    Write_Debug_Message(" Process_Spectrum. Unknown Opcode Received: " + Convert.ToString(op_code));
                    break;
            }
        }
        #endregion Waterfall_Management

    #region Spectrum_Management
        public void Process_Spectrum(ref byte[] udp_data, int read_size)
        {
            byte op_code;
            int operand;
            String Message;

            //read_size = udp_data.Length;
            op_code = udp_data[0];
            operand = udp_data[1];

            Spectrum_Panadapter_Controls.Call_count++;
            switch (op_code)
            {
                case Spectrum_Panadapter_Controls.CMD_GET_SET_PANADAPTER:
                    int sequence = 0;
                    int data_size = 0;
                    int temp_x = 0;
                    UInt16 x = 0;
                    UInt16 y = 0;

                    
                    Spectrum_Display.Spectrum_Ready = true;
                    if (Spectrum_Master_Controls.System_Ready &&
                        Spectrum_Master_Controls.spectrum_initialized && Spectrum_Display.Spectrum_Ready)
                    {
                        
                        //Write_Debug_Message(" CMD_GET_SET_PANADAPTER. STARTED");
                        sequence = operand;
                        data_size = read_size - 2;
                        Spectrum_Master_Controls.No_Data = false;
                        Spectrum_Master_Controls.No_Data_Received_Count = 0;
                        switch (sequence)
                        {
                            case 0:
                                if (Spectrum_Panadapter_Controls.Sequence_1_Complete)
                                {
                                    //Spectrum_Display.DataReady = false;
                                    //Write_Debug_Message(" CMD_GET_SET_PANADAPTER. STARTED. CASE 0");
                                    Spectrum_Panadapter_Controls.Sequence_0_Complete = false;
                                    x = 0;
                                    y = 0;
                                    Spectrum_Panadapter_Controls.Buffer_0.X_value[x] = x;
                                    //Need skip past the first two control bytes
                                    Spectrum_Panadapter_Controls.Buffer_0.Y_value[x] = BitConverter.ToUInt16(udp_data, 2);
                                    x++;
                                    y = 4;
                                    temp_x = 1;
                                    while (temp_x < (data_size / 2))
                                    {
                                        Spectrum_Panadapter_Controls.Buffer_0.X_value[x] = x;
                                        Spectrum_Panadapter_Controls.Buffer_0.Y_value[x] = BitConverter.ToUInt16(udp_data, y);
                                        x++;
                                        y += 2;
                                        temp_x++;
                                    }
                                    x = 0;
                                    Spectrum_Panadapter_Controls.Sequence_0_Complete = true;
                                }
                                break;

                            case 1:
                                if (Spectrum_Panadapter_Controls.Sequence_0_Complete)
                                {
                                    //Write_Debug_Message(" CMD_GET_SET_PANADAPTER. CASE 1");
                                    Spectrum_Panadapter_Controls.Sequence_1_Complete = false;
                                    //Do the first copy of the message buffer outside of the loop to skip over the control bytes.
                                    x = 0;
                                    y = 0;
                                    Spectrum_Panadapter_Controls.Buffer_1.X_value[x] = x;
                                    //Need skip past the first two control bytes
                                    Spectrum_Panadapter_Controls.Buffer_1.Y_value[x] = BitConverter.ToUInt16(udp_data, 2);
                                    x++;
                                    y = 4;
                                    temp_x = 1;
                                    while (temp_x < (data_size / 2))
                                    {
                                        Spectrum_Panadapter_Controls.Buffer_1.X_value[x] = x;
                                        Spectrum_Panadapter_Controls.Buffer_1.Y_value[x] = BitConverter.ToUInt16(udp_data, y);
                                        x++;
                                        y += 2;
                                        temp_x++;
                                    }

                                    //Now copy the two receive buffers to the display buffer
                                    for (x = 0; x < Spectrum_Panadapter_Controls.Max_X; x++)
                                    {
                                        Spectrum_Panadapter_Controls.Display_Buffer.X_value[x] = x;
                                        Spectrum_Panadapter_Controls.Display_Buffer.Y_value[x] =
                                            Spectrum_Panadapter_Controls.Buffer_0.Y_value[x];
                                    }
                                    y = (UInt16)Spectrum_Panadapter_Controls.Max_X;
                                    for (x = 0; x < Spectrum_Panadapter_Controls.Max_X; x++)
                                    {
                                        Spectrum_Panadapter_Controls.Display_Buffer.X_value[x +
                                            Spectrum_Panadapter_Controls.Max_X] = (UInt16)(x + Spectrum_Panadapter_Controls.Max_X);
                                        Spectrum_Panadapter_Controls.Display_Buffer.Y_value[x + Spectrum_Panadapter_Controls.Max_X] =
                                            Spectrum_Panadapter_Controls.Buffer_1.Y_value[x];
                                    }
                                    Array.Copy(Spectrum_Panadapter_Controls.Display_Buffer.Y_value,
                                        Spectrum_Panadapter_Controls.Start_X_Position, Spectrum_Display.new_display_data,
                                                0, (Spectrum_Panadapter_Controls.Width));
                                    //Spectrum_Panadapter_Controls.Sequence_1_Complete = true;
                                    if (Spectrum_Master_Controls.Display_Delay_Count == 0)
                                    {
                                        try
                                        {
                                            
                                            //Spectrum_Display.DataReady = true;
                                            Spectrum_Display.DrawPanadapter(Pic_Spectrum_graphics, Spectrum_Panadapter_Controls.Width,
                                                Spectrum_Panadapter_Controls.Height, 1, false);
                                            picSpectrum.Invalidate();
                                            Spectrum_Panadapter_Controls.Sequence_1_Complete = true;
                                            Write_Debug_Message(" CMD_GET_SET_PANADAPTER. FINISHED");
                                        }
                                        catch
                                        {
                                            Write_Debug_Message(" Call to Display.DrawPanadapter Failed");
                                        }
                                    }
                                    else
                                    {
                                        Spectrum_Master_Controls.Display_Delay_Count--;
                                    }
                                }
                                break;
                        }
                    }
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_MONITOR:
                    switch (operand)
                    {
                        case 0:
                            Spectrum_Panadapter_Controls.Monitor = false;
                            break;
                        case 1:
                            Spectrum_Panadapter_Controls.Monitor = true;
                            break;
                    }
                    Message = " CMD_SET_MONITOR: " + Convert.ToString(Spectrum_Panadapter_Controls.Monitor);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Filter_control.CMD_SET_TX_HICUT:
                    Spectrum_Filter_control.Filter_TX_High_Index = (short)operand;
                    switch (Spectrum_Filter_control.Filter_TX_High_Index)
                    {
                        case 0:
                            Spectrum_Filter_control.Markers.TX_DISPLAY_BANDWITH = 2400;
                            break;
                        case 1:
                            Spectrum_Filter_control.Markers.TX_DISPLAY_BANDWITH = 2700;
                            break;
                        case 2:
                            Spectrum_Filter_control.Markers.TX_DISPLAY_BANDWITH = 3000;
                            break;
                        case 3:
                            Spectrum_Filter_control.Markers.TX_DISPLAY_BANDWITH = 5500;
                            break;
                    }
                    Message = " Process_Spectrum. CMD_SET_TX_HICUT received: " + Convert.ToString(operand) + "TX Bandwidth: " +
                                                                        Convert.ToString(Spectrum_Filter_control.Markers.TX_DISPLAY_BANDWITH);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_STEP_VALUE:
                    Spectrum_Panadapter_Controls.XCVR_Step_Index = (byte)operand;
                    switch (Spectrum_Panadapter_Controls.XCVR_Step_Index)
                    {
                        case 0:
                            Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier = 100000;
                            break;
                        case 1:
                            Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier = 10000;
                            break;
                        case 2:
                            Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier = 1000;
                            break;
                        case 3:
                            Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier = 100;
                            break;
                        case 4:
                            Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier = 10;
                            break;
                        case 5:
                            Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier = 1;
                            break;
                    }
                    Message = " Process_Spectrum. CMD_SET_STEP_VALUE received: " + Convert.ToString(operand);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_GET_SET_MSSDR_STATUS:
                    Spectrum_Panadapter_Controls.GUI_Ready = true;
                    Message = " Process_Spectrum. CMD_GET_SET_MSSDR_STATUS received: " + Convert.ToString(Spectrum_Panadapter_Controls.GUI_Ready);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_SPECTRUM_VIEW_GRID:
                    switch (operand)
                    {
                        case 0:
                            Spectrum_Panadapter_Controls.view_grid = false;
                            break;
                        case 1:
                            Spectrum_Panadapter_Controls.view_grid = true;
                            break;
                    }
                    Message = " Process_Spectrum. CMD_SET_SPECTRUM_VIEW_GRID received: " + Convert.ToString(operand);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_SPECTRUM_SHARP:
                    Message = " Process_Spectrum. CMD_SET_SPECTRUM_SHARP received: " + Convert.ToString(operand);
                    Write_Debug_Message(Message);
                    switch (operand)
                    {
                        case 0:
                            Spectrum_Panadapter_Controls.Anti_Alias = false;
                            break;
                        case 1:
                            Spectrum_Panadapter_Controls.Anti_Alias = true;
                            break;
                    }
                    break;

                case Spectrum_Filter_control.CMD_SET_BW_HICUT:
                    Spectrum_Filter_control.Filter_High_Index = (short)operand;
                    Spectrum_Filter_control.Markers.band_marker_high = operand;
                    Message = " Process_Spectrum. CMD_SET_BW_HICUT received: " + Convert.ToString(Spectrum_Filter_control.Filter_High_Index);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_TX_ON:
                    Spectrum_Master_Controls.TX_On = (byte)operand;
                    if (Spectrum_Master_Controls.Previous_TX_On != Spectrum_Master_Controls.TX_On)
                    {
                        Spectrum_Master_Controls.Display_Delay_Count = 9; //This removes the -12KHZ mixing spike when returning to RX
                        Spectrum_Master_Controls.Previous_TX_On = Spectrum_Master_Controls.TX_On;
                    }
                    Message = " Process_Spectrum. CMD_SET_TX_ON received: " + Convert.ToString(Spectrum_Master_Controls.TX_On);
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_CW_PITCH:
                    Spectrum_Filter_control.CW_Pitch_Index = operand;
                    Message = " Process_Spectrum. CMD_SET_CW_PITCH received";
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_SPECTRUM_WATERFALL_MODE:
                    Spectrum_Last_used.Current_mode = Convert.ToChar(operand);
                    Message = " Spectrum_Last_used.Current_mode: " + Spectrum_Last_used.Current_mode;
                    Write_Debug_Message(Message);
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_SPECTRUM_WATERFALL_FREQ:
                    Spectrum_Panadapter_Controls.XCVR_Freq = BitConverter.ToInt32(udp_data, 1);
                    Spectrum_Panadapter_Controls.XCVR_Scroll_Freq = Spectrum_Panadapter_Controls.XCVR_Freq;
                    Set_Viewport();
                    Write_Debug_Message(" Process_Spectrum. CMD_SET_SPECTRUM_WATERFALL_FREQ: " +
                        Convert.ToString(Spectrum_Panadapter_Controls.XCVR_Freq));
                    break;

                case Spectrum_Panadapter_Controls.CMD_SET_MAIN_FREQ:
                    Spectrum_Panadapter_Controls.XCVR_Freq = BitConverter.ToInt32(udp_data, 1);
                    Spectrum_Panadapter_Controls.XCVR_Scroll_Freq = Spectrum_Panadapter_Controls.XCVR_Freq;
                    Set_Viewport();
                    Write_Debug_Message(" Process_Spectrum. CMD_SET_MAIN_FREQ: " +
                       Convert.ToString(Spectrum_Panadapter_Controls.XCVR_Freq));
                    break;

                default:
                    Write_Debug_Message(" Process_Spectrum. Unknown Opcode Received: " + Convert.ToString(op_code));
                    break;
            }
        }
