        public void Set_Viewport()
        {
            int high_temp = 0;
            int MHz = 0;
            int KHz = 0;
            int Hz = 0;

            Spectrum_Panadapter_Controls.Freq_Bounds.Low_Freq = (Spectrum_Panadapter_Controls.Display_freq -
                                    (Spectrum_Filter_control.Markers.DISPLAY_BANDWIDTH / 2)) +
                                                    ((Spectrum_Filter_control.Markers.DISPLAY_BANDWIDTH /
                                   Spectrum_Filter_control.Markers.STARTUP_MAX_PIXELS));// *
                                                                                        //Spectrum_Panadapter_Controls.Freq_Bounds.Current_X_Min); 

            high_temp = Spectrum_Filter_control.Markers.STARTUP_MAX_PIXELS -
                                            Spectrum_Panadapter_Controls.Freq_Bounds.Current_X_Max;
            Spectrum_Panadapter_Controls.Freq_Bounds.High_Freq = (Spectrum_Panadapter_Controls.Display_freq +
                (Spectrum_Filter_control.Markers.DISPLAY_BANDWIDTH / 2)) -
                ((Spectrum_Filter_control.Markers.DISPLAY_BANDWIDTH /
                                    Spectrum_Filter_control.Markers.STARTUP_MAX_PIXELS) * high_temp);

            MHz = (Spectrum_Panadapter_Controls.Freq_Bounds.Low_Freq) / 1000000;
            KHz = ((Spectrum_Panadapter_Controls.Freq_Bounds.Low_Freq) - (MHz * 1000000)) / 1000;
            Hz = (Spectrum_Panadapter_Controls.Freq_Bounds.Low_Freq) - (MHz * 1000000) - (KHz * 1000);

            MHz = (Spectrum_Panadapter_Controls.Freq_Bounds.High_Freq) / 1000000;
            KHz = ((Spectrum_Panadapter_Controls.Freq_Bounds.High_Freq) - (MHz * 1000000)) / 1000;
            Hz = (Spectrum_Panadapter_Controls.Freq_Bounds.High_Freq) - (MHz * 1000000) - (KHz * 1000);
        }
        public static string getBetween_spectrum(string strSource, string strStart, string strEnd)
        {
            int Start, End;
            if (strSource.Contains(strStart) && strSource.Contains(strEnd))
            {
                Start = strSource.IndexOf(strStart, 0) + strStart.Length;
                End = strSource.IndexOf(strEnd, Start);
                return strSource.Substring(Start, End - Start);
            }
            else
            {
                return "";
            }
        }
