        public void Initialize_Spectrum()
        {
            this.picSpectrum.Paint += new System.Windows.Forms.PaintEventHandler(Spectrum_Display.pictureBox_Paint);
            String Message = " Initialize_Spectrum START";
            Write_Debug_Message(Message);
            picSpectrum.Visible = true;
            Spectrum_pic_window_size = picSpectrum.Size;
            Spectrum_Panadapter_Controls.Start_X_Position = picSpectrum.Location.X;
            Spectrum_Panadapter_Controls.Width = picSpectrum.Width;
            Spectrum_Panadapter_Controls.Height = picSpectrum.Height;
            Spectrum_Panadapter_Controls.bm = new Bitmap(Spectrum_Panadapter_Controls.Width, Spectrum_Panadapter_Controls.Height);
            Pic_Spectrum_graphics = Graphics.FromImage(Spectrum_Panadapter_Controls.bm);
            Message = " pic_size W: " + Convert.ToString(Spectrum_pic_window_size.Width) + " H: " 
                + Convert.ToString(Spectrum_pic_window_size.Height) +
                " pic X location: " + Convert.ToString(Spectrum_Panadapter_Controls.Start_X_Position);
            Write_Debug_Message(Message);
            Spectrum_Display.G_Width = Spectrum_Panadapter_Controls.Width;
            Spectrum_Display.G_Height = Spectrum_Panadapter_Controls.Height;
            Spectrum_Display.MOX = false;
            Spectrum_Display.current_display_mode = DisplayMode.PANADAPTER;
            Spectrum_Display.Init();
            //Display.SpectrumGridMax = 7000;
            Spectrum_Display.PanFill = true;
            Spectrum_Display.RXDisplayLow = 0;
            Spectrum_Display.TXDisplayHigh = 72000;
            Spectrum_Display.RXDisplayHigh = 72000;
            Spectrum_Display.DataReady = true;
            Pic_Spectrum_graphics.SmoothingMode = SmoothingMode.HighSpeed;
            Pic_Spectrum_graphics.CompositingMode = CompositingMode.SourceOver;
            Pic_Spectrum_graphics.CompositingQuality = CompositingQuality.HighSpeed;
            Spectrum_Display.Initialize_Spectrum_Box(Pic_Spectrum_graphics, Spectrum_Panadapter_Controls.Width,
                                                                            Spectrum_Panadapter_Controls.Height);
            picSpectrum.Show();
            Spectrum_Master_Controls.spectrum_initialized = true;
            //Spectrum_Master_Controls.System_Ready = true;
            Message = " Initialize_Spectrum FINSHED";
            Write_Debug_Message(Message);
        }
