        public void Set_Spectrum_Frequency(int freq)
        {
            int delta = 0;
            int new_freq = 0;

            //int temp_freq = 0;
            Write_Debug_Message(" Set_Spectrum_Frequency -> Called -> frequency: " + Convert.ToString(freq));
            if (Spectrum_Last_used.Current_mode != 'C')
            {
                if (Spectrum_Panadapter_Controls.Auto_Snap.Auto_Snap_Checkbox)
                {
                    delta = freq % Spectrum_Panadapter_Controls.Auto_Snap.Snap_Value;
                    if (delta != 0)
                    {
                        switch (Spectrum_Panadapter_Controls.Auto_Snap.Snap_Value)
                        {
                            case 1000:
                                if (delta > (Spectrum_Panadapter_Controls.Auto_Snap.Snap_Value / 2))
                                {
                                    new_freq = Spectrum_Panadapter_Controls.Auto_Snap.Snap_Value - delta;
                                    freq = freq + new_freq;
                                }
                                else
                                {
                                    freq = freq - delta;
                                }
                                break;
                            case 500:
                                new_freq = freq - delta;
                                delta = new_freq % 1000;
                                if (delta == 0)
                                {
                                    freq = new_freq;
                                }
                                else
                                {
                                    delta = freq % 500;
                                    freq = freq - delta;
                                }
                                break;
                            case 100:
                                new_freq = freq - delta;
                                delta = new_freq % 500;
                                if (delta == 0)
                                {
                                    freq = new_freq;
                                }
                                else
                                {
                                    delta = freq % 100;
                                    freq = freq - delta;
                                }
                                break;
                        }
                    }
                    Write_Debug_Message(" Set_Spectrum_Frequency. New frequency: " + Convert.ToString(freq));
                }
            }
            Spectrum_oCode.DisplayFreq = freq;
            switch (Spectrum_oCode.current_band)
            {
                case 160:
                    Spectrum_Last_used.B160.Freq = freq;
                    break;
                case 80:
                    Spectrum_Last_used.B80.Freq = freq;
                    break;
                case 60:
                    Spectrum_Last_used.B60.Freq = freq;
                    break;
                case 40:
                    Spectrum_Last_used.B40.Freq = freq;
                    break;
                case 30:
                    Spectrum_Last_used.B30.Freq = freq;
                    break;
                case 20:
                    Spectrum_Last_used.B20.Freq = freq;
                    break;
                case 17:
                    Spectrum_Last_used.B17.Freq = freq;
                    break;
                case 15:
                    Spectrum_Last_used.B15.Freq = freq;
                    break;
                case 12:
                    Spectrum_Last_used.B12.Freq = freq;
                    break;
                case 10:
                    Spectrum_Last_used.B10.Freq = freq;
                    break;
                default:
                    Spectrum_Last_used.GEN.Freq = freq;
                    break;
            }
            Spectrum_Panadapter_Controls.Display_freq = freq;
            oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, freq);
            Freq_queue_add(freq);
            Write_Debug_Message(" Set_Frequency -> Finished");
        }
        private void CursorValueEvent(object sender, MouseEventArgs e)
        {
            double x = 0.0;
            double start_freq = 0.0;
            int freq = 0;
            double cw_offset = 0.0;
            int offset = 0;
            Point mouse_position;
            //String Message;

            mouse_position = Cursor.Position;

            if (Spectrum_Panadapter_Controls.Mouse_event.x == mouse_position.X &&
                Spectrum_Panadapter_Controls.Mouse_event.y == mouse_position.Y)
            {
                Spectrum_Panadapter_Controls.Cursor_Moved = false;
                return;
            }
            Spectrum_Panadapter_Controls.Cursor_Moved = true;
            Spectrum_Panadapter_Controls.Mouse_event.x = mouse_position.X;
            Spectrum_Panadapter_Controls.Mouse_event.y = mouse_position.Y;
            Spectrum_Panadapter_Controls.Mouse_event.User_Cursor_x = mouse_position.X - this.Location.X -
                offset;
            x = Spectrum_Panadapter_Controls.Mouse_event.User_Cursor_x;
            start_freq = (double)(Spectrum_Panadapter_Controls.XCVR_Freq - 36000.0);
            if (Spectrum_Last_used.Current_mode == 'C')
            {
                Set_CW_Pitch();
                cw_offset = (double)Spectrum_Filter_control.CW_Pitch;
            }
            else
            {
                cw_offset = 0.0d;
            }
            Spectrum_Panadapter_Controls.Graph_Freq = start_freq + ((72000.0d / 816.0d) * (x) - cw_offset);
            /*Message = "  Spectrum_Panadapter_Controls.XCVR_Freq: " + Convert.ToString(Spectrum_Panadapter_Controls.XCVR_Freq);
            Write_Debug_Message(Message);
            Message = "  start_freq: " + Convert.ToString(start_freq);
            Write_Debug_Message(Message);
            Message = " Spectrum_Panadapter_Controls.Graph_Freq " +
                Convert.ToString(Spectrum_Panadapter_Controls.Graph_Freq);
            Write_Debug_Message(Message);
            */
            //String Message = " X Position: " + Spectrum_Panadapter_Controls.Graph_Freq.ToString("f2");
            //Write_Debug_Message(Message);
            freq = (int)Spectrum_Panadapter_Controls.Graph_Freq;
            int MHz = (freq) / 1000000;
            int KHz = ((freq) - (MHz * 1000000)) / 1000;
            int Hz = (freq) - (MHz * 1000000) - (KHz * 1000);
            Spectrum_Panadapter_Controls.Mouse_event.Display_Freq = Convert.ToString(MHz) + "." +
                string.Format("{0:000}", KHz) + "." + string.Format("{0:000}", Hz);
            Cursor_message = Spectrum_Panadapter_Controls.Mouse_event.Display_Freq
                + "\r\n" + " 72KHz";
            Spectrum_Panadapter_Controls.Cursor_Controls.Cursor_freq = Cursor_message;
            if (Spectrum_Panadapter_Controls.Pan_Graph)
            {
                Pan_Graph(Spectrum_Panadapter_Controls.Graph_Freq);
            }

        }
