        public void Mouse_Scroll_freq(object sender, MouseEventArgs e)
        {
            Int32 n = e.Delta;

            if (Spectrum_Panadapter_Controls.Display_Cursor && !Spectrum_Panadapter_Controls.Pan_Graph)
            {
                if (n > 0) n = 1; else n = -1;
                switch (n)
                {
                    case 1:
                        Spectrum_Panadapter_Controls.XCVR_Scroll_Freq += Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier;
                        break;
                    default:
                        Spectrum_Panadapter_Controls.XCVR_Scroll_Freq -= Spectrum_Panadapter_Controls.XCVR_Freq_Multiplier;
                        break;
                }
                //SendCommand32(Server_txsocket, Server_txtarget, Spectrum_Panadapter_Controls.CMD_SET_MAIN_FREQ,
                //    Spectrum_Panadapter_Controls.XCVR_Scroll_Freq);
                //SendCommand32(GUI_txsocket, GUI_txtarget, Spectrum_Panadapter_Controls.CMD_SET_DISPLAY_FREQ,
                //    Spectrum_Panadapter_Controls.XCVR_Scroll_Freq);
                MonitorTextBoxText(" Mouse_Scroll_freq: " + Spectrum_Panadapter_Controls.XCVR_Scroll_Freq.ToString());
            }
        }
