        #region UDP_RECEIVE
        //THE FOLLOWING PROCEDURES RECEIVE DATA FROM MS-SDR
        public void OnUdpData(IAsyncResult result)
        {
            int op_code;
            int operand;
            Int32 Freq;
            int read_size = 0;
            byte[] buf = new byte[2];
            char mode = 'N';
            int version = 0;
            int sdr_trans_version = 0;
            short band = 180;
            int bias = 0;
            int VU_Value = 0;

            Master_Controls.Network_Receive_Busy = true;
            UdpClient socket = result.AsyncState as UdpClient;
            socket = result.AsyncState as UdpClient;
            // get the actual message and fill out the source:
            byte[] message = new byte[1024];
            message = socket.EndReceive(result, ref Udp_data.rxtarget);
            read_size = message.Length;

            //if (oCode.display_heartbeat) MonitorTextBoxText(  " Rx: " + "0x" + message[0].ToString("X2") + " " +
            //                                                                            BitConverter.ToInt32(message, 1) );
            op_code = message[0];
            operand = message[1];
            //MonitorTextBoxText(" Rx: " + "0x" + message[0].ToString("X2"));
            //MonitorTextBoxText( " Rx: Received Value: " + message[1].ToString("X4"));

            switch (op_code)
            {
                case Smeter_controls.CMD_MENSURO_CALIBRATE:
                    MonitorTextBoxText(" CMD_MENSURO_CALIBRATE. NOOP: " + Convert.ToString(operand));
                    Smeter_controls.Mensure_Calibration_Message = true;
                    break;

                case VFO_Controls.CMD_SET_VFO:
                    VFO_Controls.vfo = (byte)operand;
                    MonitorTextBoxText(" CMD_SET_VFO: " + Convert.ToString(VFO_Controls.vfo));
                    break;

                case IQ_Controls.CMD_REPORT_IMAGE_VALUE:
                    IQ_Controls.Image_Value = BitConverter.ToInt32(message, 1);
                    break;

                case Master_Controls.CMD_SET_ANTENNA_SENSE:
                    /*this.Antenna_Switch_checkBox.CheckedChanged -= new System.EventHandler(this.Antenna_Switch_checkBox_CheckedChanged);
                    switch (operand)
                    {
                        case 0:
                            Antenna_Switch_checkBox.Checked = false;
                            break;
                        case 1:
                            Antenna_Switch_checkBox.Checked = true;
                            break;
                    }
                    this.Antenna_Switch_checkBox.CheckedChanged += new System.EventHandler(this.Antenna_Switch_checkBox_CheckedChanged);
                    */
                    MonitorTextBoxText(" CMD_SET_ANTENNA_SENSE. NOOP: " + Convert.ToString(operand));
                    break;

                case Volume_Controls.CMD_SET_VOLUME_BY_SERVER:
                    Transceiver_Model_Settings.Volume_Settings.Set_By_Server = true;
                    if (!Transceiver_Model_Settings.Volume_Settings.Mic_Is_Digital)
                    {
                        Transceiver_Model_Settings.Volume_Settings.Speaker_Voice_Volume = operand;
                    }
                    else
                    {
                        Transceiver_Model_Settings.Volume_Settings.Speaker_Volume = operand;
                    }
                    Transceiver_Model_Settings.Volume_Settings.Master_Speaker_Volume = operand;
                    MonitorTextBoxText(" CMD_SET_VOLUME_BY_SERVER: " + Convert.ToString(operand));
                    break;

                case RIT.Rit_Controls.CMD_SET_RIT_FREQ:
                    RIT.Rit_Controls.RIT_Offset_From_Server = BitConverter.ToInt32(message, 1);
                    break;

                case oCode.CMD_SET_MAIN_MODE:
                    //MonitorTextBoxText(" CMD_SET_MAIN_MODE: NOOP");
                    MonitorTextBoxText(" CMD_SET_MAIN_MODE: " + Convert.ToString((char)operand));
                    switch ((char)operand)
                    {
                        case 'A':
                            Master_Controls.modeswitch = Power_Controls.Mode.AM_mode;
                            mainmodebutton2.Text = "AM";
                            mode = 'A';
                            //Volume_Controls.Volume_Slider_Mode = Volume_Controls.SLIDER_AM_MODE;
                            break;
                        case 'L':
                            Master_Controls.modeswitch = Power_Controls.Mode.LSB_mode;
                            mainmodebutton2.Text = "LSB";
                            mode = 'L';
                            //Volume_Controls.Volume_Slider_Mode = Volume_Controls.SLIDER_SSB_MODE;
                            break;
                        case 'U':
                            Master_Controls.modeswitch = Power_Controls.Mode.USB_mode;
                            mainmodebutton2.Text = "USB";
                            mode = 'U';
                            //Volume_Controls.Volume_Slider_Mode = Volume_Controls.SLIDER_SSB_MODE;
                            break;
                        case 'C':
                            Master_Controls.modeswitch = Power_Controls.Mode.CW_mode;
                            mainmodebutton2.Text = "CW";
                            mode = 'C';
                            //Volume_Controls.Volume_Slider_Mode = Volume_Controls.SLIDER_CW_MODE;
                            break;
                    }
                    VFOA_Last_Used.Last_used.Current_mode = mode;
                    switch (VFOA_Master_Controls.current_band)
                    {
                        case 160:
                            VFOA_Last_Used.Last_used.B160.Mode = mode;
                            break;
                        case 80:
                            VFOA_Last_Used.Last_used.B80.Mode = mode;
                            break;
                        case 60:
                            VFOA_Last_Used.Last_used.B60.Mode = mode;
                            break;
                        case 40:
                            VFOA_Last_Used.Last_used.B40.Mode = mode;
                            break;
                        case 30:
                            VFOA_Last_Used.Last_used.B30.Mode = mode;
                            break;
                        case 20:
                            VFOA_Last_Used.Last_used.B20.Mode = mode;
                            break;
                        case 17:
                            VFOA_Last_Used.Last_used.B17.Mode = mode;
                            break;
                        case 15:
                            VFOA_Last_Used.Last_used.B15.Mode = mode;
                            break;
                        case 12:
                            VFOA_Last_Used.Last_used.B12.Mode = mode;
                            break;
                        case 10:
                            VFOA_Last_Used.Last_used.B10.Mode = mode;
                            break;
                        default:
                            VFOA_Last_Used.Last_used.GEN.Mode = mode;
                            break;
                    }
                    VFOA_Last_Used.Last_used.Current_mode = mode;
                    break;

                case Master_Controls.CMD_SEND_GUI_STATUS:
                    Master_Controls.GUI_check_status = true;
                    MonitorTextBoxText(" OnUdpData -> CMD_SEND_GUI_STATUS Received");
                    break;

                case Tuning_Knob_Controls.CMD_SET_STEP_VALUE:
                    VFOA_Master_Controls.Freq_Tune_Index = (short)operand;
#if RPI
                    Transceiver_Model_Settings.Freq_Step = operand;
#else
                    Master_Controls.Step_Index = operand;
#endif
                    Master_Controls.FreqDigit = (short)Swap_tuning_step(operand);
                    Transceiver_Model_Settings.New_Freq_Pointer = true;
                    //Set_Freq_Digit_Pointer();
                    break;
                    

                case oCode.CMD_SET_KEEP_ALIVE:
                    Master_Controls.Keep_Alive = true;
                    break;

                case AGC_ALC_Notch_Controls.CMD_SET_ALC:
                    if (Master_Controls.Transmit_Mode)
                    {
                        Main_Smeter_controls.VU_Meter_value = BitConverter.ToInt32(message, 1);
                        if (Master_Controls.Debug_Display)
                        {
                            MonitorTextBoxText(" OnUdpData -> CMD_SET_ALC RECIEVED(1). VALUE : " +
                                                                    Convert.ToString(Main_Smeter_controls.VU_Meter_value));
                        }
                        if (Master_Controls.Debug_Display)
                        {
                            MonitorTextBoxText(" OnUdpData -> CMD_SET_ALC RECIEVED(2). VALUE : " +
                               Convert.ToString(BitConverter.ToInt32(message, 1)));
                        }
                        VU_Value = BitConverter.ToInt32(message, 1);
                        Smeter_controls.VU.VU_Value = VU_Value;
                    }
                    break;

                case Audio_Device_Controls.CMD_SET_MICROPHONE_STATUS:
                    if (operand == 1)
                    {
                        Master_Controls.code_triggered = true;
                        //MIC_Status_checkBox2.Checked = true;
                        Master_Controls.code_triggered = false;
                        Audio_Device_Controls.Microphone_Status = true;
                        //MIC_Status_checkBox2.Text = "Microphone ON";
                    }
                    else
                    {
                        Master_Controls.code_triggered = true;
                        //MIC_Status_checkBox2.Checked = false;
                        Master_Controls.code_triggered = false;
                        Audio_Device_Controls.Microphone_Status = false;
                        //MIC_Status_checkBox2.Text = "Microphone OFF";
                    }
                    break;

                case Amplifier_Power_Controls.CMD_SET_POTENTIA_CALIBRATION:
                    Amplifier_Power_Controls.Current_Calibration_Value = BitConverter.ToInt16(message, 1);
                    if (Amplifier_Power_Controls.Current_Calibration_Value >= -99 &&
                        Amplifier_Power_Controls.Current_Calibration_Value <= 4)
                    {
                        Transceiver_Model_Settings.Amplifier_Values.Power_Calibration = 
                            Amplifier_Power_Controls.Current_Calibration_Value;
                    }
                    Power_calibration_label58.Text = "STEP: " + 
                        Convert.ToString((100 + Amplifier_Power_Controls.Current_Calibration_Value));
                    MonitorTextBoxText(" OnUdpData. CMD_SET_POTENTIA_CALIBRATION. Calibration Value: " +
                        Convert.ToString(BitConverter.ToInt16(message, 1)));
                    break;

                case Amplifier_Power_Controls.CMD_GET_POTENTIA_TEMPERATURE:
                    //temperature = operand;
                    G_Potentia_Temparature_Average = operand;
                    Amplifier_temperature_label58.Text = "PA TEMP: " + Convert.ToString(operand) + "°C";
                    AMP_Temp_MFC_AMP_label5.Text = "PA: " + Convert.ToString(operand) + "°C";
                    break;

                case Amplifier_Power_Controls.CMD_GET_AMP_POWER:
                    Master_Controls.Power_Bar_Value = operand;
                    if (Master_Controls.Power_Bar_Value >= 0 && Master_Controls.Power_Bar_Value <= 100)
                    {
                        //Power_progressBar1.Value = Master_Controls.Power_Bar_Value;
                        //Power_Meter.Level = Master_Controls.Power_Bar_Value;
                    }
                    break;

                case Window_controls.CMD_SET_PANADAPTER_DISPLAY:
                    if (operand == 1)
                    {
                        Window_controls.Panadapter_On_By_Server = true;
                        Master_Controls.code_triggered = true;
                        Master_Controls.code_triggered = false;
                        Window_controls.Panadapter_Toggle = true;
                    }
                    else
                    {
                        Window_controls.Panadapter_On_By_Server = false;
                        Master_Controls.code_triggered = true;
                        Master_Controls.code_triggered = false;
                        Window_controls.Panadapter_Toggle = false;
                    }
                    break;

                case Amplifier_Power_Controls.CMD_GET_POTENTIA_BIAS:
                    bias = BitConverter.ToInt16(message, 1);
                    //MonitorTextBoxText(" OnUdpData -> CMD_GET_POTENTIA_BIAS Received. Amplifier_Power_Controls.Bias_On: " +
                    //       Amplifier_Power_Controls.Bias_On + " Received Bias: " + Convert.ToString(bias));
                    if (Amplifier_Power_Controls.Bias_On == true)
                    {
                        AMP_Raw_Bias_label5.Text = "BIAS I (ma): " + Convert.ToString(bias);
                    }
                    else
                    {
                        AMP_Raw_Bias_label5.Text = "PA I (ma): " + Convert.ToString(bias);
                    }
                    AMP_Current_label5.Text = "PA I (ma): " + Convert.ToString(bias);
                    Smeter_controls.Meter_I_Value = bias;
                    break;

                case Window_controls.CMD_SET_SMETER_DISPLAY:
                    if (operand == 1)
                    {
                        Window_controls.Smeter_On_By_Server = true;
                        Master_Controls.code_triggered = true;
                        Master_Controls.code_triggered = false;
                        Window_controls.Smeter_Toggle = true;
                    }
                    else
                    {
                        Window_controls.Smeter_On_By_Server = false;
                        Master_Controls.code_triggered = true;
                        Master_Controls.code_triggered = false;
                        Window_controls.Smeter_Toggle = false;
                    }
                    break;

                case Panadapter_Controls.CMD_SET_DRIFT:
                    int drift_temp = 0;
                    drift_temp = BitConverter.ToInt16(message, 1);
                    MonitorTextBoxText(" OnUdpData -> Panadapter_Controls.CMD_SET_DRIFT.  Drift:" +
                        Convert.ToString(drift_temp));
                    Freq_Comp_label32.Text = "Freq Comp: " + Convert.ToString(drift_temp) + " Hz";
                    break;

                case Master_Controls.CMD_GET_TRANSCEIVER_TEMP:
                    Temperature_label57.Text = "PROFICIO: " + Convert.ToString(operand) + "°C";
                    Smeter_controls.Proficio_temperature = operand;
                    Master_Controls.Transceiver_Warming = false;
                    break;

                case Master_Controls.CMD_RPI_SET_TEMPERATURE:
                    RPi_Temperature_label1.Text = "PROCESSOR: " + Convert.ToString(operand) + "°C";
                    if (operand >= 75)
                    {
                        Set_Warning_Label_Color(true, RPi_Temperature_label1);
                    }
                    else
                    {
                        Set_Warning_Label_Color(false, RPi_Temperature_label1);
                    }
                    break;

                case Master_Controls.CMD_GET_OPTIONS_STATUS:
                    MonitorTextBoxText(" OnUdpData. NOOP. CMD_GET_MIA_STATUS: " + Convert.ToString(operand));
                    /*if (operand == 0)
                    {
                        Transceiver_Model_Settings.Options_Status = false;
                        Master_Controls.QRP_Mode = true;
                    }
                    else
                    {
                        Transceiver_Model_Settings.Options_Status = true;
                    }
                    Transceiver_Model_Settings.Mia_Status_Set = true;
                    Manage_Options_Status();
                    */
                    break;

                case Master_Controls.CMD_SET_PA_BYPASS:
                    MonitorTextBoxText(" OnUdpData. NOOP. CMD_SET_PA_BYPASS: " + Convert.ToString(operand));
                    /*if (Transceiver_Model_Settings.Solidus_Status)
                    {
                        if (operand == 0)
                        {
                            Master_Controls.QRP_Mode = true;
                        }
                        else
                        {
                            Master_Controls.QRP_Mode = false;
                        }
                    }
                    else
                    {
                        MonitorTextBoxText(" OnUdpData -> CMD_SET_PA_BYPASS: NOT IN SOLIDUS MODE");
                    }*/
                    break;

                case IQ_Controls.CMD_GET_IQ_VALUE:
                    IQ_Controls.RPi.Calibration_Slider_Value = BitConverter.ToInt32(message, 1);
                    MonitorTextBoxText(" CMD_GET_IQ_VALUE: " + Convert.ToString(IQ_Controls.RPi.Calibration_Slider_Value));
                    break;

                case oCode.CMD_SET_STOP:
                    if (!Master_Controls.Shutdown_By_User)
                    {
                        if (operand == 0)
                        {
                            if (!Master_Controls.Shutdown)
                            {
                                DialogResult stop_ret = MessageBox.Show("A STOP Command from MS-SDR has been received." + "\r\n" +
                                    "MSCC will stop", "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
                                if (stop_ret == DialogResult.OK)
                                {
                                    Application.Exit();
                                }
                            }
                        }
                        else
                        {
                            MonitorTextBoxText(" CMD_SET_STOP: NORMAL SHUTDOWN BY SERVER");
                            //if (Band_Bank.General_Bank.General_Bank_Selected)
                            //{
                            //    Restore_HAM_Band();
                            //}
                            if (Band_Bank.Geminus_Bank.Geminus_Selected)
                            {
                                Restore_GEM_Band();
                            }
                            Master_Controls.Shutdown = true;
                            Smeter_Timer.Enabled = false;
                            Smeter_Timer.Stop();
                            Master_State_Machine_Timer.Enabled = false;
                            Master_State_Machine_Timer.Stop();
                            //Thread.Sleep(5);
                            if (Transceiver_Model_Settings.Client_Initialized)
                            {
                                Update_Client_Settings();
                            }
                            Thread.Sleep(1000);
                            Application.Exit();
                        }
                    }
                    break;

                case AGC_ALC_Notch_Controls.CMD_SET_AGC_FAST_LEVEL:
                    AGC_hScrollBar1.Value = BitConverter.ToInt32(message, 1);
                    AGC_Value_label.Text = Convert.ToString(AGC_hScrollBar1.Value) + " mS";
                    AGC_ALC_Notch_Controls.AGC_Release = AGC_hScrollBar1.Value;
                    MonitorTextBoxText(" CMD_SET_AGC_FAST_LEVEL: " + Convert.ToString(AGC_ALC_Notch_Controls.AGC_Release));
                    break;

                case AGC_ALC_Notch_Controls.CMD_GET_SET_AGC:
                    Master_Controls.code_triggered = true;
                    AGC_ALC_Notch_Controls.AGC_Level = operand;
                    AGC_listBox1.SelectedIndex = AGC_ALC_Notch_Controls.AGC_Level;
                    switch (AGC_ALC_Notch_Controls.AGC_Level)
                    {
                        case 0:
                            ACG_button.Text = "SLO";
                            break;
                        case 1:
                            ACG_button.Text = "MED";
                            break;
                        case 2:
                            ACG_button.Text = "FST";
                            break;
                    }
                    Master_Controls.code_triggered = false;
                    break;


                case Filter_control.CMD_SET_CW_PITCH:
                    Master_Controls.code_triggered = true;
                    CW_Pitch_listBox1.SelectedIndex = operand;
                    Filter_control.CW_Pitch_Index = operand;
                    switch (operand)
                    {
                        case 0:
                            Filter_control.CW_Pitch = 400;
                            break;
                        case 1:
                            Filter_control.CW_Pitch = 600;
                            break;
                        case 2:
                            Filter_control.CW_Pitch = 800;
                            break;
                        case 3:
                            Filter_control.CW_Pitch = 1000;
                            break;
                    }
                    Master_Controls.code_triggered = false;
                    break;

                case Panadapter_Controls.CMD_CW_SNAP_FINISHED:
                    MonitorTextBoxText(" CMD_CW_SNAP_FINISHED ->Received");
                    Panadapter_Controls.CW_Snap.Button_Color = Color.Black;
                    Window_controls.Waterfall_Controls.CW_Snap.Button_Color = Color.Black;
                    //Panadapter_Controls.CW_Snap.CW_button = false;
                    Panadapter_Controls.CW_Snap.CW_snap_status = false;
                    Window_controls.Waterfall_Controls.CW_Snap.CW_snap_status = false;
                    break;

                case Panadapter_Controls.CMD_SET_CW_SNAP_FREQ:
                    MonitorTextBoxText(" CMD_SET_CW_SNAP_FREQ ->Received");
                    int CW_Snap_Freq = BitConverter.ToInt32(message, 1);
                    MonitorTextBoxText(" CMD_SET_CW_SNAP_FREQ -> Setting CW SNAP Frequency: " + Convert.ToString(CW_Snap_Freq));
                    VFOA_Master_Controls.DisplayFreq = CW_Snap_Freq;
                    Display_Main_Freq_VFOA();
                    break;

