        #region MFC_Management
        private void MFC_Update_Timer_Tick(object sender, EventArgs e)
        {
            byte transceiver_display = 0;
            byte[] buf = new byte[2];

            switch (Tuning_Knob_Controls.Send_State)
            {
                case 0:
                    transceiver_display = (byte)(0x00 | Tuning_Knob_Controls.Initialize.knob_switch);
                    oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_TRANSCEIVER_DISPLAY, transceiver_display);
                    buf[0] = Master_Controls.Extended_Commands.CMD_SET_KNOB_SWITCH;
                    buf[1] = (byte)Tuning_Knob_Controls.Initialize.knob_switch;
                    oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                    Tuning_Knob_Controls.Send_State++;
                    break;
                case 1:
                    transceiver_display = (byte)(0x10 | Tuning_Knob_Controls.Initialize.left_switch);
                    oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_TRANSCEIVER_DISPLAY, transceiver_display);
                    buf[0] = Master_Controls.Extended_Commands.CMD_SET_LEFT_SWITCH;
                    buf[1] = (byte)Tuning_Knob_Controls.Initialize.left_switch;
                    oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                    Tuning_Knob_Controls.Send_State++;
                    break;
                case 2:
                    transceiver_display = (byte)(0x20 | Tuning_Knob_Controls.Initialize.middle_switch);
                    oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_TRANSCEIVER_DISPLAY, transceiver_display);
                    buf[0] = Master_Controls.Extended_Commands.CMD_SET_MIDDLE_SWITCH;
                    buf[1] = (byte)Tuning_Knob_Controls.Initialize.middle_switch;
                    oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                    Tuning_Knob_Controls.Send_State++;
                    break;
                case 3:
                    transceiver_display = (byte)(0x30 | Tuning_Knob_Controls.Initialize.right_switch);
                    oCode.SendCommand(txsocket, txtarget, Tuning_Knob_Controls.CMD_SET_TRANSCEIVER_DISPLAY, transceiver_display);
                    buf[0] = Master_Controls.Extended_Commands.CMD_SET_RIGHT_SWITCH;
                    buf[1] = (byte)Tuning_Knob_Controls.Initialize.right_switch;
                    oCode.SendCommand_MultiByte(txsocket, txtarget, Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                    MFC_Update_Timer.Stop();
                    MFC_Update_Timer.Enabled = false;
                    break;
            }
        }
        public bool parse_line(String line)
        {
            //ListViewItem itm;
            String temp_string;
            int param_pos = 0;
            int end_pos = 0;

            MonitorTextBoxText(" parse_line -> Start");
            param_pos = line.IndexOf("VERSION");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 8));   // parse everything between the end of NAME= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the VERSION parameter value. Find the trailing comma
                MFC_arr[0] = temp_string.Substring(0, end_pos);   // temp string will start with the DEVICE_NAME parameter value.
                param_pos = 0;
            }
            param_pos = line.IndexOf("STATE");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 6));   // parse everything between the end of STATE= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the STATE parameter value. Find the trailing comma
                MFC_arr[5] = temp_string.Substring(0, end_pos);   // temp string will start with the DEVICE_NAME parameter value.
                param_pos = 0;
            }
            param_pos = line.IndexOf("KNOB_SWITCH");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 12));   // parse everything between the end of NAME= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the DEVICE_NAME parameter value. Find the trailing comma
                MFC_arr[1] = temp_string.Substring(0, end_pos);   // temp string will start with the DEVICE_NAME parameter value.
                param_pos = 0;
            }
            param_pos = line.IndexOf("LEFT_SWITCH");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 12));   // parse everything between the end of NAME= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the DEVICE_NAME parameter value. Find the trailing comma
                MFC_arr[2] = temp_string.Substring(0, end_pos);   // temp string will start with the DEVICE_NAME parameter value.
                param_pos = 0;
            }
            param_pos = line.IndexOf("MIDDLE_SWITCH");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 14));   // parse everything between the end of MIDDLE_SWITCH= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the MIDDLE_SWITCH parameter value. Find the trailing comma
                MFC_arr[3] = temp_string.Substring(0, end_pos);   // temp string will start with the MIDDLE_SWITCH parameter value.
                param_pos = 0;
            }
            param_pos = line.IndexOf("RIGHT_SWITCH");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 13));   // parse everything between the end of NAME= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the DEVICE_NAME parameter value. Find the trailing comma
                MFC_arr[4] = temp_string.Substring(0, end_pos);   // temp string will start with the DEVICE_NAME parameter value.
                param_pos = 0;
            }
            param_pos = line.IndexOf("PTT_SWITCH");
            if (param_pos != -1)
            {
                temp_string = line.Substring((param_pos + 11));   // parse everything between the end of NAME= and the end of the line.
                end_pos = temp_string.IndexOf(";"); //temp string will start with the DEVICE_NAME parameter value. Find the trailing comma
                MFC_arr[6] = temp_string.Substring(0, end_pos);   // temp string will start with the DEVICE_NAME parameter value.
                param_pos = 0;
            }
            MonitorTextBoxText(" parse_line -> Finish");
            return false;
        }
        public int Check_MFC_Value(int value)
        {
            int mfc_value = 0;

            if (value > Tuning_Knob_Controls.Button_Function_List.MAX_FUNCTIONS)
            {
                mfc_value = 0;
            }
            else
            {
                mfc_value = value;
            }
            return mfc_value;
        }
        public bool MFC_Initialize()
        {
            String path, line;
            System.IO.StreamReader file;
            bool status = false;

            MonitorTextBoxText(" Initialize_MFC -> Starting");

            path = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
#if RPI
            path += "/mscc-GEMINUS/mfc_controller.ini";
#else
            path += "\\multus-sdr-client\\mfc_controller.ini";
#endif
            try
            {
                file = new System.IO.StreamReader(File.OpenRead(path));
            }
            catch (IOException e)
            {
                string er = e.Message;
                DialogResult ret = MessageBox.Show("IO Exception opening: mfc_controller.ini. " +
                    "\r\n Error: " + er + "\r\nMake note of the error and send log files to Multus SDR,LLC.",
                    "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return false;
            }
            while ((line = file.ReadLine()) != null)
            {
                status = parse_line(line);
            }
            file.Close();
            Tuning_Knob_Controls.Initialize.version = Convert.ToInt16(MFC_arr[0]);
            Tuning_Knob_Controls.Initialize.knob_switch = Convert.ToInt16(MFC_arr[1]);
            Tuning_Knob_Controls.Initialize.knob_switch = Check_MFC_Value(Tuning_Knob_Controls.Initialize.knob_switch);
            Tuning_Knob_Controls.Initialize.left_switch = Convert.ToInt16(MFC_arr[2]);
            Tuning_Knob_Controls.Initialize.left_switch = Check_MFC_Value(Tuning_Knob_Controls.Initialize.left_switch);
            Tuning_Knob_Controls.Initialize.middle_switch = Convert.ToInt16(MFC_arr[3]);
            Tuning_Knob_Controls.Initialize.middle_switch = Check_MFC_Value(Tuning_Knob_Controls.Initialize.middle_switch);
            Tuning_Knob_Controls.Initialize.right_switch = Convert.ToInt16(MFC_arr[4]);
            Tuning_Knob_Controls.Initialize.right_switch = Check_MFC_Value(Tuning_Knob_Controls.Initialize.right_switch);
            Tuning_Knob_Controls.Initialize.state = Convert.ToInt16(MFC_arr[5]);
            Tuning_Knob_Controls.Initialize.ptt_switch = Convert.ToInt16(MFC_arr[6]);
            Tuning_Knob_Controls.Initialize.ptt_switch = Check_MFC_Value(Tuning_Knob_Controls.Initialize.ptt_switch);
            Master_Controls.code_triggered = true;
            Tuning_Knob_Controls.Initialize_State++;

            //Knob_comboBox1.SelectedIndex = Tuning_Knob_Controls.Initialize.knob_switch;
            Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.KNOB_SWITCH] = (sbyte)Tuning_Knob_Controls.Initialize.knob_switch;
            Tuning_Knob_Controls.Knob_switch_function = (byte)Tuning_Knob_Controls.Initialize.knob_switch;
            //MFC_Knob_label38.Text = "K: " + Knob_comboBox1.Text;
            Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.PTT_SWITCH] = (sbyte)Tuning_Knob_Controls.Initialize.ptt_switch;
            Tuning_Knob_Controls.PTT_switch_function = (byte)Tuning_Knob_Controls.Initialize.ptt_switch;
            Tuning_Knob_Controls.Initialize_State++;

            //Left_Button_comboBox2.SelectedIndex = Tuning_Knob_Controls.Initialize.left_switch;
            Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.LEFT_SWITCH] = (sbyte)Tuning_Knob_Controls.Initialize.left_switch;
            Tuning_Knob_Controls.Button_left_function = (byte)Tuning_Knob_Controls.Initialize.left_switch;
            Tuning_Knob_Controls.Star_Position.Left = (byte)(0x10 | Tuning_Knob_Controls.Initialize.left_switch);
            //MFC_A_label38.Text = "A: " + Left_Button_comboBox2.Text;
            Tuning_Knob_Controls.Initialize_State++;

            //Middle_Button_comboBox3.SelectedIndex = Tuning_Knob_Controls.Initialize.middle_switch;
            MonitorTextBoxText(" Initialize_MFC -> middle_switch: " + Convert.ToString(Tuning_Knob_Controls.Initialize.middle_switch));
            Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.MIDDLE_SWITCH] = (sbyte)Tuning_Knob_Controls.Initialize.middle_switch;
            Tuning_Knob_Controls.Button_middle_function = (byte)Tuning_Knob_Controls.Initialize.middle_switch;
            Tuning_Knob_Controls.Star_Position.Middle = (byte)(0x20 | Tuning_Knob_Controls.Initialize.middle_switch);
            //MFC_B_label38.Text = "B: " + Middle_Button_comboBox3.Text;
            Tuning_Knob_Controls.Initialize_State++;

            //MFC_Switch_C_comboBox.SelectedIndex = Tuning_Knob_Controls.Initialize.right_switch;
            Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.RIGHT_SWITCH] = (sbyte)Tuning_Knob_Controls.Initialize.right_switch;
            Tuning_Knob_Controls.Button_right_function = (byte)Tuning_Knob_Controls.Initialize.right_switch;
            Tuning_Knob_Controls.Star_Position.Right = (byte)(0x30 | Tuning_Knob_Controls.Initialize.right_switch);
            //MFC_C_label38.Text = "C: " + MFC_Switch_C_comboBox.Text;
            Tuning_Knob_Controls.Initialize_State++;

            Master_Controls.code_triggered = false;
            /*if (Tuning_Knob_Controls.Initialize.state == 1)
            {
                Tuning_Knob_Controls.On = true;
                //Tuning_Knob_groupBox1.Enabled = true;
                Knob_comboBox1.Enabled = true;
                Left_Button_comboBox2.Enabled = true;
                MFC_Switch_C_comboBox.Enabled = true;
                Middle_Button_comboBox3.Enabled = true;
            }
            else
            {
                //Tuning_Knob_groupBox1.Enabled = false;
                Knob_comboBox1.Enabled = false;
                Left_Button_comboBox2.Enabled = false;
                MFC_Switch_C_comboBox.Enabled = false;
                Middle_Button_comboBox3.Enabled = false;
            }*/
            MonitorTextBoxText(" Tuning Knob Initialization Finished: " + Tuning_Knob_Controls.Initialize.knob_switch +
                Tuning_Knob_Controls.Initialize.left_switch + Tuning_Knob_Controls.Initialize.middle_switch +
                Tuning_Knob_Controls.Initialize.right_switch);
            Tuning_Knob_Controls.Initialize_State++;
            Tuning_Knob_Controls.MFC_Initialized = true;
            return true;
        }
        public bool Compare_Switches(sbyte MFC_switch, int switch_value)
        {
            bool status = true;

            MonitorTextBoxText(" Compare_Switches Called. MFC_Switch: " + Convert.ToString(MFC_switch));
            MonitorTextBoxText(" Compare_Switches: " + Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.KNOB_SWITCH] +
                 Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.LEFT_SWITCH] +
                Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.MIDDLE_SWITCH] +
                Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.RIGHT_SWITCH] +
                Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.PTT_switch]);

            switch (MFC_switch)
            {
                case Tuning_Knob_Controls.KNOB_SWITCH:
                    if (switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.LEFT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.RIGHT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.MIDDLE_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.PTT_SWITCH])
                    {
                        status = false;
                    }
                    break;

                case Tuning_Knob_Controls.LEFT_SWITCH:
                    if (switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.MIDDLE_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.RIGHT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.KNOB_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.PTT_SWITCH])
                    {
                        status = false;
                    }
                    break;

                case Tuning_Knob_Controls.MIDDLE_SWITCH:
                    if (switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.LEFT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.RIGHT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.KNOB_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.PTT_SWITCH])
                    {
                        status = false;
                    }
                    break;

                case Tuning_Knob_Controls.RIGHT_SWITCH:
                    if (switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.LEFT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.KNOB_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.MIDDLE_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.PTT_SWITCH])
                    {
                        status = false;
                    }
                    break;

                case Tuning_Knob_Controls.PTT_SWITCH:
                    if (switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.LEFT_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.KNOB_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.MIDDLE_SWITCH] ||
                        switch_value == Tuning_Knob_Controls.previous_switch_table[Tuning_Knob_Controls.RIGHT_SWITCH])
                    {
                        status = false;
                    }
                    break;
            }
            if (status == false)
            {
                MessageBox.Show("Multiple switches may NOT have the same function", "MSCC",
                    MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
            MonitorTextBoxText(" Compare_Switches Finished. Status: " + Convert.ToString(status));
            return status;
        }
