        private void VU_Blink_button_Click(object sender, EventArgs e)
        {
            if (Smeter_controls.VU.Blink == 1)
            {
                ALC_Blink_timer1.Enabled = false;
                ALC_Blink_timer1.Stop();
                if (Smeter_controls.selected_mode == Smeter_controls.ALC_MODE)
                {
                    Set_Button_Color(true, Meter_ALC_button8);
                }
                Smeter_controls.VU.Blink = 0;
                Set_Button_Color(false, VU_Blink_button);
            }
            else
            {
                ALC_Blink_timer1.Enabled = true;
                ALC_Blink_timer1.Start();
                Smeter_controls.VU.Blink = 1;
                Set_Button_Color(true, VU_Blink_button);
            }
        }
        private void S_Meter_Color_button_Click(object sender, EventArgs e)
        {
            Smeter_controls.Meter_Background_Color = Smeter_controls.Meter_Background_Color_Index;
