            {
                case 0:
                    vuMeter1.DialBackground = Color.Moccasin;
                    S_Meter_Color_button.BackColor = Color.Moccasin;
                    S_Meter_Color_button.Text = "Moccasin".ToUpper();
                    break;
                case 1:
                    vuMeter1.DialBackground = Color.Coral;
