                    S_Meter_Color_button.Text = "Coral".ToUpper();
                    break;
                case 2:
                    vuMeter1.DialBackground = Color.Tomato;
                    S_Meter_Color_button.BackColor = Color.Tomato;
                    S_Meter_Color_button.Text = "Tomato".ToUpper();
                    break;
                case 3:
                    vuMeter1.DialBackground = Color.Orange;
                    S_Meter_Color_button.BackColor = Color.Orange;
                    S_Meter_Color_button.Text = "Orange".ToUpper();
                    break;
                case 4:
                    vuMeter1.DialBackground = Color.Blue;
                    S_Meter_Color_button.BackColor = Color.Blue;
                    S_Meter_Color_button.Text = "Blue".ToUpper();
                    break;
                case 5:
                    vuMeter1.DialBackground = Color.Green;
                    S_Meter_Color_button.BackColor = Color.Green;
                    S_Meter_Color_button.Text = "Green".ToUpper();
                    break;
                case 6:
                    vuMeter1.DialBackground = Color.Yellow;
