        private void ALC_ON_OFF_button5_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            if (AGC_ALC_Notch_Controls.ALC_STATE == false)
            {
                DialogResult ret = MessageBox.Show("TURN ALC OFF? THIS IS FOR TESTING PURPOSES ONLY", "MSCC",
                    MessageBoxButtons.YesNo, MessageBoxIcon.Warning, MessageBoxDefaultButton.Button1);
                if (ret == DialogResult.Yes)
                {
                    AGC_ALC_Notch_Controls.ALC_STATE = true;
                    oCode.SendCommand(txsocket, txtarget, AGC_ALC_Notch_Controls.CMD_SET_ALC_MULTIPLIER, 0);
                    Smeter_controls.VU.VU_Value = 0;
                    Set_Button_Color(true, ALC_ON_OFF_button5, "ALC OFF");
                }
            }
            else
            {
                AGC_ALC_Notch_Controls.ALC_STATE = false;
                oCode.SendCommand(txsocket, txtarget, AGC_ALC_Notch_Controls.CMD_SET_ALC_MULTIPLIER,
                                                                                (short)AGC_ALC_Notch_Controls.ALC_Value);
                Set_Button_Color(false, ALC_ON_OFF_button5, "ALC ON");
            }
        }
        private void ALC_Blink_timer1_Tick(object sender, EventArgs e)
        {
            int vu_display_value;
            int blink_time_slow = 1000;
            int blink_time_med = 750;
            int blink_time_fast = 500;

            if (Master_Controls.Transmit_Mode && VFOA_Last_Used.Last_used.Current_mode != 'C')
            {
                vu_display_value = Smeter_controls.VU.VU_Value;
                if (vu_display_value >= 10)
                {
                    Smeter_controls.ALC_Blink_Display = true;
                    if (Smeter_controls.ALC_Blink_Toggle)
                    {
                        Set_Button_Color(true, Meter_ALC_button8);
                        Smeter_controls.ALC_Blink_Toggle = false;
                    }
                    else
                    {
                        Set_Button_Color(false, Meter_ALC_button8);
                        Smeter_controls.ALC_Blink_Toggle = true;
                    }
                    if (vu_display_value > 10 && vu_display_value <= 180)
                    {
                        ALC_Blink_timer1.Interval = blink_time_slow;
                    }
                    else
                    {
                        if (vu_display_value > 180 && vu_display_value < 360)
                        {
                            ALC_Blink_timer1.Interval = blink_time_med;
                        }
                        else
                        {
                            if (vu_display_value >= 360)
                            {
                                ALC_Blink_timer1.Interval = blink_time_fast;
                            }
                        }
                    }
                }
                else
                {
                    if (Smeter_controls.ALC_Blink_Display == true)
                    {
                        Smeter_controls.VU.VU_Value = 0;
                        vu_display_value = Smeter_controls.VU.VU_Value;
                        if (Smeter_controls.selected_mode == Smeter_controls.ALC_MODE)
                        {
                            Set_Button_Color(true, Meter_ALC_button8);
                        }
                        else
                        {
                            Set_Button_Color(false, Meter_ALC_button8);
                            Smeter_controls.ALC_Blink_Display = false;
                        }
                    }
                }
            }
            else
            {
                if (Smeter_controls.ALC_Blink_Display == true)
                {
                    if (Smeter_controls.selected_mode != Smeter_controls.ALC_MODE)
                    {
                        Smeter_controls.VU.VU_Value = 0;
                        vu_display_value = Smeter_controls.VU.VU_Value;
                        Set_Button_Color(false, Meter_ALC_button8);
                    }
                    Smeter_controls.ALC_Blink_Display = false;
                }
            }
        }
