        public String Db_to_Smeter_Display(int db)
        {
            String Smeter_display = "S1";
            if (db <= -130) return Smeter_display = "S0";
            if (db <= -121) return Smeter_display = "S0";
            if (db <= -115) return Smeter_display = "S1";
            if (db <= -109) return Smeter_display = "S2";
            if (db <= -103) return Smeter_display = "S3";
            if (db <= -97) return Smeter_display = "S4";
            if (db <= -91) return Smeter_display = "S5";
            if (db <= -85) return Smeter_display = "S6";
            if (db <= -79) return Smeter_display = "S7";
            if (db <= -73) return Smeter_display = "S9";
            if (db <= -63) return Smeter_display = "S9";
            if (db <= -53) return Smeter_display = "S9+10";
            if (db <= -43) return Smeter_display = "S9+20";
            if (db <= -33) return Smeter_display = "S9+30";
            if (db <= -23) return Smeter_display = "S9+40";
            if (db <= -13) return Smeter_display = "S9+50";
            return Smeter_display;
        }
        public int Db_to_Smeter(int db)
        {
            int smeter_value = 0;
            //Write_Debug_Message(" Db_to_Smeter -> db: " + Convert.ToString(db));
            if (db <= -130) return 0;
            if (db <= -121) return 1;
            if (db <= -115) return 2;
            if (db <= -109) return 3;
            if (db <= -103) return 4;
            if (db <= -97) return 5;
            if (db <= -91) return 6;
            if (db <= -85) return 7;
            if (db <= -79) return 8;
            if (db <= -73) return 9;
            if (db <= -63) return 10;
            if (db <= -53) return 11;
            if (db <= -43) return 12;
            if (db <= -33) return 13;
            if (db <= -23) return 14;
            if (db <= -13) return 15;
            return smeter_value;
        }
