        private bool Manage_Text_Display()
        {
            bool display_mode = false;
            if (Smeter_controls.Display_Mode == Smeter_controls.S_METER_MODE)
            {
                if (!Smeter_controls.Display_Smeter_Value)
                {
                    Dbm_Value_label9.Visible = true;
                    Dbm_label9.Visible = true;
                    Power_Value_label2.Visible = false;
                    Power_Value_label2.Text = "";
                }
                else
                {
                    Smeter_Display_Value_label.Visible = true;
                    Dbm_Value_label9.Visible = false;
                    Dbm_label9.Visible = false;
                    Power_Value_label2.Visible = false;
                    Power_Value_label2.Text = "";
                }
                display_mode = true;
            }
            else
            {
                Smeter_Display_Value_label.Visible = false;
                Dbm_Value_label9.Visible = false;
                Dbm_label9.Visible = false;
                Power_Value_label2.Visible = true;
                //Power_Value_label2.Visible = true;
                display_mode = false;
            }
            MonitorTextBoxText(" Manage_Text_Display: display_mode: " + Convert.ToString(display_mode));
            return display_mode;
        }
        private void Set_Smeter_Label_Color(bool active, Label mylabel)
        {
            switch (active)
            {
                case true:
                    mylabel.ForeColor = Color.Red;
                    mylabel.BackColor = Color.White;
                    break;
                default:
                    mylabel.ForeColor = Color.White;
                    mylabel.BackColor = Color.Transparent;
                    break;
            }
