        private void Configure_Meter()
        {
            if (Smeter_controls.Display_Mode != Smeter_controls.selected_mode)
            {
                Size led_size = new Size();
                MonitorTextBoxText(" Configure_Meter: Smeter_controls.Display_Mode: " + Convert.ToString(Smeter_controls.Display_Mode) +
                                            " Smeter_controls.selected_mode:  " + Convert.ToString(Smeter_controls.selected_mode));
                Smeter_controls.Display_Mode = Smeter_controls.selected_mode;
                vuMeter1.Level = 0;
                Set_Smeter_Label_Color(false, Power_Value_label2);
                vuMeter1.ShowTextInDial = true;
                led_size.Width = 3;
                led_size.Height = 14;
                vuMeter1.LedSize = led_size;
                vuMeter1.Led1ColorOff = Smeter_controls.meter_colors.led1_off;
                vuMeter1.Led1ColorOn = Smeter_controls.meter_colors.led1_on;
                vuMeter1.Led2ColorOff = Smeter_controls.meter_colors.led2_off;
                vuMeter1.Led2ColorOn = Smeter_controls.meter_colors.led2_on;
                vuMeter1.Led3ColorOff = Smeter_controls.meter_colors.led3_off;
                vuMeter1.Led3ColorOn = Smeter_controls.meter_colors.led3_on;
                switch (Smeter_controls.selected_mode)
                {
                    case Smeter_controls.POWER_MODE:
                        Smeter_controls.Display_Power_Value = true;
                        switch (Master_Controls.QRP_Mode)
                        {
                            case true:
                                //Meter_Power_button8.Text = "P";
                                vuMeter1.SuspendLayout();
                                vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                                vuMeter1.VuText = "Watts";
                                vuMeter1.TextInDial = Smeter_controls.Smeter.power_dial_QRP;
                                vuMeter1.Level = 0;
                                vuMeter1.Led1Count = 4;
                                vuMeter1.Led2Count = 0;
                                vuMeter1.Led3Count = 2;
                                vuMeter1.LevelMax = 110;
                                vuMeter1.DialTextNegative = Color.Red;
                                vuMeter1.DialTextPositive = Color.Black;
                                vuMeter1.ResumeLayout();
                                MonitorTextBoxText(" Meter Set to QRP mode");
                                break;
                            default:
                                //Meter_Power_button8.Text = "P";
                                vuMeter1.SuspendLayout();
                                vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                                vuMeter1.VuText = "Watts";
                                vuMeter1.TextInDial = Smeter_controls.Smeter.power_dial_QRO;
                                vuMeter1.Level = 0;
                                vuMeter1.Led1Count = 6;
                                vuMeter1.Led2Count = 2;
                                vuMeter1.Led3Count = 2;
                                vuMeter1.LevelMax = Smeter_controls.Power_Meter_Max_Level;
                                vuMeter1.DialTextNegative = Color.Red;
                                vuMeter1.DialTextPositive = Color.Black;
                                vuMeter1.ResumeLayout();
                                break;
                        }
                        break;
                    case Smeter_controls.SWR_MODE:
                        vuMeter1.SuspendLayout();
                        vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                        vuMeter1.VuText = "SWR";
                        vuMeter1.TextInDial = Smeter_controls.Smeter.swr_dial;
                        vuMeter1.Level = 0;
                        vuMeter1.Led1Count = 4;
                        vuMeter1.Led2Count = 3;
                        vuMeter1.Led3Count = 3;
                        vuMeter1.LevelMax = 20;
                        vuMeter1.DialTextNegative = Color.Red;
                        vuMeter1.DialTextPositive = Color.Black;
                        vuMeter1.ResumeLayout();
                        break;
                    case Smeter_controls.ALC_MODE:
                        vuMeter1.SuspendLayout();
                        vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                        vuMeter1.VuText = "ALC";
                        vuMeter1.TextInDial = Smeter_controls.Smeter.alc_dial;
                        vuMeter1.Level = 0;
                        vuMeter1.Led1Count = 6;
                        vuMeter1.Led2Count = 0;
                        vuMeter1.Led3Count = 3;
                        vuMeter1.LevelMax = 700;
                        vuMeter1.DialTextNegative = Color.Black;
                        vuMeter1.DialTextPositive = Color.Red;
                        led_size.Width = 16;
                        led_size.Height = 14;
                        vuMeter1.LedSize = led_size;
                        vuMeter1.Led1ColorOff = Color.LimeGreen;
                        vuMeter1.Led1ColorOn = Color.LimeGreen;
                        vuMeter1.Led3ColorOn = Color.Red;
                        vuMeter1.Led3ColorOff = Color.Red;
                        vuMeter1.ShowTextInDial = false;
                        vuMeter1.ResumeLayout();
                        Smeter_controls.VU.VU_Value = 0;
                        break;
                    case Smeter_controls.I_MODE:
                        vuMeter1.SuspendLayout();
                        vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                        vuMeter1.VuText = "I (Amp)";
                        vuMeter1.TextInDial = Smeter_controls.Smeter.I_dial;
                        vuMeter1.Level = 0;
                        vuMeter1.Led1Count = 7;
                        vuMeter1.Led2Count = 0;
                        vuMeter1.Led3Count = 0;
                        vuMeter1.LevelMax = 22;
                        vuMeter1.DialTextNegative = Color.Red;
                        vuMeter1.DialTextPositive = Color.Black;
                        vuMeter1.ResumeLayout();
                        break;
                    case Smeter_controls.TEMPERATURE_MODE:
                        vuMeter1.SuspendLayout();
                        vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                        vuMeter1.VuText = "TEMP °C";
                        vuMeter1.TextInDial = Smeter_controls.Smeter.temperature_dial;
                        vuMeter1.Level = 0;
                        vuMeter1.Led1Count = 4;
                        vuMeter1.Led2Count = 1;
                        vuMeter1.Led3Count = 2;
                        vuMeter1.LevelMax = 75;
                        vuMeter1.DialTextNegative = Color.Red;
                        vuMeter1.DialTextPositive = Color.Black;
                        vuMeter1.ResumeLayout();
                        break;
                }
                Smeter_controls.Previous_Meter_Configuration = Smeter_controls.selected_mode;
            }
