        private void Display_I_Value()
        {
            int I_value = 0;

            I_value = Smeter_controls.Meter_I_Value / 1000;
            if (I_value > 20)
            {
                I_value = 20;
            }
            vuMeter1.Level = I_value;
            Power_Value_label2.Text = Convert.ToString(Smeter_controls.Meter_I_Value) + " ma";
        }
        private void Display_ALC_Value()
        {
            int vu_display_value = 0;

            vu_display_value = Smeter_controls.VU.VU_Value;
            if (Smeter_controls.VU.New_Session) //The VU value at the beginning of a new PTT is sometimes bogus
            {
                vuMeter1.Level = 0;
                if (Smeter_controls.VU.Ignore_Count++ > Smeter_controls.VU.IGNORE_LIMIT)
                { //Ignore the first IGNORE_LIMIT values
                    Smeter_controls.VU.Ignore_Count = 0;
                    Smeter_controls.VU.New_Session = false;
                }
            }
            else
            {
                if (Smeter_controls.Smeter_Hold_On)
                {
                    if (vu_display_value < Smeter_controls.VU.Previous_Low)
                    {
                        Smeter_controls.VU.Previous_Low = Smeter_controls.VU.Previous_Low - (Smeter_controls.Smeter_decrement + 10);
                        vu_display_value = Smeter_controls.VU.Previous_Low;
                    }
                    else
                    {
                        Smeter_controls.VU.Previous_Low = vu_display_value;
                    }
                }
                vuMeter1.Level = vu_display_value;
            }
        }
        private void Display_Smeter_Value()
        {
            int db_value;
            string smeter_display_value = "S0";
            //int smeter_value = 0;

            Smeter_controls.smeter_display_value = Db_to_Smeter(Smeter_controls.smeter_value) * 10;
            if (Smeter_controls.Display_Smeter_Toggle)
            {
                Manage_Text_Display();
                Smeter_controls.Display_Smeter_Toggle = false;
            }
            if (Smeter_controls.Display_Smeter_Value)
            {
                smeter_display_value = Db_to_Smeter_Display(Smeter_controls.smeter_value);
                Smeter_Display_Value_label.Text = smeter_display_value;
                //MonitorTextBoxText(" Display_Smeter_Value. smeter_display_value: " + smeter_display_value + " smeter_value: " +
                //    Convert.ToString(Smeter_controls.smeter_value));
            }
            if (Smeter_controls.Smeter_Hold_On)
            {
                if (Smeter_controls.smeter_display_value < Smeter_controls.Previous_Low)
                {
                    Smeter_controls.Previous_Low = Smeter_controls.Previous_Low - Smeter_controls.Smeter_decrement;
                    Smeter_controls.smeter_display_value = Smeter_controls.Previous_Low;

                }
                else
                {
                    Smeter_controls.Previous_Low = Smeter_controls.smeter_display_value;
                }
            }
            vuMeter1.Level = Smeter_controls.smeter_display_value;
            IQ_Image_meter.Level = Smeter_controls.smeter_display_value;
            Freq_Cal_Meter.Level = Smeter_controls.smeter_display_value;
            db_value = Smeter_controls.smeter_value;
            Dbm_Value_label9.Text = Convert.ToString(db_value);
        }
        private void Display_Power_Value()
        {
            vuMeter1.Level = Smeter_controls.Power_Value;
            //Power_Value_label2.Text = Convert.ToString(Smeter_controls.Power_Value) + " W";
            //MonitorTextBoxText(" Display_Power_Value: " + Convert.ToString(Smeter_controls.Power_Value));
        }
        private void Display_SWR_Value()
        {
            int meter_display_value = 0;
            float meter_raw = 0.0f;

            meter_raw = Smeter_controls.SWR_Value;
            if (meter_raw > 3.0f)
            {
                meter_raw = 3.0f;
            }
            Smeter_controls.SWR_Fraction = (10 * (Math.Round(meter_raw, 2)));
            Smeter_controls.SWR_Fraction_Part = (int)Smeter_controls.SWR_Fraction;
            if (Smeter_controls.SWR_Fraction_Part >= 10)
            {
                Smeter_controls.SWR_Fraction_Part = Smeter_controls.SWR_Fraction_Part - 10;
            }
            if (Smeter_controls.SWR_Fraction_Part > 20)
            {
                Smeter_controls.SWR_Fraction_Part = Smeter_controls.SWR_Fraction_Part - 20;
            }
            if (Smeter_controls.SWR_Fraction_Part > 30)
            {
                Smeter_controls.SWR_Fraction_Part = Smeter_controls.SWR_Fraction_Part - 30;
            }

            //MonitorTextBoxText(" SWR_Fraction: " + Convert.ToString(Smeter_controls.SWR_Fraction_Part));
            meter_display_value = ((int)Smeter_controls.SWR_Value - 1) + Smeter_controls.SWR_Fraction_Part;
            if (meter_display_value >= 20)
            {
                meter_display_value = 20;
            }
            vuMeter1.Level = meter_display_value;
            //MonitorTextBoxText(" vuMeter1.Level: " + Convert.ToString(vuMeter1.Level));
            Power_Value_label2.Text = SWR_Value_label43.Text;
        }
        private void Display_Temperature_Value()
        {
            if (Master_Controls.QRP_Mode)
            {
                vuMeter1.Level = Smeter_controls.Proficio_temperature;
            }
            else
            {
                if (Smeter_controls.Preferred_Temperature_Mode == Smeter_controls.PREFERRED_TEMPERATURE_AMPLIFIER)
                {
                    if (G_Potentia_Temparature_Average > 15)
                    {
                        vuMeter1.Level = G_Potentia_Temparature_Average;
                    }
                }
                else
                {
                    vuMeter1.Level = Smeter_controls.Proficio_temperature;
                }
            }
            Power_Value_label2.Text = Convert.ToString(vuMeter1.Level) + " °C";

        }
        private void Smeter_Timer_Tick(object sender, EventArgs e)
        {
            Size led_size = new Size();
            if (!Master_Controls.Transmit_Mode)
            {
                if (Smeter_controls.Display_Mode != Smeter_controls.S_METER_MODE)
                {
                    MonitorTextBoxText(" Smeter_Timer_Tick: Smeter_controls.Display_Mode: " + 
                        Convert.ToString(Smeter_controls.Display_Mode));
                    Smeter_controls.Display_Power_Value = false;
                    vuMeter1.MeterScale = VU_MeterLibrary.MeterScale.Analog;
                    led_size.Width = 3;
                    led_size.Height = 14;
                    vuMeter1.LedSize = led_size;
                    vuMeter1.SuspendLayout();
                    vuMeter1.VuText = "S Meter";
                    vuMeter1.TextInDial = Smeter_controls.Smeter.smeter_dial;
                    vuMeter1.Led1Count = 9;
                    vuMeter1.Led2Count = 0;
                    vuMeter1.Led3Count = 5;
                    vuMeter1.LevelMax = 150;
                    vuMeter1.Led1ColorOff = Color.Black;
                    vuMeter1.Led1ColorOn = Color.LimeGreen;
                    vuMeter1.Led2ColorOff = Color.Black;
                    vuMeter1.Led2ColorOn = Color.Yellow;
                    vuMeter1.Led3ColorOff = Color.Black;
                    vuMeter1.Led3ColorOn = Color.Red;
                    vuMeter1.DialTextNegative = Color.Red;
                    vuMeter1.DialTextPositive = Color.Black;
                    vuMeter1.ShowTextInDial = true;
                    vuMeter1.ResumeLayout();
                    Smeter_controls.Display_Mode = Smeter_controls.S_METER_MODE;
                    Smeter_controls.Text_Display_Dbm_mode = Manage_Text_Display();
                }
            }
            else
            {
                if (Smeter_controls.Text_Display_Dbm_mode == true)
                {
                    MonitorTextBoxText(" Smeter_Timer_Tick: Smeter_controls.Text_Display_Dbm_mode: " 
                        + Convert.ToString(Smeter_controls.Text_Display_Dbm_mode));
                    Smeter_controls.Text_Display_Dbm_mode = Manage_Text_Display();
                    Configure_Meter();
                }
            }
            if (Smeter_controls.Previous_Meter_Configuration != Smeter_controls.selected_mode)
            {
                MonitorTextBoxText(" Smeter_Timer_Tick: Smeter_controls.Previous_Meter_Configuration: "
                        + Convert.ToString(Smeter_controls.Previous_Meter_Configuration));
                Configure_Meter();
            }

            switch (Smeter_controls.Display_Mode)
            {
                case Smeter_controls.ALC_MODE:
                    Display_ALC_Value();
                    break;
                case Smeter_controls.POWER_MODE:
                    Display_Power_Value();
                    break;
                case Smeter_controls.SWR_MODE:
                    Display_SWR_Value();
                    break;
                case Smeter_controls.S_METER_MODE:
                    Display_Smeter_Value();
                    break;
                case Smeter_controls.I_MODE:
                    Display_I_Value();
                    break;
                case Smeter_controls.TEMPERATURE_MODE:
                    Display_Temperature_Value();
                    break;
            }
        }
        private void Smeter_Hold_Time_button_Click(object sender, EventArgs e)
        {
            Smeter_controls.smeter_hold_time_index = Smeter_controls.smeter_hold;
            switch (Smeter_controls.smeter_hold)
            {
                case 0:
                    Smeter_controls.smeter_hold_time = 10;
                    Smeter_Hold_Time_button.Text = Convert.ToString(Smeter_controls.smeter_hold_time);
                    Smeter_Timer.Interval = Smeter_controls.smeter_hold_time;
                    break;
                case 1:
                    Smeter_controls.smeter_hold_time = 20;
                    Smeter_Hold_Time_button.Text = Convert.ToString(Smeter_controls.smeter_hold_time);
                    Smeter_Timer.Interval = Smeter_controls.smeter_hold_time;
                    break;
                case 2:
                    Smeter_controls.smeter_hold_time = 30;
                    Smeter_Hold_Time_button.Text = Convert.ToString(Smeter_controls.smeter_hold_time);
                    Smeter_Timer.Interval = Smeter_controls.smeter_hold_time;
                    break;
                case 3:
                    Smeter_controls.smeter_hold_time = 50;
                    Smeter_Hold_Time_button.Text = Convert.ToString(Smeter_controls.smeter_hold_time);
                    Smeter_Timer.Interval = Smeter_controls.smeter_hold_time;
                    break;
                case 4:
                    Smeter_controls.smeter_hold_time = 100;
                    Smeter_Hold_Time_button.Text = Convert.ToString(Smeter_controls.smeter_hold_time);
                    Smeter_Timer.Interval = Smeter_controls.smeter_hold_time;
                    break;
            }
            Smeter_controls.smeter_hold++;
            if (Smeter_controls.smeter_hold > 4)
            {
                Smeter_controls.smeter_hold = 0;
            }
        }
