        private void IQBD_MouseWheel(Int32 e)
        {
            Int32 n = e;
            if (Master_Controls.isLoading == true) return;

            if (IQ_Controls.IQ_Band_Selected)
            {
                IQ_Controls.IQ_Offset += n;
                if (IQ_Controls.IQ_Offset > 200) IQ_Controls.IQ_Offset = 200;
                if (IQ_Controls.IQ_Offset < -200) IQ_Controls.IQ_Offset = -200;
                IQBD_TX_hScrollBar.Value = IQ_Controls.IQ_Offset;
                if (IQ_Controls.IQ_tx_mode_active)
                {
                    MonitorTextBoxText(" IQBD_MouseWheel IQ_Controls.IQ_Offset:  " + (short)IQ_Controls.IQ_Offset);
                    oCode.SendCommand32(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_OFFSET, (IQ_Controls.IQ_Offset));
                    IQ_TX_Label.Text = "TX IQ OFFSET: " + Convert.ToString(IQ_Controls.IQ_Offset);
                }
            }
            else
            {
                DialogResult ret = MessageBox.Show("Select a Band", "MSCC",
                              MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
        }
        private void IQBD_TX_Power_hScrollBar_Scroll(object sender, ScrollEventArgs e)
        {
            int value;

            if (Master_Controls.isLoading == true) return;
            value = IQBD_TX_Power_hScrollBar.Value;
            if (value == IQ_Controls.Tune_power) return;
            if (IQ_Controls.IQ_Band_Selected)
            {
                IQ_TX_Button.Text = "POWER: " + Convert.ToString(value);
                IQ_Controls.Tune_power = (short)value;
                oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_TUNE_POWER, (short)value);
            }
            else
            {
                DialogResult ret = MessageBox.Show("Select a Band", "MSCC",
                            MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
        }
        private bool IQBD_TX_Tune(bool on_off)
        {
            bool status = false;
            if (IQ_Controls.IQ_Band_Selected)
            {
                if (Master_Controls.Tuning_Mode == false && on_off == true)
                {
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_RX_TX, IQ_Controls.TX_IQBD);
                    IQBD_Set_Band(IQ_Controls.Selected_Band, true);
                    //oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 1);
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, Power_Controls.Mode.TUNE_mode);
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 1);
                    Set_Button_Color(true, Tune_vButton2);
                    Set_Button_Color(true, buttTune);
                    Set_Button_Color(true, IQBD_TX_Tune_button,"TX ON");
                    IQ_Controls.IQ_tx_mode_active = true;
                    Master_Controls.Tuning_Mode = true;
                    Master_Controls.Transmit_Mode = true;
                    AM_Carrier_hScrollBar1.Enabled = false;
                    Power_hScrollBar1.Enabled = false;
                    CW_Power_hScrollBar1.Enabled = false;
                    GEM_Group_Box.Enabled = false;
                    //Manage_Fortis_Buttons(false);
                    QRP_Button.Enabled = false;
                    Monitor_button8.Enabled = false;
                    //IQBD_Auto_button8.Enabled = false;
                    IQBD_Reset_button8.Enabled = false;
                    IQ_TX_Band_button.Enabled = false;
                    IQBD_Meter.Enabled = false;
                    IQBD_Meter.Visible = false;
                    IQBD_Monitor_label.Visible = false;
                    IQBD_TX_hScrollBar.Enabled = true;
                    IQBD_TX_hScrollBar.Visible = true;
                    //Antenna_Switch_groupBox.Enabled = false;
                    Geminus_Select_Band_button.Enabled = false;
                    status = true;
                }
                else
                {
                    if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                    {
                        oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    }
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                    IQBD_Set_Band(IQ_Controls.Selected_Band, false);
                    Set_Button_Color(false, Tune_vButton2);
                    Set_Button_Color(false, buttTune);
                    Set_Button_Color(false, IQBD_TX_Tune_button, "TX OFF");
                    IQ_Controls.IQ_tx_mode_active = false;
                    Master_Controls.Tuning_Mode = false;
                    Master_Controls.Transmit_Mode = false;
                    AM_Carrier_hScrollBar1.Enabled = true;
                    Power_hScrollBar1.Enabled = true;
                    CW_Power_hScrollBar1.Enabled = true;
                    GEM_Group_Box.Enabled = true;
                    QRP_Button.Enabled = true;
                    Monitor_button8.Enabled = true;
                    //Antenna_Switch_groupBox.Enabled = true;
                    IQBD_Reset_button8.Enabled = true;
                    IQ_TX_Band_button.Enabled = true;
                    Geminus_Select_Band_button.Enabled = true;
                    status = true;
                }
            }
            else
            {
                DialogResult ret = MessageBox.Show("SELECT A BAND", "MSCC",
                          MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                status = false;
            }
            return status;
        }
        private void IQBD_TX_Tune_button_Click(object sender, EventArgs e)
        {
            bool status = false;

            if (!IQ_Controls.IQ_TX_ON)
            {
                status = IQBD_TX_Tune(true);
                if (status == true)
                {
                    IQ_Controls.IQ_TX_ON = true;
                }
            }
            else
            {
                status = IQBD_TX_Tune(false);
                if(status == true && IQ_Controls.IQ_TX_ON)
                {
                    IQ_Controls.IQ_TX_ON = false;
                    DialogResult ret = MessageBox.Show("APPLY THE CURRENT I/Q VALUE?", "MSCC",
                      MessageBoxButtons.OKCancel, MessageBoxIcon.Asterisk, MessageBoxDefaultButton.Button2);
                    if (ret == DialogResult.OK)
                    {
                        oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_COMMIT_IQ, 0);
                        IQ_Controls.IQ_Server_Calibrating = true;
                    }
                }
            }
        }
