        private void IQBD_Manage_Calibrate(int band, bool start)
        {
            byte[] buf = new byte[2];
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_IQBD_MONITOR;
            if (start)
            {
                //oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                IQ_Controls.Previous_QRP_Mode = Master_Controls.QRP_Mode;
                MonitorTextBoxText(" Previous_QRP_Mode: " + Convert.ToString(IQ_Controls.Previous_QRP_Mode));
                if (Master_Controls.Tuning_Mode || Master_Controls.Transmit_Mode)
                {
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_TX_ON, 0);
                    if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                    {
                        oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    }
                }
                buf[1] = 1;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                                        Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_RX_TX, IQ_Controls.TX_IQBD);
                IQBD_Set_Band(band, true);
                IQBD_Manage_TX(true);
                IQ_Controls.IQ_tx_mode_active = true;
                //IQBD_hScrollBar2.Value = Power_Controls.TUNE_Power;
                oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_RX_TX, IQ_Controls.TX_IQBD);
                IQ_Controls.IQBD_MONITOR = true;
                IQBD_TX_Tune_button.Enabled = false;
            }
            else
            {
                buf[1] = 0;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                                        Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                IQ_Controls.IQ_Server_Calibrating = false;
                IQ_Controls.IQBD_MONITOR = false;
                IQBD_TX_Tune_button.Enabled = true;
                oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_TUNE, 0);
                /*switch (IQ_Controls.Previous_QRP_Mode)
                {
                    case true:
                        oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                        break;
                    default:
                        oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 1);
                        break;
                }*/
            }
        }
        private void IQBD_Manage_TX(bool on_off)
        {
            switch (on_off)
            {
                case true:
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 1);
                    IQ_Controls.Tuning_Mode = true;
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_TUNE, 1);
                    Master_Controls.Transmit_Mode = true;
                    break;
                case false:
                    IQ_Controls.Tuning_Mode = false;
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_TUNE, 0);
                    Master_Controls.Transmit_Mode = false;
                    if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                    {
                        oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    }
                    break;
            }
        }
        private void IQBD_Auto_button8_Click(object sender, EventArgs e)
        {
            if (IQ_Controls.IQ_Band_Selected)
            {
                if (IQ_Controls.Calibrating == false)
                {
                    Set_Button_Color(true, IQBD_Auto_button8);
                    IQ_Controls.Calibrating = true;
                    //oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                    IQBD_Manage_Calibrate(IQ_Controls.Selected_Band, true);
                    Calibration_Band_button8.Enabled = false;
                    IQBD_Monitor_label.Text = "WAIT";
                    Set_Label_Color(true, IQBD_Monitor_label);
                    IQBD_TX_hScrollBar.Value = 0;
                    IQ_TX_Band_button.Enabled = false;
                    IQBD_Reset_button8.Enabled = false;
                    IQBD_Meter.Visible = true;
                    IQBD_Meter.Enabled = true;
                    IQBD_Monitor_label.Visible = true;
                    IQBD_Monitor_label.Enabled = true;
                }
                else
                {
                    byte[] buf = new byte[2];
                    buf[0] = Master_Controls.Extended_Commands.CMD_SET_IQBD_MONITOR;
                    IQBD_Manage_TX(false);
                    IQ_TX_Band_button.Enabled = true;
                    Thread.Sleep(10);
                    IQBD_Calibrate_Band(0, false);
                    IQ_Controls.IQ_Server_Calibrating = false;
                    IQ_Controls.Cool_Down = 0;
                    IQBD_Auto_button8.Text = "IQBD INTERNAL";
                    Set_Button_Color(false, IQBD_Auto_button8);
                    IQ_Controls.Calibrating = false;
                    Set_Label_Color(false, IQBD_Monitor_label);
                    IQBD_Monitor_label.Text = "0";
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_RX_TX, IQ_Controls.RX_IQBD);
                    buf[1] = 0;
                    oCode.SendCommand_MultiByte(txsocket, txtarget,
                                            Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                    Calibration_Band_button8.Enabled = true;
                    IQBD_Meter.Level = 0;
                    IQBD_Reset_button8.Enabled = true;
                    IQBD_Meter.Visible = false;
                    IQBD_Meter.Enabled = false;
                    IQBD_Monitor_label.Visible = false;
                    IQBD_Monitor_label.Enabled = false;
                }
            }
            else
            {
                _ = MessageBox.Show("SELECT A CALIBRATION BAND", "MSCC",
                       MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
        }
        private void IQBD_Set_Band(int band, bool on_off)
        {
            String On_Off;

            switch (on_off)
            {
                case true:
                    On_Off = " TX ON";
                    Set_Button_Color(true, IQBD_Auto_button8);
                    break;
                default:
                    On_Off = " TX OFF";
                    Set_Button_Color(false, IQBD_Auto_button8);
                    break;
            }
            switch (band)
            {
                case 2200:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 2200);
                    IQBD_Auto_button8.Text = "2200M" + On_Off;
                    break;
                case 630:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 630);
                    IQBD_Auto_button8.Text = "630M" + On_Off;
                    break;
                case 160:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 160);
                    IQBD_Auto_button8.Text = "160M" + On_Off;
                    break;
                case 80:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 80);
                    IQBD_Auto_button8.Text = "80M" + On_Off;
                    break;
                case 60:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 60);
                    IQBD_Auto_button8.Text = "60M" + On_Off;
                    break;
                case 40:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 40);
                    IQBD_Auto_button8.Text = "40M" + On_Off;
                    break;
                case 30:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 30);
                    IQBD_Auto_button8.Text = "30M" + On_Off;
                    break;
                case 20:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 20);
                    IQBD_Auto_button8.Text = "20M" + On_Off;
                    break;
                case 17:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 17);
                    IQBD_Auto_button8.Text = "17M" + On_Off;
                    break;
                case 15:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 15);
                    IQBD_Auto_button8.Text = "15M" + On_Off;
                    break;
                case 12:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 12);
                    IQBD_Auto_button8.Text = "12M" + On_Off;
                    break;
                case 10:
                    oCode.SendCommand(txsocket, txtarget, IQ_Controls.CMD_SET_IQ_BAND, 10);
                    IQBD_Auto_button8.Text = "10M" + On_Off;
                    break;
                default:
                    break;
            }
        }
        private int IQBD_Selection_Index_To_Band(int index)
        {
            int band = 0;
            switch (index)
            {
                case 0:
                    band = 160;
                    break;
                case 1:
                    band = 80;
                    break;
                case 2:
                    band = 60;
                    break;
                case 3:
                    band = 40;
                    break;
                case 4:
                    band = 30;
                    break;
                case 5:
                    band = 20;
                    break;
                case 6:
                    band = 17;
                    break;
                case 7:
                    band = 15;
                    break;
                case 8:
                    band = 12;
                    break;
                case 9:
                    band = 10;
                    break;
            }
            return band;
        }
        private int IQBD_Geminus_Selection_Index_To_Band(int index)
        {
            int band = 0;
            switch (index)
            {
                case 0:
                    band = 2200;
                    break;
                case 1:
                    band = 630;
                    break;
            }
            return band;
        }
        private void IQBD_Calibrate_Band(int band, bool start)
        {
            byte[] buf = new byte[2];
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_IQBD_MONITOR;
            if (start)
            {
                //oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                IQ_Controls.Previous_QRP_Mode = Master_Controls.QRP_Mode;
                MonitorTextBoxText(" Previous_QRP_Mode: " + Convert.ToString(IQ_Controls.Previous_QRP_Mode));
                if (Master_Controls.Tuning_Mode || Master_Controls.Transmit_Mode)
                {
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_TX_ON, 0);
                    if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                    {
                        oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    }
                }
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, Power_Controls.Mode.TUNE_mode);
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                IQ_Controls.IQ_tx_mode_active = true;
                //IQBD_hScrollBar2.Value = Power_Controls.TUNE_Power;
                oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_RX_TX, IQ_Controls.TX_IQBD);
                //IQBD_Calibration_Band(band);
                buf[1] = 1;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                                        Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                IQ_Controls.IQBD_MONITOR = true;
                IQBD_TX_Tune_button.Enabled = false;
            }
            else
            {
                buf[1] = 0;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                                        Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                IQ_Controls.IQ_Server_Calibrating = false;
                IQ_Controls.IQBD_MONITOR = false;
                IQBD_TX_Tune_button.Enabled = true;
                oCode.SendCommand(txsocket, txtarget, IQ_Controls.IQ_CALIBRATION_TUNE, 0);
                /*switch (IQ_Controls.Previous_QRP_Mode)
                {
                    case true:
                        oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 0);
                        break;
                    default:
                        oCode.SendCommand(txsocket, txtarget, Master_Controls.CMD_SET_PA_BYPASS, 1);
                        break;
                }*/
            }
        }
        private void IQ_TX_Band_button_Click(object sender, EventArgs e)
        {
            switch (IQ_Controls.Band_Selection_Index)
            {
                case 0:
                    IQ_TX_Band_button.Text = "160M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B160.Freq);
                    break;
                case 1:
                    IQ_TX_Band_button.Text = "80M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B80.Freq);
                    break;
                case 2:
                    IQ_TX_Band_button.Text = "60M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B60.Freq);
                    break;
                case 3:
                    IQ_TX_Band_button.Text = "40M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B40.Freq);
                    break;
                case 4:
                    IQ_TX_Band_button.Text = "30M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B30.Freq);
                    break;
                case 5:
                    IQ_TX_Band_button.Text = "20M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B20.Freq);
                    break;
                case 6:
                    IQ_TX_Band_button.Text = "17M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B17.Freq);
                    break;
                case 7:
                    IQ_TX_Band_button.Text = "15M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B15.Freq);
                    break;
                case 8:
                    IQ_TX_Band_button.Text = "12M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B12.Freq);
                    break;
                case 9:
                    IQ_TX_Band_button.Text = "10M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, VFOA_Last_Used.Last_used.B10.Freq);
                    break;
            }
            IQ_Controls.Selected_Band = IQBD_Selection_Index_To_Band(IQ_Controls.Band_Selection_Index);
            IQ_Controls.Band_Selection_Index++;
            if (IQ_Controls.Band_Selection_Index > 9)
            {
                IQ_Controls.Band_Selection_Index = 0;
            }
            Set_Button_Color(false, IQBD_Auto_button8, IQ_TX_Band_button.Text);
            IQBD_TX_Power_hScrollBar.Enabled = true;
            IQBD_TX_hScrollBar.Enabled = true;
            IQ_Controls.IQ_Band_Selected = true;
        }
