        private void Set_Antenna_Switch()
        {
            byte[] buf = new byte[2];

            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 0;
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            if ((Transceiver_Model_Settings.Antenna_Switch_Control.Previous_Band != VFOA_Master_Controls.current_band) ||
                                                                            Transceiver_Model_Settings.Antenna_Switch_Control.State_Change)
            {
                switch (VFOA_Master_Controls.current_band)
                {
                    case 160:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M160)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 80:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M80)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 60:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M60)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 40:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M40)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 30:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M30)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 20:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M20)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 17:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M17)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 15:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M15)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 12:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M12)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                    case 10:
                        if (Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M10)
                        {
                            Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value = 1;
                        }
                        break;
                }
                buf[1] = Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                       Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
                Transceiver_Model_Settings.Antenna_Switch_Control.Previous_Band = (byte)VFOA_Master_Controls.current_band;
                Transceiver_Model_Settings.Antenna_Switch_Control.State_Change = false;
            }
        }
