            else
            {
                Transceiver_Model_Settings.Antenna_Switch_Control.Switch_State.M60 = false;
            }
            Transceiver_Model_Settings.Antenna_Switch_Control.State_Change = true;
        }
        */
        #endregion Antenna_Switch

