        private void Calibration_Band_button8_Click(object sender, EventArgs e)
        {
            int Power_Value = 100;
            if (Master_Controls.isLoading) return;

            if (Transceiver_Model_Settings.Fortis_Devices != Transceiver_Model_Settings.FORTIS_GEMINUS)
            {
                MonitorTextBoxText(" Calibration_Band_button8_Click. STARTED");
                switch (IQ_Controls.Calibration_Band_Count)
                {
                    case 0:
                        Amplifier_Power_Controls.Band = 160;
                        Calibration_Band_button8.Text = "160M";
                        AMP_label57.Text = "160M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B160]);
                        break;
                    case 1:
                        Amplifier_Power_Controls.Band = 80;
                        Calibration_Band_button8.Text = "80M";
                        AMP_label57.Text = "80M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B80]);
                        break;
                    case 2:
                        Amplifier_Power_Controls.Band = 60;
                        Calibration_Band_button8.Text = "60M";
                        AMP_label57.Text = "60M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B60]);
                        break;
                    case 3:
                        Amplifier_Power_Controls.Band = 40;
                        Calibration_Band_button8.Text = "40M";
                        AMP_label57.Text = "40M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                             IQ_Controls.iq_calibration_freqs[IQ_Controls.B40]);
                        break;
                    case 4:
                        Amplifier_Power_Controls.Band = 30;
                        Calibration_Band_button8.Text = "30M";
                        AMP_label57.Text = "30M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B30]);
                        break;
                    case 5:
                        Amplifier_Power_Controls.Band = 20;
                        Calibration_Band_button8.Text = "20M";
                        AMP_label57.Text = "20M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                             IQ_Controls.iq_calibration_freqs[IQ_Controls.B20]);
                        break;
                    case 6:
                        Amplifier_Power_Controls.Band = 17;
                        Calibration_Band_button8.Text = "17M";
                        AMP_label57.Text = "17M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B17]);
                        break;
                    case 7:
                        Amplifier_Power_Controls.Band = 15;
                        Calibration_Band_button8.Text = "15M";
                        AMP_label57.Text = "15M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B15]);
                        break;
                    case 8:
                        Amplifier_Power_Controls.Band = 12;
                        Calibration_Band_button8.Text = "12M";
                        AMP_label57.Text = "12M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B12]);
                        break;
                    case 9:
                        Amplifier_Power_Controls.Band = 10;
                        Calibration_Band_button8.Text = "10M";
                        AMP_label57.Text = "10M";
                        oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                            IQ_Controls.iq_calibration_freqs[IQ_Controls.B10]);
                        break;
                }
                IQ_Controls.Calibration_Band_Count++;
                if (IQ_Controls.Calibration_Band_Count > 9)
                {
                    IQ_Controls.Calibration_Band_Count = 0;
                }

            }
            else
            {
                if (IQ_Controls.Geminus_band_toggle)
                {
                    Amplifier_Power_Controls.Band = 630;
                    Calibration_Band_button8.Text = "630M";
                    AMP_label57.Text = "630m";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                        IQ_Controls.iq_calibration_freqs[IQ_Controls.B630]);
                    IQ_Controls.Geminus_band_toggle = false;
                }
                else
                {
                    Amplifier_Power_Controls.Band = 2200;
                    Calibration_Band_button8.Text = "2200M";
                    AMP_label57.Text = "2200M";
                    oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ,
                        IQ_Controls.iq_calibration_freqs[IQ_Controls.B2200]);
                    IQ_Controls.Geminus_band_toggle = true;
                }
            }
            oCode.SendCommand(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_AMPLIFIER_INITIALIZE,
                                                                                   (short)Amplifier_Power_Controls.Band);
            oCode.SendCommand(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_AMPLIFIER_POWER,
                                                                            (short)Power_Value);
            Amplifier_Power_Controls.PA_Band_Selected = true;
            Amplifier_Power_Controls.PA_Calibration_Increment = 0;
            PA_hScrollBar.Value = -99;
            //oCode.SendCommand32(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_POTENTIA_CALIBRATION,
            //        Amplifier_Power_Controls.PA_Calibration_Increment);
            MonitorTextBoxText(" Calibration_Band_button8_Click. FINISHED");
        }
        private void PA_Manual_Calibrate()
        {
            short power = 0;
            short mode_number = 0;

            MonitorTextBoxText(" PA_Manual_Calibrate. STARTED");
            if (Amplifier_Power_Controls.PA_Band_Selected)
            {
                if (!Master_Controls.TX_Inhibited)
                {
                    if (Master_Controls.Tuning_Mode == false)
                    {
                        if (PA_Check_Proficio_Calibration(Amplifier_Power_Controls.Band))
                        {
                            PA_hScrollBar.Visible = true;
                            Amplifier_Power_Controls.PA_Not_Calibrated_Count = 0;
                            Amplifier_Power_Controls.PA_Calibrating = true;
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 1);
                            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, Power_Controls.Mode.TUNE_mode);
                            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 1);
                            Amplifier_Power_Controls.PA_Calibrated = false;
                            Set_Button_Color(true, PA_Calibrate_button);
                            Set_Button_Color(true, buttTune);
                            Master_Controls.Tuning_Mode = true;
                            Master_Controls.Transmit_Mode = true;
                            AM_Carrier_hScrollBar1.Enabled = false;
                            Power_hScrollBar1.Enabled = false;
                            CW_Power_hScrollBar1.Enabled = false;
                            button1.Enabled = false;
                            Set_Button_Color(true, Tune_vButton2);
                            IQBD_TX_groupBox.Enabled = false;
                            Solidus_Bias_button8.Enabled = false;
                            Calibration_Band_button8.Enabled = false;
                            PA_Reset_button8.Enabled = false;
                            //Antenna_Switch_groupBox.Enabled = false;
                            Amplifier_Power_Controls.PA_Calibration_Increment = -99;
                            oCode.SendCommand32(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_POTENTIA_CALIBRATION,
                                                                            Amplifier_Power_Controls.PA_Calibration_Increment);
                            PA_hScrollBar.Value = -99;
                            PA_Display_Power_Timer.Enabled = true;
                            PA_Display_Power_Timer.Start();
                            //PA_Calibrate_Timer.Start();
                        }
                        else
                        {
                            MessageBox.Show("THE TRANSCEIVER HAS NOT BEEN CALIBRATED FOR THIS BAND", "MSCC",
                                                        MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                        }
                    }
                    else
                    {
                        Amplifier_Power_Controls.PA_Calibrating = false;
                        PA_hScrollBar.Visible = false;
                        if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                        {
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                        }
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                        power = get_previous_power(VFOA_Master_Controls.current_band);
                        mode_number = Convert_mode_char_to_digit(VFOA_Last_Used.Last_used.Current_mode);
                        MonitorTextBoxText(" Tune -> Current Band: " + VFOA_Master_Controls.current_band +
                            " Current Mode Number: " + mode_number);
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                        Set_Button_Color(false, buttTune);
                        Master_Controls.Tuning_Mode = false;
                        Master_Controls.Transmit_Mode = false;
                        AM_Carrier_hScrollBar1.Enabled = true;
                        Power_hScrollBar1.Enabled = true;
                        CW_Power_hScrollBar1.Enabled = true;
                        button1.Enabled = true;
                        Set_Button_Color(false, Tune_vButton2);
                        IQBD_TX_groupBox.Enabled = true;
                        Solidus_Bias_button8.Enabled = true;
                        Calibration_Band_button8.Enabled = true;
                        PA_Reset_button8.Enabled = true;
                        //Antenna_Switch_groupBox.Enabled = true;
                        Set_Button_Color(false, PA_Calibrate_button);
                        PA_Display_Power_Timer.Enabled = false;
                        PA_Display_Power_Timer.Stop();
                    }
                }
            }
            else
            {
                MessageBox.Show("SELECT A BAND", "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
            MonitorTextBoxText(" PA_Manual_Calibrate. FINISHED");
        }
