                            AM_Carrier_hScrollBar1.Enabled = false;
                            Power_hScrollBar1.Enabled = false;
                            CW_Power_hScrollBar1.Enabled = false;
                            button1.Enabled = false;
                            Set_Button_Color(true, Tune_vButton2);
                            IQBD_TX_groupBox.Enabled = false;
                            Solidus_Bias_button8.Enabled = false;
                            Calibration_Band_button8.Enabled = false;
                            PA_Reset_button8.Enabled = false;
                            //Antenna_Switch_groupBox.Enabled = false;
                            Amplifier_Power_Controls.PA_Calibration_Increment = -99;
                            oCode.SendCommand32(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_POTENTIA_CALIBRATION,
                                                                            Amplifier_Power_Controls.PA_Calibration_Increment);
                            PA_Calibrate_Timer.Start();
                        }
                        else
                        {
                            MessageBox.Show("THE TRANSCEIVER HAS NOT BEEN CALIBRATED FOR THIS BAND", "MSCC",
                                                        MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                        }
                    }
                    else
                    {
                        PA_Calibrate_Timer.Enabled = false;
                        PA_Calibrate_Timer.Stop();
                        Amplifier_Power_Controls.PA_Calibrating = false;
                        if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                        {
                            oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                        }
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                        power = get_previous_power(VFOA_Master_Controls.current_band);
                        mode_number = Convert_mode_char_to_digit(VFOA_Last_Used.Last_used.Current_mode);
                        MonitorTextBoxText(" Tune -> Current Band: " + VFOA_Master_Controls.current_band +
                            " Current Mode Number: " + mode_number);
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                        Set_Button_Color(false, buttTune);
                        Master_Controls.Tuning_Mode = false;
                        Master_Controls.Transmit_Mode = false;
                        AM_Carrier_hScrollBar1.Enabled = true;
                        Power_hScrollBar1.Enabled = true;
                        CW_Power_hScrollBar1.Enabled = true;
                        button1.Enabled = true;
                        Set_Button_Color(false, Tune_vButton2);
                        IQBD_TX_groupBox.Enabled = true;
                        Solidus_Bias_button8.Enabled = true;
                        Calibration_Band_button8.Enabled = true;
                        PA_Reset_button8.Enabled = true;
                        //Antenna_Switch_groupBox.Enabled = true;
                        Set_Button_Color(false, PA_Calibrate_button, "CALIBRATE");
                        if (Amplifier_Power_Controls.PA_Calibrated == false)
                        {
                            result_message = "CALIBRATION TERMINATED. THE CURRENT BAND IS SET TO: " +
                                                                        Convert.ToString(Amplifier_Power_Controls.Step_Display);
                            MessageBox.Show(result_message, "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                        }
                    }
                }
            }
            else
            {
                MessageBox.Show("SELECT A BAND", "MSCC", MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
            MonitorTextBoxText(" PA_Auto_Calibrate. FINISHED ");
        }
