        private bool PA_Check_Proficio_Calibration(int band)
        {
            bool calibrated = false;
            byte band_calibrated = 0;
            switch (band)
            {
                case 2200:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_2200;
                    break;
                case 630:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_630;
                    break;
                case 160:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_160;
                    break;
                case 80:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_80;
                    break;
                case 60:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_60;
                    break;
                case 40:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_40;
                    break;
                case 30:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_30;
                    break;
                case 20:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_20;
                    break;
                case 17:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_17;
                    break;
                case 15:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_15;
                    break;
                case 12:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_12;
                    break;
                case 10:
                    band_calibrated = Power_Calibration_Controls.Calibrated_Bands.B_10;
                    break;
            }
            if (band_calibrated == 1)
            {
                calibrated = true;
            }
            return calibrated;
        }
        private void PA_Calibrate_Timer_Tick(object sender, EventArgs e)
        {
            short power = 0;
            short mode_number = 0;

            Amplifier_Power_Controls.PA_Calibration_Increment++; //This a decreasing negative number
            Amplifier_Power_Controls.Step_Display = 100 + Amplifier_Power_Controls.PA_Calibration_Increment;
            Power_calibration_label58.Text = "STEP: " + Convert.ToString(Amplifier_Power_Controls.Step_Display);
            oCode.SendCommand32(txsocket, txtarget, Amplifier_Power_Controls.CMD_SET_POTENTIA_CALIBRATION,
                    Amplifier_Power_Controls.PA_Calibration_Increment);
            MonitorTextBoxText(" PA_Calibrate_Timer_Tick -> Amplifier_Power_Controls.PA_Power: " +
                Amplifier_Power_Controls.PA_Power);
            if (Amplifier_Power_Controls.PA_Power >= Amplifier_Power_Controls.PA_Calibration_Power_Limit)
            {
                MonitorTextBoxText(" PA_Calibrate_Timer_Tick -> Amplifier_Power_Controls.PA_Power: " +
                    Amplifier_Power_Controls.PA_Power);
                Amplifier_Power_Controls.PA_Calibrated_Value = Amplifier_Power_Controls.PA_Power;
                Set_Button_Color(false, PA_Calibrate_button, "CALIBRATED");
                Amplifier_Power_Controls.PA_Calibrated = true;
                Master_Controls.Tuning_Mode = false;
                if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                {
                    oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                }
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                power = get_previous_power(VFOA_Master_Controls.current_band);
                mode_number = Convert_mode_char_to_digit(VFOA_Last_Used.Last_used.Current_mode);
                MonitorTextBoxText(" PA_Calibrate_Timer_Tick -> Current Band: " + VFOA_Master_Controls.current_band +
                    " Current Mode Number: " + mode_number);
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                Set_Button_Color(false, buttTune);
                Master_Controls.Tuning_Mode = false;
                Master_Controls.Transmit_Mode = false;
                AM_Carrier_hScrollBar1.Enabled = true;
                Power_hScrollBar1.Enabled = true;
                CW_Power_hScrollBar1.Enabled = true;
                button1.Enabled = true;
                Set_Button_Color(false, Tune_vButton2);
                IQBD_TX_groupBox.Enabled = true;
                Solidus_Bias_button8.Enabled = true;
                Calibration_Band_button8.Enabled = true;
                Convert.ToString(Amplifier_Power_Controls.PA_Calibrated_Value);
                PA_Reset_button8.Enabled = true;
                Amplifier_Power_Controls.PA_Calibrating = false;
                PA_Calibrate_Timer.Enabled = false;
                PA_Calibrate_Timer.Stop();
            }
            else
            {
                if (Amplifier_Power_Controls.PA_Calibration_Increment > Amplifier_Power_Controls.PA_MAX_CALIBRATION_COUNT)
                {
                    PA_Calibrate_button.Text = "CALIBRATE";
                    Amplifier_Power_Controls.PA_Calibrating = false;
                    Set_Button_Color(false, PA_Calibrate_button);
                    Master_Controls.Tuning_Mode = false;
                    if (!Transceiver_Model_Settings.Volume_Settings.Speaker_MutED)
                    {
                        oCode.SendCommand(txsocket, txtarget, Volume_Controls.CMD_SET_SPEAKER_MUTE, 0);
                    }
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_RIG_TUNE, 0);
                    power = get_previous_power(VFOA_Master_Controls.current_band);
                    mode_number = Convert_mode_char_to_digit(VFOA_Last_Used.Last_used.Current_mode);
                    MonitorTextBoxText(" PA_Calibrate_Timer_Tick -> Current Band: " + VFOA_Master_Controls.current_band +
                        " Current Mode Number: " + mode_number);
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                    Set_Button_Color(false, buttTune);
                    Master_Controls.Tuning_Mode = false;
                    Master_Controls.Transmit_Mode = false;
                    AM_Carrier_hScrollBar1.Enabled = true;
                    Power_hScrollBar1.Enabled = true;
                    CW_Power_hScrollBar1.Enabled = true;
                    button1.Enabled = true;
                    Set_Button_Color(false, Tune_vButton2);
                    IQBD_TX_groupBox.Enabled = true;
                    Solidus_Bias_button8.Enabled = true;
                    Calibration_Band_button8.Enabled = true;
                    PA_Reset_button8.Enabled = true;
                    PA_Calibrate_Timer.Enabled = false;
                    PA_Calibrate_Timer.Stop();
                    MessageBox.Show("COULD NOT ACHIEVE 100 WATTS FOR THIS BAND.  CHECK PROFICIO OUTPUT POWER", "MSCC",
                            MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                }
            }
        }
