        private void PA_Reset_button8_Click(object sender, EventArgs e)
        {
            DialogResult ret = MessageBox.Show("THIS RESETS POWER AMPLIFIER CALIBRATION FOR ALL BANDS TO FACTORY DEFAULTS" +
