        private void powertunebutton1_Click(object sender, EventArgs e)
        {
            MonitorTextBoxText(" powertunebutton1_Click Entered ");
            if (!Master_Controls.Transceiver_Warming)
            {
                if (Power_Calibration_Controls.Band_Is_Selected)
                {
                    if (Power_Calibration_Controls.Warning_Accepted)
                    {
                        if (!Power_Calibration_Controls.Tuning_Mode)
                        {
                            Proficio_Manual_Calibrate_button.Enabled = false;
                            Power_Calibration_Controls.Tuning_Mode = true;
                            Power_Calibration_Controls.TX_button = true;
                            oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 1);
                            Set_Button_Color(true, powertunebutton1);
                            Master_Controls.Transmit_Mode = true;
                            Proficio_Pwr_groupBox6.Enabled = false;
                            Proficio_Calibrate_button8.Enabled = false;
                            //Antenna_Switch_groupBox.Enabled = false;

                        }
                        else
                        {
                            Proficio_Manual_Calibrate_button.Enabled = true;
                            Power_Calibration_Controls.Tuning_Mode = false;
                            Power_Calibration_Controls.TX_button = false;
                            oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 0);
                            Set_Button_Color(false, powertunebutton1);
                            Master_Controls.Transmit_Mode = false;
                            Proficio_Pwr_groupBox6.Enabled = true;
                            Proficio_Calibrate_button8.Enabled = true;
                            //Antenna_Switch_groupBox.Enabled = true;
                        }
                    }
                    else
                    {
                        DialogResult ret = MessageBox.Show("IS A WELL MATCHED ANTENNA OR DUMMY LOAD ATTACHED TO THE SOLIDUS?\n\r" +
                             "A 50Ω 5W OR BETTER DUMMY LOAD IS PREFERRED", "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk);
                        if (ret == DialogResult.Yes)
                        {
                            Power_Calibration_Controls.Warning_Accepted = true;
                        }
                    }
                }
                else
                {
                    DialogResult ret = MessageBox.Show("Select a Band", "MSCC",
                          MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                }
            }
            else
            {
                MessageBox.Show("Transceiver is in Warm Up Mode. Try again later after warm up is complete", "MSCC",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            MonitorTextBoxText(" powertunebutton1_Click finished ");
        }
        private void powerrestorebutton2_Click(object sender, EventArgs e)
        {
            if (!Power_Calibration_Controls.Factory_Defaults)
            {
                DialogResult ret = MessageBox.Show("RESETS THE POWER CALIBRATION TO FACTORY DEFAULTS FOR ALL BANDS \n\r" + "CONTINUE ?", "MSCC",
                    MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk, MessageBoxDefaultButton.Button2);
                if (ret == DialogResult.Yes)
                {
                    Set_Button_Color(true, powerrestorebutton2, "WAIT");
                    Power_Calibration_Controls.Factory_Defaults = true;
                    oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_BAND_POWER_DEFAULTS, 1);
                    Thread.Sleep(50);
                    Proficio_Set_Band_Calibrated(1, 160);
                    Proficio_Set_Band_Calibrated(1, 80);
                    Proficio_Set_Band_Calibrated(1, 60);
                    Proficio_Set_Band_Calibrated(1, 40);
                    Proficio_Set_Band_Calibrated(1, 30);
                    Proficio_Set_Band_Calibrated(1, 20);
                    Proficio_Set_Band_Calibrated(1, 17);
                    Proficio_Set_Band_Calibrated(1, 15);
                    Proficio_Set_Band_Calibrated(1, 12);
                    Proficio_Set_Band_Calibrated(1, 10);
                }
            }
        }
        private void Proficio_Manual_Calibrate_button_Click(object sender, EventArgs e)
        {
            MonitorTextBoxText(" Proficio_Manual_Calibrate_button_Click Entered ");
            if (Power_Calibration_Controls.Band_Is_Selected)
            {
                if (Power_Calibration_Controls.Warning_Accepted)
                {
                    if (!Power_Calibration_Controls.Tuning_Mode)
                    {
                        Set_Button_Color(true, Proficio_Manual_Calibrate_button);
                        powertunebutton1.Enabled = false;
                        Master_Controls.Transmit_Mode = true;
                        Proficio_Pwr_groupBox6.Enabled = false;
                        //Proficio_Set_Band_Calibrated(0, (short)Power_Calibration_Controls.Band);
                        //Proficio_Calibrate_button8.Enabled = false;
                        Proficio_Calibrate_Power_hScrollBar.Enabled = true;
                        Proficio_Calibrate_Power_hScrollBar.Value = 0;
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_BAND_POWER_POWER, 0);
                        oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 1);
                        Power_Calibration_Controls.Tuning_Mode = true;
                        Power_Calibration_Controls.TX_button = true;
                    }
                    else
                    {
                        Set_Button_Color(false, Proficio_Manual_Calibrate_button);
                        powertunebutton1.Enabled = true;
                        powerrestorebutton2.Enabled = true;
                        Master_Controls.Transmit_Mode = false;
                        Proficio_Calibrate_Power_hScrollBar.Enabled = false;
                        Proficio_Pwr_groupBox6.Enabled = true;
                        //Proficio_Calibrate_button8.Enabled = true;
                        Power_Calibration_Controls.Tuning_Mode = false;
                        Power_Calibration_Controls.TX_button = false;
                        Proficio_Calibrate_Power_hScrollBar.Value = 0;
                        Power_Calibration_Controls.Tune_Power = 0;
                        oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 0);
                        DialogResult ret = MessageBox.Show("ACCEPT THIS CALIBRATION ?\n\r", "MSCC",
                            MessageBoxButtons.YesNoCancel, MessageBoxIcon.Question, MessageBoxDefaultButton.Button3);
                        if (ret == DialogResult.Yes)
                        {
                            Proficio_Set_Band_Calibrated(1, (short)Power_Calibration_Controls.Band);
                        }
                        else
                        {
                            if (ret == DialogResult.No)
                            {
                                Proficio_Set_Band_Calibrated(0, (short)Power_Calibration_Controls.Band);
                                MessageBox.Show("CALIBRATION NOT SET", "MSCC",
                                        MessageBoxButtons.OK, MessageBoxIcon.Information);
                            }
                            else
                            {
                                MessageBox.Show("CALIBRATION CANCELLED", "MSCC",
                                        MessageBoxButtons.OK, MessageBoxIcon.Information);
                            }
                        }
                    }
                }
                else
                {
                    DialogResult ret = MessageBox.Show("IS A WELL MATCHED ANTENNA OR DUMMY LOAD ATTACHED TO THE PROFICIO?\n\r" +
                        "A 50Ω 5W OR BETTER DUMMY LOAD IS PREFERRED", "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk);
                    if (ret == DialogResult.Yes)
                    {
                        Power_Calibration_Controls.Warning_Accepted = true;
                    }
                }
            }
            else
            {
                DialogResult ret = MessageBox.Show("Select a Band", "MSCC",
                      MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
            MonitorTextBoxText(" Proficio_Manual_Calibrate_button_Click finished ");
        }
        private void Proficio_Calibrate_Power_hScrollBar_Scroll(object sender, ScrollEventArgs e)
        {
