            if (Master_Controls.isLoading) return;
            value = Proficio_Calibrate_Power_hScrollBar.Value;
            if (Power_Calibration_Controls.Tune_Power == value) return;
            Power_Calibration_Controls.Tune_Power = value;
            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_BAND_POWER_POWER, (short)Power_Calibration_Controls.Tune_Power);
            //oCode.SendCommand(txsocket, txtarget, Power_Controls.CMD_SET_TUNE_POWER, (short)Power_Calibration_Controls.Tune_Power);
        }
        private void Proficio_Calibrate_timer_Tick(object sender, EventArgs e)
        {
            int lower = 0;
            MonitorTextBoxText("Proficio_Calibrate_timer_Tick -> Upper: " +
                Convert.ToString(Power_Calibration_Controls.Calibration_Power_Watts) + " Lower: " +
                Convert.ToString(Power_Calibration_Controls.Calibration_Power_Watts_Decimal));

            lower = Power_Calibration_Controls.Calibration_Power_Watts_Decimal;
            if (Power_Calibration_Controls.Calibration_Power_Watts_Decimal >= 100)
            {
                lower = Power_Calibration_Controls.Calibration_Power_Watts_Decimal / 10;
            }
            else
            {
                if (Power_Calibration_Controls.Calibration_Power_Watts_Decimal >= 1000)
                {
                    lower = Power_Calibration_Controls.Calibration_Power_Watts_Decimal / 100;
                }
            }

            XCRV_Power_Display_label33.Text = "POWER OUTPUT: " + Convert.ToString(Power_Calibration_Controls.Calibration_Power_Watts)
                + "." + lower.ToString("D");

            if (Power_Calibration_Controls.Calibration_Power_Watts >= Power_Calibration_Controls.CALIBRATION_MAX_POWER
                && Power_Calibration_Controls.Calibration_Power_Watts_Decimal >=
                                                    Power_Calibration_Controls.CALIBRATION_MAX_POWER_DECIMAL)
            {
                Proficio_Calibrate_button8.Text = "CALIBRATED";
                XCRV_Power_Display_label33.Text = "POWER OUTPUT: " +
                    Convert.ToString(Power_Calibration_Controls.Calibration_Power_Watts)
               + "." + lower.ToString("D");
                Set_Button_Color(false, Proficio_Calibrate_button8);
                powerrestorebutton2.Enabled = true;
                Power_Calibration_Controls.Tuning_Mode = false;
                oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 0);
                Set_Button_Color(false, powertunebutton1);
                powertunebutton1.Enabled = true;
                Proficio_Pwr_groupBox6.Enabled = true;
                Master_Controls.Transmit_Mode = false;
                Power_Calibration_Controls.Calibrating = false;
                Proficio_Set_Band_Calibrated(1, (short)Power_Calibration_Controls.Band);
                Proficio_Manual_Calibrate_button.Enabled = true;
                Proficio_Calibrate_timer.Enabled = false;
                Proficio_Calibrate_timer.Stop();
            }
            else
            {
                if (Power_Calibration_Controls.Step > Power_Calibration_Controls.STEP_MAX)
                {
                    Proficio_Calibrate_timer.Enabled = false;
                    Proficio_Calibrate_timer.Stop();
                    XCRV_Power_Display_label33.Text = "POWER OUTPUT: " +
                    Convert.ToString(Power_Calibration_Controls.Calibration_Power_Watts)
                                            + "." + Power_Calibration_Controls.Calibration_Power_Watts_Decimal.ToString("D2");
                    Set_Button_Color(false, Proficio_Calibrate_button8);
                    powerrestorebutton2.Enabled = true;
                    Power_Calibration_Controls.Tuning_Mode = false;
                    oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 0);
                    Set_Button_Color(false, powertunebutton1);
                    powertunebutton1.Enabled = true;
                    Proficio_Pwr_groupBox6.Enabled = true;
                    Master_Controls.Transmit_Mode = false;
                    Power_Calibration_Controls.Calibrating = false;
                    Proficio_Calibrate_button8.Text = "LOW";
                    Proficio_Manual_Calibrate_button.Enabled = true;
                    Proficio_Set_Band_Calibrated(1, (short)Power_Calibration_Controls.Band);
                    MessageBox.Show("COULD NOT ACHIEVE 5 WATTS FOR THIS BAND.", "MSCC",
                          MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                }
            }
            if (Power_Calibration_Controls.Calibrating)
            {
                Power_Calibration_Controls.Step++;
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_BAND_POWER_POWER,
                                   (short)Power_Calibration_Controls.Step);
                powerlabel14.Text = "CALIBRATION STEP: " + Convert.ToString(Power_Calibration_Controls.Step);
            }
        }
        private void Proficio_Calibrate_button8_Click(object sender, EventArgs e)
        {
            MonitorTextBoxText(" Proficio_Calibrate_button8_Click Entered ");
            if (Power_Calibration_Controls.Band_Is_Selected)
            {
                if (Power_Calibration_Controls.Warning_Accepted)
                {
                    if (!Power_Calibration_Controls.Tuning_Mode)
                    {
                        Power_Calibration_Controls.Tuning_Mode = true;
                        Power_Calibration_Controls.First_Pass = true;
                        Proficio_Manual_Calibrate_button.Enabled = false;
                        Power_Calibration_Controls.Step = Power_Calibration_Controls.STEP_START;
                        oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 1);
                        oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_BAND_POWER_POWER,
                                                                        (short)Power_Calibration_Controls.Step);
                        Set_Button_Color(true, powertunebutton1);
                        powertunebutton1.Enabled = false;
                        Master_Controls.Transmit_Mode = true;
                        Proficio_Pwr_groupBox6.Enabled = false;
                        //Proficio_Calibrate_button8.Text = "CALIBRATING";
                        Set_Button_Color(true, Proficio_Calibrate_button8, "CALIBRATING");
                        powerrestorebutton2.Enabled = false;
                        Power_Calibration_Controls.Calibration_Power_Watts = 0;
                        Power_Calibration_Controls.Calibration_Power_Watts_Decimal = 0;
                        Power_Calibration_Controls.Calibrating = true;
                        Proficio_Set_Band_Calibrated(0, (short)Power_Calibration_Controls.Band);
                        Thread.Sleep(100);
                        Proficio_Calibrate_timer.Enabled = true;
                        Proficio_Calibrate_timer.Start();
                    }
                    else
                    {
                        Proficio_Calibrate_timer.Enabled = false;
                        Proficio_Manual_Calibrate_button.Enabled = true;
                        Proficio_Calibrate_timer.Stop();
                        Power_Calibration_Controls.Tuning_Mode = false;
                        Power_Calibration_Controls.First_Pass = false;
                        oCode.SendCommand(txsocket, txtarget, Power_Calibration_Controls.CMD_CALIBRATION_TUNE, 0);
                        Set_Button_Color(false, powertunebutton1);
                        powerrestorebutton2.Enabled = true;
                        Master_Controls.Transmit_Mode = false;
                        Proficio_Pwr_groupBox6.Enabled = true;
                        //Proficio_Calibrate_button8.Text = "CALIBRATE";
                        Set_Button_Color(false, Proficio_Calibrate_button8, "CALIBRATE");
                        Power_Calibration_Controls.Step = Power_Calibration_Controls.STEP_START;
                        Proficio_Set_Band_Calibrated(0, (short)Power_Calibration_Controls.Band);
                        Power_Calibration_Controls.Calibration_Power_Watts = 0;
                        Power_Calibration_Controls.Calibration_Power_Watts_Decimal = 0;

                        if (Power_Calibration_Controls.Calibrating == true)
                        {
                            MessageBox.Show("CALIBRATION TERMINATED BY USER. THE CURRENT BAND IS NOT CALIBRATED", "MSCC", MessageBoxButtons.OK,
                                MessageBoxIcon.Asterisk);
                            Power_Calibration_Controls.Calibrating = false;
                        }
                    }
                }
                else
                {
                    DialogResult ret = MessageBox.Show("IS A WELL MATCHED ANTENNA OR DUMMY LOAD ATTACHED TO THE SOLIDUS?\n\r" +
                        "A 50Ω 5W OR BETTER DUMMY LOAD IS PREFERRED", "MSCC", MessageBoxButtons.YesNo, MessageBoxIcon.Asterisk);
                    if (ret == DialogResult.Yes)
                    {
                        Power_Calibration_Controls.Warning_Accepted = true;
                    }
                }
            }
            else
            {
                DialogResult ret = MessageBox.Show("Select a Band", "MSCC",
                      MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
            }
            MonitorTextBoxText(" Proficio_Calibrate_button8_Click finished ");
        }
