        private void Proficio_Set_Band_Calibrated(short calibrated, short band)
        {
            Color indicator_color = Color.White;

            if (calibrated == 0)
            {
                indicator_color = Color.White;
            }
            else
            {
                indicator_color = Color.Red;
            }

            switch (band)
            {
                case 160:
                    Power_Calibration_Controls.Calibrated_Bands.B_160 = (byte)calibrated;
                    Proficio_Band_Calibrated_160_button.BackColor = indicator_color;
                    break;
                case 80:
                    Power_Calibration_Controls.Calibrated_Bands.B_80 = (byte)calibrated;
                    Proficio_Band_Calibrated_80_button.BackColor = indicator_color;
                    break;
                case 60:
                    Power_Calibration_Controls.Calibrated_Bands.B_60 = (byte)calibrated;
                    Proficio_Band_Calibrated_60_button.BackColor = indicator_color;
                    break;
                case 40:
                    Power_Calibration_Controls.Calibrated_Bands.B_40 = (byte)calibrated;
                    Proficio_Band_Calibrated_40_button.BackColor = indicator_color;
                    break;
                case 30:
                    Power_Calibration_Controls.Calibrated_Bands.B_30 = (byte)calibrated;
                    Proficio_Band_Calibrated_30_button.BackColor = indicator_color;
                    break;
                case 20:
                    Power_Calibration_Controls.Calibrated_Bands.B_20 = (byte)calibrated;
                    Proficio_Band_Calibrated_20_button.BackColor = indicator_color;
                    break;
                case 17:
                    Power_Calibration_Controls.Calibrated_Bands.B_17 = (byte)calibrated;
                    Proficio_Band_Calibrated_17_button.BackColor = indicator_color;
                    break;
                case 15:
                    Power_Calibration_Controls.Calibrated_Bands.B_15 = (byte)calibrated;
                    Proficio_Band_Calibrated_15_button.BackColor = indicator_color;
                    break;
                case 12:
                    Power_Calibration_Controls.Calibrated_Bands.B_12 = (byte)calibrated;
                    Proficio_Band_Calibrated_12_button.BackColor = indicator_color;
                    break;
                case 10:
                    Power_Calibration_Controls.Calibrated_Bands.B_10 = (byte)calibrated;
                    Proficio_Band_Calibrated_10_button.BackColor = indicator_color;
                    break;
                case 2200:
                    Power_Calibration_Controls.Calibrated_Bands.B_2200 = (byte)calibrated;
                    Geminus_Band_Calibrated_2200_button.BackColor = indicator_color;
                    break;
                case 630:
                    Power_Calibration_Controls.Calibrated_Bands.B_630 = (byte)calibrated;
                    Geminus_Band_Calibrated_630_button.BackColor = indicator_color;
                    break;
            }
        }
