        private void B2200_radioButton_CheckedChanged(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading == true) return;
            if (Power_Calibration_Controls.Tuning_Mode)
            {
                DialogResult ret = MessageBox.Show("TX ON. BAND CHANGE NOT PERMITTED\r\nSET TX OFF", "MSCC",
                                                                                          MessageBoxButtons.OK, MessageBoxIcon.Asterisk);
                return;
            }
            if (Power_Calibration_Controls.Previous_Band != 2200)
            {
                MonitorTextBoxText(" B2200_radioButton_CheckedChanged");
                Power_Calibration_Controls.Band_Is_Selected = true;
                Power_Calibration_Controls.Previous_Band = 2200;
                Power_Calibration_Controls.Band = 2200;
                Power_Calibration_Controls.Old_Power_Value = 40;
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_BAND_POWER_BAND, (short)Power_Calibration_Controls.Band);
                //oCode.SendCommand(txsocket, txtarget, oCode.CMD_GET_BAND_POWER, (short)Power_Calibration_Controls.Band);
            }
        }
        private void B630_radioButton_CheckedChanged(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading == true) return;
            if (Power_Calibration_Controls.Tuning_Mode)
