        public void Set_Gen_Band(byte band)
        {
            byte[] buf = new byte[2];
            //int MHz;
            //int KHz;
            //int Hz;
            short mode_number;
            int freq = 0;
            char mode = 'N';
            short antenna_switch = 0;
            if (Master_Controls.isLoading) return;

            buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            MonitorTextBoxText(" Set_Gen_Band called.  Band:  " + Convert.ToString(band));
            //this.Antenna_Switch_checkBox.CheckedChanged -= new System.EventHandler(this.Antenna_Switch_checkBox_CheckedChanged);
            //Antenna_Switch_checkBox.Checked = false;
            Master_Controls.Auto_Tune.Inhibit = true;
            switch (band)
            {
                case Band_Bank.General_Bank.RWM:
                    freq = Band_Bank.General_Bank.Last_Used.RWM.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.RWM.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.RWM.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.RWM.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.RWM.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.RWM.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.CHU1:
                    freq = Band_Bank.General_Bank.Last_Used.CHU1.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.CHU1.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.CHU1.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.CHU1.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.CHU1.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.CHU1.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.CHU2:
                    freq = Band_Bank.General_Bank.Last_Used.CHU2.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.CHU2.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.CHU2.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.CHU2.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.CHU2.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.CHU2.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.WWV2_5:
                    freq = Band_Bank.General_Bank.Last_Used.WWV2_5.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.WWV2_5.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.WWV2_5.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.WWV2_5.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.WWV2_5.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.WWV2_5.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.WWV5:
                    freq = Band_Bank.General_Bank.Last_Used.WWV5.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.WWV5.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.WWV5.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.WWV5.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.WWV5.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.WWV5.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.WWV10:
                    freq = Band_Bank.General_Bank.Last_Used.WWV10.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.WWV10.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.WWV10.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.WWV10.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.WWV10.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.WWV10.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.WWV15:
                    freq = Band_Bank.General_Bank.Last_Used.WWV15.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.WWV15.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.WWV15.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.WWV15.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.WWV15.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.WWV15.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.WWV20:
                    freq = Band_Bank.General_Bank.Last_Used.WWV20.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.WWV20.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.WWV20.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.WWV20.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.WWV20.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.WWV20.Antenna_Switch;
                    break;
                case Band_Bank.General_Bank.GEN:
                    freq = Band_Bank.General_Bank.Last_Used.GEN.Freq;
                    mode = Band_Bank.General_Bank.Last_Used.GEN.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.General_Bank.Last_Used.GEN.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.General_Bank.Last_Used.GEN.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.General_Bank.Last_Used.GEN.Filter_Low_Index;
                    antenna_switch = Band_Bank.General_Bank.Last_Used.GEN.Antenna_Switch;
                    break;
            }
            /*if (antenna_switch == 0)
            {
                Antenna_Switch_checkBox.Checked = false;
            }
            else
            {
                Antenna_Switch_checkBox.Checked = true;
            }
            this.Antenna_Switch_checkBox.CheckedChanged += new System.EventHandler(this.Antenna_Switch_checkBox_CheckedChanged);
            */
            Band_Bank_Display_High_Cut_Value((byte)Filter_control.Filter_High_Index);
            Band_Bank_Display_Low_Cut_Value((byte)Filter_control.Filter_Low_Index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_HICUT, Filter_control.Filter_High_Index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_LOCUT, Filter_control.Filter_Low_Index);
            Set_mode_display(mode);
            VFOA_Master_Controls.gen_band_active = true;
            VFOA_Master_Controls.previous_main_band = 200;
            VFOA_Master_Controls.DisplayFreq = freq;
            Display_Main_Freq_VFOA();
            //VFOA_Master_Controls.current_band = 200;
            Set_Rit(freq);
            //int freq_plus_rit = freq + RIT.Rit_Controls.Offset;
            //RIT.Rit_Controls.RIT_Freq = freq;
            //MHz = freq_plus_rit / 1000000;
            //KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
            //Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
            //ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            Panadapter_Controls.Frequency = VFOA_Master_Controls.DisplayFreq;
            Panadapter_Controls.Freq_Set_By_Master = true;
#if FTDI
                Relay_Board_Controls.sentBytes[0] = (byte)(Relay_Board_Controls.sentBytes[0] = 0);
#endif
            if (!Power_Calibration_Controls.Power_Tab_Active && !Amplifier_Power_Controls.Tab_Active)
            {
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, freq);
                mode_number = Convert_mode_char_to_digit(mode);
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                Master_Controls.modeswitch = mode_number;
                buf[1] = (byte)antenna_switch;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                       Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
            }
            MonitorTextBoxText(" Set_Gen_Band -> " + "Current Mode: " + VFOA_Last_Used.Last_used.GEN.Mode);
            MonitorTextBoxText(" Set_Gen_Band Finished ");
        }
        public void Restore_HAM_Band()
        {
            short mode_number;
            int MHz;
            int KHz;
            int Hz;
            byte[] buf = new byte[2];

            mode_number = Convert_mode_char_to_digit(Band_Bank.HAM_Last_Used.Mode);
            oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, Band_Bank.HAM_Last_Used.Freq);
            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
            Master_Controls.modeswitch = mode_number;
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_HICUT, Band_Bank.HAM_Last_Used.Filter_High_Index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_LOCUT, Band_Bank.HAM_Last_Used.Filter_Low_Index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_BW, Band_Bank.HAM_Last_Used.Filter_CW_index);
            Display_High_Cut_Value(Band_Bank.HAM_Last_Used.Filter_High_Index);
            Display_Low_Cut_Value(Band_Bank.HAM_Last_Used.Filter_Low_Index);
            Display_CW_Value(Band_Bank.HAM_Last_Used.Filter_CW_index);
            Set_mode_display(Band_Bank.HAM_Last_Used.Mode);
            VFOA_Master_Controls.DisplayFreq = Band_Bank.HAM_Last_Used.Freq;
            Display_Main_Freq_VFOA();
            int freq_plus_rit = Band_Bank.HAM_Last_Used.Freq + RIT.Rit_Controls.Offset;
            RIT.Rit_Controls.RIT_Freq = Band_Bank.HAM_Last_Used.Freq;
            MHz = freq_plus_rit / 1000000;
            KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
            Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
            //ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            ritfreqtextBox1.Text = string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            buf[1] = Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value;
            oCode.SendCommand_MultiByte(txsocket, txtarget,
               Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
        }
        public void Restore_GEM_Band()
        {
            short mode_number = 0;
            int MHz;
            int KHz;
            int Hz;
            byte[] buf = new byte[2];
            short filter_high_index = 0;
            short filter_low_index = 0;
            short filter_cw_index = 0;
            int freq = 0;
            char mode = 'N';

            switch (Band_Bank.Geminus_Bank.Normal_Band)
            {
                case Band_Bank.Geminus_Bank.B2200:
                    mode_number = Convert_mode_char_to_digit(Band_Bank.Geminus_Bank.Last_Used.B2200.Mode);
                    mode = Band_Bank.Geminus_Bank.Last_Used.B2200.Mode;
                    freq = Band_Bank.Geminus_Bank.Last_Used.B2200.Freq;
                    filter_high_index = Band_Bank.Geminus_Bank.Last_Used.B2200.Filter_High_Index;
                    filter_low_index = Band_Bank.Geminus_Bank.Last_Used.B2200.Filter_Low_Index;
                    filter_cw_index = Band_Bank.Geminus_Bank.Last_Used.B2200.Filter_CW_index;
                    break;
                case Band_Bank.Geminus_Bank.B630:
                    mode_number = Convert_mode_char_to_digit(Band_Bank.Geminus_Bank.Last_Used.B630.Mode);
                    mode = Band_Bank.Geminus_Bank.Last_Used.B630.Mode;
                    freq = Band_Bank.Geminus_Bank.Last_Used.B630.Freq;
                    filter_high_index = Band_Bank.Geminus_Bank.Last_Used.B630.Filter_High_Index;
                    filter_low_index = Band_Bank.Geminus_Bank.Last_Used.B630.Filter_Low_Index;
                    filter_cw_index = Band_Bank.Geminus_Bank.Last_Used.B630.Filter_CW_index;
                    break;
            }
            oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, freq);
            oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
            Master_Controls.modeswitch = mode_number;
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_HICUT, filter_high_index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_LOCUT, filter_low_index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_CW_BW, filter_cw_index);
            Display_High_Cut_Value(filter_high_index);
            Display_Low_Cut_Value(filter_low_index);
            Display_CW_Value(filter_cw_index);
            Set_mode_display(mode);
            VFOA_Master_Controls.DisplayFreq = freq;
            Display_Main_Freq_VFOA();
            int freq_plus_rit = freq + RIT.Rit_Controls.Offset;
            RIT.Rit_Controls.RIT_Freq = freq;
            MHz = freq_plus_rit / 1000000;
            KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
            Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
            ritfreqtextBox1.Text = string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            buf[1] = Transceiver_Model_Settings.Antenna_Switch_Control.Antenna_Switch_Value;
            oCode.SendCommand_MultiByte(txsocket, txtarget,
               Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
        }
        private void GEN_button_Click(object sender, EventArgs e)
        {
            if (Master_Controls.isLoading) return;
            if (Band_Bank.General_Bank.General_Bank_Selected == false)
            {
                GEM_Group_Box.Enabled = false;
                GEM_Group_Box.Visible = false;
                Band_Set_2.Enabled = true;
                Band_Set_2.Visible = true;
                Band_Bank.General_Bank.General_Bank_Selected = true;
                Band_Bank.Selected_Bank = Band_Bank.GEN_BANK;
                Master_Controls.TX_Inhibited = true;
                button1.Enabled = false;
                buttTune.Enabled = false;
                Set_Button_Color(true, GEN_button, "GEN");
                Set_Gen_Band(Band_Bank.General_Bank.Band);
                //Antenna_Switch_checkBox.Enabled = true;
                VFO_button.Enabled = false;
                Split_Button.Enabled = false;
                Band_Set_2.BringToFront();
            }
            else
            {
                Band_Set_2.Enabled = false;
                Band_Set_2.Visible = false;
                GEM_Group_Box.Enabled = true;
                GEM_Group_Box.Visible = true;
                Band_Bank.General_Bank.General_Bank_Selected = false;
                Band_Bank.Selected_Bank = Band_Bank.GEMINUS_BANK;
                Master_Controls.TX_Inhibited = false;
                button1.Enabled = true;
                buttTune.Enabled = true;
                Set_Button_Color(false, GEN_button, "HAM");
                //Antenna_Switch_checkBox.Enabled = false;
                VFO_button.Enabled = true;
                Split_Button.Enabled = true;
                GEM_Group_Box.BringToFront();
                Restore_HAM_Band();
            }
        }
