        public void Set_Gem_Band_Mode(char mode)
        {
            switch (Band_Bank.Geminus_Bank.Band)
            {
                case Band_Bank.Geminus_Bank.B2200:
                    Band_Bank.Geminus_Bank.Last_Used.B2200.Mode = mode;
                    break;
                case Band_Bank.Geminus_Bank.B630:
                    Band_Bank.Geminus_Bank.Last_Used.B630.Mode = mode;
                    break;
                case Band_Bank.Geminus_Bank.GEN:
                    Band_Bank.Geminus_Bank.Last_Used.GEN.Mode = mode;
                    break;

            }
        }
