        private void Set_GEM_Band(byte band)
        {
            byte[] buf = new byte[2];
            int MHz;
            int KHz;
            int Hz;
            short mode_number;
            int freq = 0;
            char mode = 'N';
            short antenna_switch = 0;
            if (Master_Controls.isLoading) return;

            buf[0] = Master_Controls.Extended_Commands.CMD_SET_ANTENNA_SWITCH;
            MonitorTextBoxText(" Set_GEM_Band called.  Band:  " + Convert.ToString(band));
            /*this.Antenna_Switch_checkBox.CheckedChanged -= new System.EventHandler(this.Antenna_Switch_checkBox_CheckedChanged);
            Antenna_Switch_checkBox.Checked = false;*/
            switch (band)
            {
                case Band_Bank.Geminus_Bank.B2200:
                    freq = Band_Bank.Geminus_Bank.Last_Used.B2200.Freq;
                    mode = Band_Bank.Geminus_Bank.Last_Used.B2200.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.Geminus_Bank.Last_Used.B2200.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.Geminus_Bank.Last_Used.B2200.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.Geminus_Bank.Last_Used.B2200.Filter_Low_Index;
                    antenna_switch = Band_Bank.Geminus_Bank.Last_Used.B2200.Antenna_Switch;
                    Band_Bank.Geminus_Bank.Current_Band = Band_Bank.Geminus_Bank.B2200;
                    break;
                case Band_Bank.Geminus_Bank.B630:
                    freq = Band_Bank.Geminus_Bank.Last_Used.B630.Freq;
                    mode = Band_Bank.Geminus_Bank.Last_Used.B630.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.Geminus_Bank.Last_Used.B630.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.Geminus_Bank.Last_Used.B630.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.Geminus_Bank.Last_Used.B630.Filter_Low_Index;
                    antenna_switch = Band_Bank.Geminus_Bank.Last_Used.B630.Antenna_Switch;
                    Band_Bank.Geminus_Bank.Current_Band = Band_Bank.Geminus_Bank.B630;
                    break;
                case Band_Bank.Geminus_Bank.GEN:
                    freq = Band_Bank.Geminus_Bank.Last_Used.GEN.Freq;
                    mode = Band_Bank.Geminus_Bank.Last_Used.GEN.Mode;
                    Filter_control.Filter_High_Index = Band_Bank.Geminus_Bank.Last_Used.GEN.Filter_High_Index;
                    Filter_control.CW_Filter_Index = Band_Bank.Geminus_Bank.Last_Used.GEN.Filter_CW_index;
                    Filter_control.Filter_Low_Index = Band_Bank.Geminus_Bank.Last_Used.GEN.Filter_Low_Index;
                    antenna_switch = Band_Bank.Geminus_Bank.Last_Used.GEN.Antenna_Switch;
                    Band_Bank.Geminus_Bank.Current_Band = Band_Bank.Geminus_Bank.GEN;
                    break;
                case Band_Bank.Geminus_Bank.BCN:
                    Band_Bank.Geminus_Bank.Current_Band = Band_Bank.Geminus_Bank.BCN;
                    switch (Band_Bank.Geminus_Bank.Becon_Band)
                    {
                        case 0:
                            freq = Band_Bank.Geminus_Bank.Last_Used.Beacon_0.Freq;
                            mode = Band_Bank.Geminus_Bank.Last_Used.Beacon_0.Mode;
                            Filter_control.Filter_High_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_0.Filter_High_Index;
                            Filter_control.CW_Filter_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_0.Filter_CW_index;
                            Filter_control.Filter_Low_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_0.Filter_Low_Index;
                            break;
                        case 1:
                            freq = Band_Bank.Geminus_Bank.Last_Used.Beacon_1.Freq;
                            mode = Band_Bank.Geminus_Bank.Last_Used.Beacon_1.Mode;
                            Filter_control.Filter_High_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_1.Filter_High_Index;
                            Filter_control.CW_Filter_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_1.Filter_CW_index;
                            Filter_control.Filter_Low_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_1.Filter_Low_Index;
                            break;
                        case 2:
                            freq = Band_Bank.Geminus_Bank.Last_Used.Beacon_2.Freq;
                            mode = Band_Bank.Geminus_Bank.Last_Used.Beacon_2.Mode;
                            Filter_control.Filter_High_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_2.Filter_High_Index;
                            Filter_control.CW_Filter_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_2.Filter_CW_index;
                            Filter_control.Filter_Low_Index = Band_Bank.Geminus_Bank.Last_Used.Beacon_2.Filter_Low_Index;
                            break;
                    }
                    break;
            }
            Band_Bank_Display_High_Cut_Value((byte)Filter_control.Filter_High_Index);
            Band_Bank_Display_Low_Cut_Value((byte)Filter_control.Filter_Low_Index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_HICUT, Filter_control.Filter_High_Index);
            oCode.SendCommand(txsocket, txtarget, Filter_control.CMD_SET_BW_LOCUT, Filter_control.Filter_Low_Index);
            Set_mode_display(mode);
            VFOA_Master_Controls.gem_band_active = true;
            VFOA_Master_Controls.previous_main_band = 200;
            VFOA_Master_Controls.DisplayFreq = freq;
            Display_Main_Freq_VFOA();
            //VFOA_Master_Controls.current_band = 200;
            int freq_plus_rit = freq + RIT.Rit_Controls.Offset;
            RIT.Rit_Controls.RIT_Freq = freq;
            MHz = freq_plus_rit / 1000000;
            KHz = (freq_plus_rit - (MHz * 1000000)) / 1000;
            Hz = freq_plus_rit - (MHz * 1000000) - (KHz * 1000);
            ritfreqtextBox1.Text = string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            //ritfreqtextBox1.Text = Convert.ToString(MHz) + "." + string.Format("{0:000}", KHz) + "." + (string.Format("{0:000}", Hz));
            Panadapter_Controls.Frequency = VFOA_Master_Controls.DisplayFreq;
            Panadapter_Controls.Freq_Set_By_Master = true;
            if (!Power_Calibration_Controls.Power_Tab_Active && !Amplifier_Power_Controls.Tab_Active)
            {
                oCode.SendCommand32(txsocket, txtarget, oCode.CMD_SET_MAIN_FREQ, freq);
                mode_number = Convert_mode_char_to_digit(mode);
                oCode.SendCommand(txsocket, txtarget, oCode.CMD_SET_MAIN_MODE, mode_number);
                Master_Controls.modeswitch = mode_number;
                buf[1] = (byte)antenna_switch;
                oCode.SendCommand_MultiByte(txsocket, txtarget,
                       Master_Controls.Extended_Commands.CMD_SET_EXTENDED_COMMAND, buf, buf.Length);
            }
            MonitorTextBoxText(" Set_GEM_Band -> " + "Current Mode: " + mode);
            MonitorTextBoxText(" Set_GEM_Band Finished ");
        }
